import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Product, Order } from '../types';
import { calculateDistance } from '../utils/geo';
import ChatWindow from '../components/ChatWindow';
import { db } from '../services/db';
import { suggestUsage } from '../services/geminiService';

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const StarRating: React.FC<{ initialValue?: number, onRate?: (val: number) => void, interactive?: boolean }> = ({ initialValue = 0, onRate, interactive = false }) => {
  const [hover, setHover] = useState(0);
  const stars = [1, 2, 3, 4, 5];

  return (
    <div className="flex items-center gap-1">
      {stars.map((star) => (
        <button
          key={star}
          type="button"
          disabled={!interactive}
          className={`${interactive ? 'cursor-pointer hover:scale-125' : 'cursor-default'} transition-all`}
          onClick={() => interactive && onRate && onRate(star)}
          onMouseEnter={() => interactive && setHover(star)}
          onMouseLeave={() => interactive && setHover(0)}
        >
          <svg
            className={`w-6 h-6 ${
              star <= (hover || initialValue) ? 'text-amber-500 fill-current' : 'text-slate-200 fill-current'
            }`}
            viewBox="0 0 20 20"
          >
            <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
          </svg>
        </button>
      ))}
    </div>
  );
};

const BuyerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [view, setView] = useState<'marketplace' | 'store' | 'orders'>('marketplace');
  const [farmers, setFarmers] = useState<User[]>([]);
  const [selectedFarmer, setSelectedFarmer] = useState<User | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [buyerOrders, setBuyerOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'all' | 'favorites'>('all');
  const [chatRecipient, setChatRecipient] = useState<{id: string, name: string} | null>(null);
  const [orderQuantities, setOrderQuantities] = useState<Record<string, number>>({});
  const [aiSuggestions, setAiSuggestions] = useState<Record<string, string>>({});
  const [ratingModal, setRatingModal] = useState<Order | null>(null);
  const [cancelConfirmOrder, setCancelConfirmOrder] = useState<Order | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const buttonPrimary = "bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg hover:shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50";

  // Ref to track the current selected farmer ID to avoid infinite loops in loadData
  const selectedFarmerIdRef = useRef<string | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    try {
      const allUsers = await db.users.find({ role: 'farmer' });
      setFarmers(allUsers);

      const orders = await db.orders.find({ buyerId: user.id });
      // Sort orders by date descending
      setBuyerOrders(orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

      if (selectedFarmerIdRef.current) {
        const fid = selectedFarmerIdRef.current;
        const currentSelectedFarmer = allUsers.find(f => f.id === fid);
        if (currentSelectedFarmer) {
          // Use functional update to avoid triggering loop if data is identical
          setSelectedFarmer(prev => {
            if (!prev || JSON.stringify(prev) !== JSON.stringify(currentSelectedFarmer)) {
              return currentSelectedFarmer;
            }
            return prev;
          });
        }
        const farmerProducts = await db.products.find({ farmerId: fid });
        setStoreProducts(prev => {
          if (JSON.stringify(prev) !== JSON.stringify(farmerProducts)) {
            return farmerProducts;
          }
          return prev;
        });
      }
    } catch (error) {
      console.error("Load Data Error:", error);
    }
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const nearbyFarmers = farmers.filter(f => {
    if (!user.location || !f.location) return true;
    const distance = calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng);
    return distance <= (f.deliveryDistance || 10);
  });

  const displayFarmers = activeTab === 'all' ? nearbyFarmers : nearbyFarmers.filter(f => user.favorites?.includes(f.id));

  const handleOpenStore = async (farmer: User) => {
    selectedFarmerIdRef.current = farmer.id;
    setSelectedFarmer(farmer);
    const farmerProducts = await db.products.find({ farmerId: farmer.id });
    setStoreProducts(farmerProducts);
    const initQtys: Record<string, number> = {};
    farmerProducts.forEach(p => initQtys[p.id] = 1);
    setOrderQuantities(initQtys);
    setView('store');
  };

  const handleBuy = async (product: Product) => {
    if (!selectedFarmer) return;
    const selectedQty = orderQuantities[product.id] || 1;

    if (selectedQty > product.stock) {
      showToast(`Insufficient stock! Only ${product.stock} available.`, 'error');
      return;
    }

    try {
      const newOrder: Order = {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        productName: product.name,
        farmerId: selectedFarmer.id,
        farmName: selectedFarmer.name,
        buyerId: user.id,
        buyerName: user.name,
        buyerLocation: user.location?.address || 'Standard Delivery',
        quantity: selectedQty,
        totalPrice: product.price * selectedQty,
        status: 'pending',
        date: new Date().toISOString()
      };

      await db.orders.insertOne(newOrder);
      await db.products.updateOne(product.id, { stock: (product.stock || 0) - selectedQty });

      const currentBatchQty = selectedFarmer.currentQuantity || 0;
      await db.users.updateOne(selectedFarmer.id, { currentQuantity: currentBatchQty + selectedQty });

      showToast(`Order for ${product.name} placed successfully!`);
      await loadData();
      setView('orders');
    } catch (err) {
      showToast("Failed to place order. Please try again.", "error");
    }
  };

  const confirmCancelOrder = async () => {
    if (!cancelConfirmOrder) return;
    const order = cancelConfirmOrder;

    try {
      await db.orders.updateOne(order.id, { status: 'cancelled' });

      const product = await db.products.findOne({ id: order.productId });
      if (product) {
        await db.products.updateOne(product.id, { stock: (product.stock || 0) + order.quantity });
      }

      const farmer = await db.users.findOne({ id: order.farmerId });
      if (farmer) {
        const updatedQty = Math.max(0, (farmer.currentQuantity || 0) - order.quantity);
        await db.users.updateOne(farmer.id, { currentQuantity: updatedQty });
      }

      setCancelConfirmOrder(null);
      await loadData();
      showToast("Order successfully cancelled.");
    } catch (err) {
      console.error("Cancel Error:", err);
      showToast("Error cancelling order.", "error");
    }
  };

  const handleGiveRating = async (farmerId: string, value: number) => {
    try {
      const farmer = await db.users.findOne({ id: farmerId });
      if (farmer) {
        const oldRating = farmer.rating || 0;
        const newRating = oldRating === 0 ? value : (oldRating + value) / 2;
        await db.users.updateOne(farmer.id, { rating: newRating });
        setRatingModal(null);
        await loadData();
        showToast("Farmer rated successfully!");
      }
    } catch (err) {
      showToast("Failed to submit rating.", "error");
    }
  };

  const handleAISuggestUsage = async (product: Product) => {
    if (aiSuggestions[product.id]) return;
    const suggestion = await suggestUsage(product.name);
    setAiSuggestions(prev => ({ ...prev, [product.id]: suggestion }));
  };

  const toggleFavorite = async (farmerId: string) => {
    const currentFavs = user.favorites || [];
    const newFavs = currentFavs.includes(farmerId) 
      ? currentFavs.filter(id => id !== farmerId)
      : [...currentFavs, farmerId];
    await db.users.updateOne(user.id, { favorites: newFavs });
    onUpdateUser({ favorites: newFavs });
  };

  return (
    <div className="max-w-7xl mx-auto p-10 md:p-16 animate-in fade-in duration-700 relative">

      {/* Toast Notification */}
      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 duration-300 font-black text-xs uppercase tracking-widest border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'}`}>
           {toast.message}
        </div>
      )}

      <div className="flex flex-col md:flex-row items-center justify-between mb-20 gap-12">
        <div className="flex bg-white p-2.5 rounded-[2.8rem] shadow-2xl border-2 border-slate-100">
          <button onClick={() => { setView('marketplace'); setSelectedFarmer(null); selectedFarmerIdRef.current = null; }} className={`px-12 py-5 rounded-[2.2rem] font-black text-xs uppercase tracking-widest transition-all ${view === 'marketplace' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>The Marketplace</button>
          <button onClick={() => setView('orders')} className={`px-12 py-5 rounded-[2.2rem] font-black text-xs uppercase tracking-widest transition-all ${view === 'orders' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Track Orders</button>
        </div>
        {view === 'marketplace' && (
          <div className="flex bg-white p-2 rounded-full shadow-lg border border-slate-100">
             <button onClick={() => setActiveTab('all')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'all' ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400'}`}>Map Near Me</button>
             <button onClick={() => setActiveTab('favorites')} className={`px-10 py-3.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'favorites' ? 'bg-pink-500 text-white shadow-xl' : 'text-slate-400'}`}>Verified Favorites</button>
          </div>
        )}
      </div>

      {view === 'marketplace' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-14">
          {displayFarmers.length === 0 ? (
            <div className="col-span-full py-40 text-center bg-white rounded-[5rem] border-4 border-dashed border-slate-100">
              <p className="text-slate-400 font-serif text-3xl italic">No farmers found in your direct delivery radius.</p>
            </div>
          ) : (
            displayFarmers.map(f => {
              const distance = user.location && f.location ? calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng) : 0;
              const progress = ((f.currentQuantity || 0) / (f.thresholdQuantity || 100)) * 100;
              const isFav = user.favorites?.includes(f.id);
              return (
                <div key={f.id} className="bg-white rounded-[4rem] p-14 shadow-sm border-2 border-slate-100 hover:shadow-2xl transition-all relative overflow-hidden group">
                  <div className="flex justify-between items-start mb-12">
                    <div className="w-24 h-24 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center text-emerald-600 scale-110 rotate-3 group-hover:rotate-0 transition-all shadow-inner relative">
                        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3"></path></svg>
                    </div>
                    <div className="flex flex-col gap-3">
                      <button onClick={() => setChatRecipient({id: f.id, name: f.name})} className="w-16 h-16 bg-emerald-600 text-white hover:bg-emerald-700 rounded-3xl transition-all shadow-xl flex items-center justify-center group-hover:scale-110 border-4 border-white">
                          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72"></path></svg>
                      </button>
                      <button onClick={() => toggleFavorite(f.id)} className={`p-4 rounded-2xl transition-all shadow-sm ${isFav ? 'bg-pink-50 text-pink-500 border-2 border-pink-200' : 'bg-slate-50 text-slate-300 hover:bg-pink-50 hover:text-pink-400 border-2 border-transparent'}`}>
                          <svg className={`w-6 h-6 ${isFav ? 'fill-current' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"></path></svg>
                      </button>
                    </div>
                  </div>
                  <h3 className="text-4xl font-serif text-slate-900 tracking-tight mb-3">{f.name}</h3>
                  <div className="flex items-center gap-4 mb-10">
                    <div className="flex items-center gap-2 bg-amber-50 px-4 py-2 rounded-2xl border border-amber-100 shadow-sm">
                      <span className="font-black text-sm tracking-widest text-amber-700">{f.rating?.toFixed(1) || '0.0'}</span>
                      <StarRating initialValue={Math.round(f.rating || 0)} />
                    </div>
                    <div className="w-1 h-1 bg-slate-300 rounded-full"></div>
                    <span className="text-slate-400 font-black text-[10px] uppercase tracking-[0.3em] font-mono">{distance} KM</span>
                  </div>
                  <div className="bg-[#FBFDFB] p-8 rounded-[2.5rem] border-2 border-slate-50 mb-12 shadow-inner">
                    <div className="flex justify-between text-[11px] font-black text-slate-400 uppercase tracking-widest mb-4">
                        <span>Logistics Pulse</span>
                        <span className="text-emerald-600 font-black">{Math.round(progress)}% Full</span>
                    </div>
                    <div className="w-full bg-slate-200 h-4 rounded-full overflow-hidden p-1 shadow-inner">
                        <div className={`h-full rounded-full transition-all duration-1000 ${progress >= 100 ? 'bg-emerald-500 animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.5)]' : 'bg-slate-400'}`} style={{ width: `${progress}%` }}></div>
                    </div>
                  </div>
                  <button onClick={() => handleOpenStore(f)} className="w-full bg-slate-900 text-white font-black py-7 rounded-[2rem] hover:bg-emerald-600 transition-all shadow-2xl shadow-slate-200 text-lg uppercase tracking-widest focus:ring-4 focus:ring-emerald-500/30">Visit Farm Store</button>
                </div>
              );
            })
          )}
        </div>
      )}

      {view === 'store' && selectedFarmer && (
        <div className="animate-in slide-in-from-bottom-20 duration-700">
           <div className="flex items-center gap-10 mb-20">
              <button onClick={() => { setView('marketplace'); setSelectedFarmer(null); selectedFarmerIdRef.current = null; }} className="w-16 h-16 bg-white rounded-3xl border-2 border-slate-100 text-slate-400 hover:text-emerald-600 shadow-xl transition-all font-black flex items-center justify-center active:scale-95">
                 <svg className="w-8 h-8 rotate-180" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7"></path></svg>
              </button>
              <div>
                <h2 className="text-6xl font-serif text-slate-900 tracking-tight">{selectedFarmer.name}</h2>
                <div className="flex items-center gap-4 mt-2">
                   <div className="bg-amber-50 px-4 py-2 rounded-2xl border border-amber-100 flex items-center gap-3">
                     <span className="font-black text-sm text-amber-700">{selectedFarmer.rating?.toFixed(1) || '0.0'}</span>
                     <StarRating initialValue={Math.round(selectedFarmer.rating || 0)} />
                   </div>
                   <p className="text-slate-400 font-bold uppercase text-[11px] tracking-[0.4em]">Verified Network Producer</p>
                </div>
              </div>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-14">
              {storeProducts.length === 0 ? (
                <div className="col-span-full py-40 text-center bg-white rounded-[5rem] border-4 border-dashed border-slate-100">
                   <p className="text-slate-400 font-serif text-3xl">No listings active currently.</p>
                </div>
              ) : (
                storeProducts.map(p => (
                  <div key={p.id} className="bg-white rounded-[4.5rem] overflow-hidden border-2 border-slate-100 hover:shadow-3xl transition-all flex flex-col group">
                    <div className="h-80 overflow-hidden relative">
                        <img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" alt={p.name} />
                        <div className="absolute top-8 left-8 bg-white/90 backdrop-blur-md px-8 py-3 rounded-[1.8rem] shadow-2xl font-black text-emerald-700 text-2xl tracking-tighter border border-white/50">₹{p.price.toFixed(2)}</div>
                        <div className="absolute bottom-6 right-6 bg-slate-900 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Available: {p.stock} {p.unit}</div>
                    </div>
                    <div className="p-14 flex-1 flex flex-col">
                        <h3 className="text-3xl font-serif text-slate-900 mb-4 leading-tight">{p.name}</h3>
                        <p className="text-slate-500 font-medium mb-4 leading-relaxed italic text-lg opacity-80">"{p.description}"</p>

                        {aiSuggestions[p.id] ? (
                          <div className="mb-6 p-4 bg-emerald-50 rounded-2xl border border-emerald-100 animate-in fade-in slide-in-from-top-4">
                            <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">✨ AI CULINARY TIP</p>
                            <p className="text-sm font-medium text-slate-700 italic">"{aiSuggestions[p.id]}"</p>
                          </div>
                        ) : (
                          <button onClick={() => handleAISuggestUsage(p)} className="mb-6 text-emerald-600 font-black text-[10px] uppercase tracking-widest hover:underline text-left transition-all">✨ REVEAL AI COOKING TIP</button>
                        )}

                        <div className="mt-auto space-y-6">
                          <div className="flex items-center justify-between bg-slate-50 p-4 rounded-2xl border-2 border-slate-100">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity ({p.unit})</label>
                            <input 
                              type="number" 
                              min="1" 
                              max={p.stock}
                              className="bg-white border-2 border-slate-200 rounded-xl px-4 py-2 w-24 text-center font-black text-slate-900 focus:border-emerald-500 outline-none" 
                              value={orderQuantities[p.id] || 1}
                              onChange={(e) => setOrderQuantities({...orderQuantities, [p.id]: parseInt(e.target.value) || 1})}
                            />
                          </div>
                          <button 
                            onClick={() => handleBuy(p)} 
                            className={buttonPrimary + " w-full text-xl uppercase tracking-widest focus:ring-4 focus:ring-emerald-500/30 shadow-emerald-100"}
                            disabled={p.stock <= 0}
                          >
                            {p.stock > 0 ? 'Place Order' : 'Out of Stock'}
                          </button>
                        </div>
                    </div>
                  </div>
                ))
              )}
           </div>
        </div>
      )}

      {view === 'orders' && (
        <div className="bg-white rounded-[4.5rem] shadow-[0_60px_120px_-20px_rgba(0,0,0,0.1)] border-2 border-slate-50 overflow-hidden animate-in fade-in duration-700">
           <div className="p-20 bg-[#FBFDFB] border-b-2 border-slate-100 text-center">
              <h2 className="text-6xl font-serif text-slate-900 tracking-tight leading-tight">Harvest Track History</h2>
              <p className="text-slate-400 font-bold uppercase text-[11px] tracking-[0.5em] mt-5">Direct farm supply monitoring</p>
           </div>
           <div className="overflow-x-auto">
              <table className="w-full text-left">
                 <thead className="text-slate-400 text-[11px] font-black uppercase tracking-[0.4em] bg-slate-100/30">
                    <tr>
                       <th className="px-20 py-10">Produce</th>
                       <th className="px-20 py-10">Progress</th>
                       <th className="px-20 py-10">Actions</th>
                       <th className="px-20 py-10 text-right">Settlement</th>
                    </tr>
                 </thead>
                 <tbody className="divide-y-4 divide-slate-50">
                    {buyerOrders.length === 0 ? (
                      <tr><td colSpan={4} className="py-24 text-center text-slate-400 font-serif text-2xl italic">You have no active orders in the marketplace.</td></tr>
                    ) : (
                      buyerOrders.map(o => (
                        <tr key={o.id} className={`hover:bg-slate-50/50 transition-all group ${o.status === 'cancelled' ? 'opacity-50 grayscale' : ''}`}>
                            <td className="px-20 py-14">
                              <p className="font-serif text-slate-900 text-3xl tracking-tight leading-tight">{o.productName}</p>
                              <p className="text-emerald-600 font-black text-[10px] uppercase tracking-widest mt-2">{o.farmName}</p>
                            </td>
                            <td className="px-20 py-14">
                              <div className="flex items-center gap-4">
                                  <div className={`w-5 h-5 rounded-full ${o.status === 'pending' ? 'bg-amber-400 shadow-amber-100 animate-pulse' : o.status === 'shipped' ? 'bg-emerald-400' : o.status === 'cancelled' ? 'bg-red-400' : 'bg-emerald-700'}`}></div>
                                  <span className={`text-[13px] font-black uppercase tracking-[0.2em] ${o.status === 'pending' ? 'text-amber-600' : o.status === 'cancelled' ? 'text-red-600' : 'text-emerald-700'}`}>{o.status}</span>
                              </div>
                            </td>
                            <td className="px-20 py-14">
                              <div className="flex items-center gap-4">
                                <button onClick={() => setChatRecipient({id: o.farmerId, name: o.farmName})} className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-[1.5rem] hover:bg-emerald-600 hover:text-white transition-all shadow-sm flex items-center justify-center border-2 border-emerald-100">
                                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949"></path></svg>
                                </button>
                                {o.status === 'delivered' && (
                                  <button 
                                    onClick={() => setRatingModal(o)}
                                    className="bg-amber-100 text-amber-700 font-black px-8 py-4 rounded-2xl text-[11px] uppercase tracking-widest hover:bg-amber-200 transition-all border-2 border-amber-200 shadow-md"
                                  >
                                    Rate Farmer
                                  </button>
                                )}
                                {o.status === 'pending' && (
                                  <button 
                                    onClick={() => setCancelConfirmOrder(o)}
                                    className="bg-white text-red-400 border-2 border-red-100 font-bold py-3 px-6 text-[11px] uppercase tracking-widest hover:text-white hover:bg-red-500 rounded-2xl transition-all shadow-sm"
                                  >
                                    Cancel
                                  </button>
                                )}
                              </div>
                            </td>
                            <td className="px-20 py-14 text-right font-black text-slate-900 text-3xl tracking-tighter">₹{o.totalPrice.toFixed(2)}</td>
                        </tr>
                      ))
                    )}
                 </tbody>
              </table>
