import React, { useState } from 'react';
import { User, Role } from '../types';
import { db } from '../services/db';

interface LoginProps {
  onLogin: (user: User) => void;
}

const LoginView: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [verificationCode, setVerificationCode] = useState('');
  const [role, setRole] = useState<Role>('buyer');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');

  const inputClasses = "w-full px-6 py-4 rounded-2xl border-2 border-slate-300 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-medium text-lg";

  const handleStartRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    const existing = await db.users.findOne({ email: formData.email });
    if (existing) {
      setError('An account with this email already exists.');
      return;
    }

    setIsSendingSms(true);
    // Simulate API delay for SMS gateway
    setTimeout(() => {
      setIsSendingSms(false);
      setIsVerifying(true);
    }, 1500);
  };

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (verificationCode === '123456') {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        name: formData.name,
        email: formData.email.toLowerCase().trim(),
        phone: formData.phone,
        password: formData.password,
        role: role,
        favorites: [],
        rating: role === 'farmer' ? 0.0 : undefined,
        deliveryDistance: role === 'farmer' ? 15 : undefined,
        thresholdQuantity: role === 'farmer' ? 50 : undefined,
        currentQuantity: role === 'farmer' ? 0 : undefined
      };

      await db.users.insertOne(newUser);
      onLogin(newUser);
    } else {
      setError('Invalid verification code. Use 123456 for demo.');
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const user = await db.users.findOne({ 
      email: formData.email.toLowerCase().trim(), 
      password: formData.password 
    });

    if (user) {
      onLogin(user);
    } else {
      setError('Invalid email or password.');
    }
  };

  if (isSendingSms) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-6">
        <div className="text-center space-y-6">
          <div className="w-16 h-16 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mx-auto"></div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Sending Security Code to {formData.phone}...</p>
        </div>
      </div>
    );
  }

  if (isVerifying) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-[2.5rem] shadow-2xl p-10 space-y-8 animate-in fade-in zoom-in duration-300 border border-slate-100">
          <div className="text-center">
            <h2 className="text-3xl font-serif text-slate-900 mb-2">Verify Phone</h2>
            <p className="text-slate-500 font-medium">We sent a 6-digit code to <br/><span className="text-emerald-600 font-bold">{formData.phone}</span></p>
          </div>
          <form onSubmit={handleVerify} className="space-y-6">
            <input 
              type="text" maxLength={6} required
              className="w-full text-center text-4xl tracking-[0.3em] font-black py-6 rounded-2xl border-2 border-slate-200 bg-slate-50 focus:border-emerald-500 outline-none"
              placeholder="000000"
              value={verificationCode}
              onChange={(e) => setVerificationCode(e.target.value)}
            />
            <button className="w-full bg-emerald-600 text-white font-bold py-5 rounded-2xl shadow-xl hover:bg-emerald-700 transition-all text-lg uppercase tracking-widest">
              Verify & Register
            </button>
          </form>
          <div className="text-center space-y-4">
             <button onClick={() => setIsVerifying(false)} className="text-emerald-600 font-black text-[10px] uppercase tracking-widest hover:underline">Edit Phone Number</button>
             <p className="text-xs font-bold text-slate-300 uppercase tracking-widest">Demo Sandbox Code: 123456</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-emerald-800 via-emerald-900 to-slate-900 flex items-center justify-center p-6">
      <div className="max-w-lg w-full bg-white rounded-[3.5rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.5)] p-12 space-y-10 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-emerald-500"></div>

        <div className="text-center">
          <div className="mx-auto w-20 h-20 bg-emerald-600 rounded-[1.8rem] flex items-center justify-center text-white mb-6 shadow-2xl shadow-emerald-200/50 rotate-3">
             <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h2 className="text-4xl font-serif text-slate-900 tracking-tight">AgroFlow</h2>
          <p className="text-slate-400 font-bold uppercase text-[9px] tracking-[0.4em] mt-2">Connecting Indian Farms Directly</p>
        </div>

        {isRegistering && (
          <div className="flex bg-slate-100 p-1.5 rounded-2xl border-2 border-slate-200">
            <button onClick={() => setRole('buyer')} className={`flex-1 py-2.5 text-[10px] font-black rounded-xl transition-all ${role === 'buyer' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-400'}`}>JOIN AS BUYER</button>
            <button onClick={() => setRole('farmer')} className={`flex-1 py-2.5 text-[10px] font-black rounded-xl transition-all ${role === 'farmer' ? 'bg-white shadow-md text-emerald-600' : 'text-slate-400'}`}>JOIN AS FARMER</button>
          </div>
        )}

        <form onSubmit={isRegistering ? handleStartRegistration : handleLogin} className="space-y-5">
          {error && <div className="bg-red-50 text-red-600 p-4 rounded-2xl text-[10px] font-black border-2 border-red-100 animate-in shake">{error}</div>}

          {isRegistering && (
            <input type="text" required className={inputClasses} placeholder="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          )}
          {isRegistering && (
            <input type="tel" required className={inputClasses} placeholder="Mobile Number" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
          )}
          <input type="email" required className={inputClasses} placeholder="Email Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
          <input type="password" required className={inputClasses} placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />

          {isRegistering && (
            <input type="password" required className={inputClasses} placeholder="Confirm Password" value={formData.confirmPassword} onChange={e => setFormData({...formData, confirmPassword: e.target.value})} />
          )}

          <button type="submit" className="w-full bg-emerald-600 text-white font-black py-5 rounded-[1.5rem] shadow-2xl hover:bg-emerald-700 transition-all text-xl tracking-tight transform active:scale-95 shadow-emerald-200/40">
            {isRegistering ? 'Start Verification' : 'Sign In'}
          </button>
        </form>

        <button onClick={() => { setIsRegistering(!isRegistering); setError(''); }} className="w-full text-center text-[10px] font-black text-slate-400 hover:text-emerald-600 uppercase tracking-widest transition-all">
          {isRegistering ? 'Already have an account? Login' : 'Need an account? Join the Network'}
        </button>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import ChatWindow from '../components/ChatWindow';
import { db } from '../services/db';

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [chatRecipient, setChatRecipient] = useState<{id: string, name: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // States for Modals
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', 
    price: '', 
    category: 'Vegetables', 
    unit: 'kg', 
    stock: '', 
    description: '',
    imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const categories = ["Vegetables", "Fruits", "Grains", "Dairy", "Spices", "Other"];

  const inputClasses = "w-full px-5 py-4 rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-bold";
  const buttonPrimary = "bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg hover:shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50";

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    const sortedProducts = userProducts.sort((a, b) => a.name.localeCompare(b.name));
    setProducts([...sortedProducts]);

    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) {
          setEditingProduct({ ...editingProduct, imageUrl: base64String });
        } else {
          setNewProduct({ ...newProduct, imageUrl: base64String });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicDescription = async (isEditing: boolean = false) => {
    const targetName = isEditing ? editingProduct?.name : newProduct.name;
    const targetCategory = isEditing ? editingProduct?.category : newProduct.category;
    if (!targetName) return;
    setIsGenerating(true);
    try {
      const description = await generateProductDescription(targetName, targetCategory || 'Vegetables');
      if (isEditing && editingProduct) {
        setEditingProduct({ ...editingProduct, description });
      } else {
        setNewProduct(prev => ({ ...prev, description }));
      }
    } catch (e) {
      console.warn("AI generation limit reached.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    try {
      const price = await suggestPrice(newProduct.name);
      setNewProduct(prev => ({ ...prev, price }));
    } catch (e) {
      console.warn("AI pricing limit reached.");
    } finally {
      setIsPricing(false);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Freshly harvested organic produce.",
      imageUrl: newProduct.imageUrl || `https://picsum.photos/seed/${newProduct.name}/400/300`
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed successfully!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    await db.products.updateOne(editingProduct.id, editingProduct);
    setEditingProduct(null);
    showToast("Product updated!");
    await loadData();
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    try {
      await db.orders.updateOne(orderId, { status: newStatus });
      showToast(`Order marked as ${newStatus}`);
      await loadData();
    } catch (err) {
      showToast("Failed to update status", "error");
    }
  };

  const confirmRemoval = async () => {
    if (!deleteConfirmId) return;
    const productId = deleteConfirmId;
    setProducts(prev => prev.filter(p => p.id !== productId));
    setDeleteConfirmId(null);
    try {
      await db.products.deleteOne(productId);
      showToast("Listing removed.");
      loadData();
    } catch (err) {
      loadData();
    }
  };

  const handleUpdateLogistics = async (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateUser({ 
      deliveryDistance: user.deliveryDistance, 
      thresholdQuantity: user.thresholdQuantity 
    });
    showToast("Logistics policies updated.");
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-73px)] bg-[#F8FAF9]">
      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 duration-300 font-black text-xs uppercase tracking-widest border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'}`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar */}
      <nav className="w-full md:w-80 bg-white border-r border-slate-200 p-8 space-y-4 flex-shrink-0 shadow-sm z-10">
        <div className="pb-6 px-4">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Control Room</h3>
        </div>
        {[
          { id: 'overview', label: 'Dashboard', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z' },
          { id: 'products', label: 'My Inventory', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
          { id: 'add-product', label: 'Add Harvest', icon: 'M12 4v16m8-8H4' },
          { id: 'orders', label: 'Orders', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2' },
          { id: 'settings', label: 'Logistics', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id as any)}
            className={`w-full flex items-center gap-5 px-7 py-5 rounded-[1.8rem] transition-all font-black text-xs uppercase tracking-widest border-2 ${activeTab === item.id ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200 scale-[1.03]' : 'bg-transparent border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path></svg>
            {item.label}
          </button>
        ))}
      </nav>

      {/* Main Content Area */}
      <div className="flex-1 p-8 md:p-14 max-w-7xl mx-auto w-full overflow-y-auto">

        {/* OVERVIEW */}
        {activeTab === 'overview' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="bg-white p-12 rounded-[4.5rem] shadow-sm border-2 border-slate-100 flex flex-col lg:flex-row items-center justify-between gap-12">
               <div className="space-y-6 flex-1 text-center lg:text-left">
                  <h2 className="text-5xl font-serif text-slate-900 tracking-tight">Delivery Readiness</h2>
                  <p className="text-slate-500 text-lg font-medium leading-relaxed">Direct delivery triggers when collective buyer orders reach your fulfillment threshold.</p>
                  <div className="inline-flex bg-emerald-600 text-white px-10 py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-200 text-2xl tracking-tighter">
                    {currentProgress} / {threshold} Units
                  </div>
               </div>
               <div className="relative w-80 h-80 flex items-center justify-center flex-shrink-0 bg-white rounded-full">
                  <svg className="w-full h-full -rotate-90 p-4" viewBox="0 0 320 320">
                    <circle cx="160" cy="160" r="130" className="stroke-slate-50 fill-none" strokeWidth="24" />
                    <circle cx="160" cy="160" r="130" className="stroke-emerald-500 fill-none transition-all duration-1000" strokeWidth="24" strokeDasharray={`${progressPercent * 8.16} 816`} strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className={`text-6xl font-black tracking-tighter ${progressPercent >= 100 ? 'text-emerald-600 animate-bounce' : 'text-slate-800'}`}>{Math.round(progressPercent)}%</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">GOAL</span>
                  </div>
               </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
