import React, { useState, useEffect, useCallback } from 'react';
import { User, Role, Product, Order, Location } from './types';
import LoginView from './views/Login';
import FarmerDashboard from './views/FarmerDashboard';
import BuyerDashboard from './views/BuyerDashboard';
import { getAddressFromCoords } from './services/geminiService';
import { db } from './services/db';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userLocation, setUserLocation] = useState<Location | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  // Auth persistence and periodic user refresh
  useEffect(() => {
    const checkAuth = async () => {
      const savedUser = localStorage.getItem('agro_user');
      if (savedUser) {
        const parsed = JSON.parse(savedUser);
        const actualUser = await db.users.findOne({ id: parsed.id });
        if (actualUser) {
          setCurrentUser(actualUser);
          setIsLoggedIn(true);
          if (actualUser.location) {
            setUserLocation(actualUser.location);
          }
        } else {
          localStorage.removeItem('agro_user');
        }
      }
    };
    checkAuth();

    const interval = setInterval(async () => {
      if (isLoggedIn && currentUser) {
        const freshUser = await db.users.findOne({ id: currentUser.id });
        if (freshUser) {
          setCurrentUser(prev => {
            if (JSON.stringify(prev) !== JSON.stringify(freshUser)) {
              return freshUser;
            }
            return prev;
          });
        }
      }
    }, 4000);

    return () => clearInterval(interval);
  }, [isLoggedIn, currentUser?.id]);

  const fetchLocation = useCallback(async () => {
    if (!("geolocation" in navigator)) {
      console.error("Geolocation not supported");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        const address = await getAddressFromCoords(loc.lat, loc.lng);
        const finalLoc = { ...loc, address };
        setUserLocation(finalLoc);

        if (currentUser) {
          await db.users.updateOne(currentUser.id, { location: finalLoc });
          const updated = { ...currentUser, location: finalLoc };
          setCurrentUser(updated);
          localStorage.setItem('agro_user', JSON.stringify(updated));
        }
      } catch (err) {
        console.error("Error updating location address:", err);
      } finally {
        setIsLocating(false);
      }
    }, (err) => {
      console.error("Geolocation permission error:", err);
      setIsLocating(false);
    }, { timeout: 10000, enableHighAccuracy: true });
  }, [currentUser]);

  useEffect(() => {
    if (isLoggedIn && !userLocation && !isLocating) {
      fetchLocation();
    }
  }, [isLoggedIn, userLocation, isLocating, fetchLocation]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsLoggedIn(true);
    localStorage.setItem('agro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsLoggedIn(false);
    setUserLocation(null);
    localStorage.removeItem('agro_user');
  };

  const updateCurrentUser = async (updates: Partial<User>) => {
    if (currentUser) {
      await db.users.updateOne(currentUser.id, updates);
      const updated = { ...currentUser, ...updates };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  if (!isLoggedIn) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-emerald-100 selection:text-emerald-900">
      <header className="bg-white/90 backdrop-blur-2xl border-b border-slate-100 sticky top-0 z-50 px-6 md:px-12 py-5 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-100 transform -rotate-3 transition-transform hover:rotate-0">
            <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h1 className="text-2xl font-serif font-black text-slate-900 hidden sm:block tracking-tight">AgroFlow</h1>
        </div>

        <div className="flex items-center gap-6">
          <button 
            onClick={fetchLocation}
            disabled={isLocating}
            className={`flex items-center gap-3 text-[11px] font-black uppercase tracking-widest transition-all px-5 py-2.5 rounded-2xl border ${isLocating ? 'bg-slate-100 text-slate-400 border-slate-200 cursor-not-allowed' : 'bg-slate-50 text-slate-500 hover:bg-emerald-50 hover:text-emerald-600 border-slate-100'}`}
          >
            <svg className={`w-4 h-4 ${isLocating ? 'animate-spin' : 'text-emerald-500'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
            <span className="truncate max-w-[180px]">{isLocating ? 'Locating...' : (userLocation?.address || 'Detect Location')}</span>
          </button>

          <div className="flex items-center gap-4 border-l border-slate-100 pl-6">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black text-slate-800 tracking-tight">{currentUser?.name}</p>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">{currentUser?.role} Network</p>
            </div>
            <button 
              onClick={handleLogout}
              className="w-12 h-12 flex items-center justify-center bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all rounded-2xl border border-slate-100 group"
            >
              <svg className="w-5 h-5 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 bg-[#F8FAF9]">
        {currentUser?.role === 'farmer' ? (
          <FarmerDashboard user={currentUser} onUpdateUser={updateCurrentUser} />
        ) : (
          <BuyerDashboard user={currentUser!} onUpdateUser={updateCurrentUser} />
        )}
      </main>
    </div>
  );
};

export default App;

