import ChatWindow from '../components/ChatWindow';
import { db } from '../services/db';

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [chatRecipient, setChatRecipient] = useState<{id: string, name: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // States for Modals
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', 
    price: '', 
    category: 'Vegetables', 
    unit: 'kg', 
    stock: '', 
    description: '',
    imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const categories = ["Vegetables", "Fruits", "Grains", "Dairy", "Spices", "Other"];

  const inputClasses = "w-full px-5 py-4 rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-bold";
  const buttonPrimary = "bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg hover:shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50";

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    const sortedProducts = userProducts.sort((a, b) => a.name.localeCompare(b.name));
    setProducts([...sortedProducts]);

    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) {
          setEditingProduct({ ...editingProduct, imageUrl: base64String });
        } else {
          setNewProduct({ ...newProduct, imageUrl: base64String });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicDescription = async (isEditing: boolean = false) => {
    const targetName = isEditing ? editingProduct?.name : newProduct.name;
    const targetCategory = isEditing ? editingProduct?.category : newProduct.category;
    if (!targetName) return;
    setIsGenerating(true);
    try {
      const description = await generateProductDescription(targetName, targetCategory || 'Vegetables');
      if (isEditing && editingProduct) {
        setEditingProduct({ ...editingProduct, description });
      } else {
        setNewProduct(prev => ({ ...prev, description }));
      }
    } catch (e) {
      console.warn("AI generation limit reached.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    try {
      const price = await suggestPrice(newProduct.name);
      setNewProduct(prev => ({ ...prev, price }));
    } catch (e) {
      console.warn("AI pricing limit reached.");
    } finally {
      setIsPricing(false);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Freshly harvested organic produce.",
      imageUrl: newProduct.imageUrl || `https://picsum.photos/seed/${newProduct.name}/400/300`
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed successfully!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    await db.products.updateOne(editingProduct.id, editingProduct);
    setEditingProduct(null);
    showToast("Product updated!");
    await loadData();
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    try {
      await db.orders.updateOne(orderId, { status: newStatus });
      showToast(`Order marked as ${newStatus}`);
      await loadData();
    } catch (err) {
      showToast("Failed to update status", "error");
    }
  };

  const confirmRemoval = async () => {
    if (!deleteConfirmId) return;
    const productId = deleteConfirmId;
    setProducts(prev => prev.filter(p => p.id !== productId));
    setDeleteConfirmId(null);
    try {
      await db.products.deleteOne(productId);
      showToast("Listing removed.");
      loadData();
    } catch (err) {
      loadData();
    }
  };

  const handleUpdateLogistics = async (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateUser({ 
      deliveryDistance: user.deliveryDistance, 
      thresholdQuantity: user.thresholdQuantity 
    });
    showToast("Logistics policies updated.");
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-73px)] bg-[#F8FAF9]">
      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 duration-300 font-black text-xs uppercase tracking-widest border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'}`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar */}
      <nav className="w-full md:w-80 bg-white border-r border-slate-200 p-8 space-y-4 flex-shrink-0 shadow-sm z-10">
        <div className="pb-6 px-4">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Control Room</h3>
        </div>
        {[
          { id: 'overview', label: 'Dashboard', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z' },
          { id: 'products', label: 'My Inventory', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
          { id: 'add-product', label: 'Add Harvest', icon: 'M12 4v16m8-8H4' },
          { id: 'orders', label: 'Orders', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2' },
          { id: 'settings', label: 'Logistics', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id as any)}
            className={`w-full flex items-center gap-5 px-7 py-5 rounded-[1.8rem] transition-all font-black text-xs uppercase tracking-widest border-2 ${activeTab === item.id ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200 scale-[1.03]' : 'bg-transparent border-transparent text-slate-400 hover:bg-slate-50 hover:text-slate-600'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path></svg>
            {item.label}
          </button>
        ))}
      </nav>

      {/* Main Content Area */}
      <div className="flex-1 p-8 md:p-14 max-w-7xl mx-auto w-full overflow-y-auto">

        {/* OVERVIEW */}
        {activeTab === 'overview' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="bg-white p-12 rounded-[4.5rem] shadow-sm border-2 border-slate-100 flex flex-col lg:flex-row items-center justify-between gap-12">
               <div className="space-y-6 flex-1 text-center lg:text-left">
                  <h2 className="text-5xl font-serif text-slate-900 tracking-tight">Delivery Readiness</h2>
                  <p className="text-slate-500 text-lg font-medium leading-relaxed">Direct delivery triggers when collective buyer orders reach your fulfillment threshold.</p>
                  <div className="inline-flex bg-emerald-600 text-white px-10 py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-200 text-2xl tracking-tighter">
                    {currentProgress} / {threshold} Units
                  </div>
               </div>
               <div className="relative w-80 h-80 flex items-center justify-center flex-shrink-0 bg-white rounded-full p-6">
                  <svg className="w-full h-full -rotate-90 overflow-visible" viewBox="0 0 320 320">
                    <circle cx="160" cy="160" r="130" className="stroke-slate-50 fill-none" strokeWidth="28" />
                    <circle cx="160" cy="160" r="130" className="stroke-emerald-500 fill-none transition-all duration-1000" strokeWidth="28" strokeDasharray={`${progressPercent * 8.16} 816`} strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className={`text-6xl font-black tracking-tighter ${progressPercent >= 100 ? 'text-emerald-600 animate-bounce' : 'text-slate-800'}`}>{Math.round(progressPercent)}%</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">GOAL</span>
                  </div>
               </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
               <div className="bg-white p-10 rounded-[3rem] border-2 border-slate-100 shadow-sm">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-4">Farm Rating</p>
                  <div className="flex items-center gap-4">
                    <p className="text-5xl font-black text-slate-900 tracking-tighter">{user.rating?.toFixed(1) || '5.0'}</p>
                    <svg className="w-10 h-10 text-amber-500 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg>
                  </div>
               </div>
               <div className="bg-white p-10 rounded-[3rem] border-2 border-slate-100 shadow-sm">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-4">Total Listings</p>
                  <p className="text-5xl font-black text-slate-900 tracking-tighter">{products.length}</p>
               </div>
               <div className="bg-white p-10 rounded-[3rem] border-2 border-slate-100 shadow-sm">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-4">Completed Sales</p>
                  <p className="text-5xl font-black text-emerald-600 tracking-tighter">{orders.filter(o => o.status === 'delivered').length}</p>
               </div>
             </div>
          </div>
        )}

        {/* MY INVENTORY */}
        {activeTab === 'products' && (
          <div className="space-y-12 animate-in fade-in duration-500 pb-20">
             <div className="flex justify-between items-end px-4">
                <div>
                  <h2 className="text-4xl font-serif text-slate-900 tracking-tight">Farm Inventory</h2>
                  <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest mt-3">Monitor and manage your active marketplace listings</p>
                </div>
                <button onClick={() => setActiveTab('add-product')} className="bg-slate-900 text-white font-black px-10 py-5 rounded-[2rem] hover:bg-emerald-600 transition-all text-xs uppercase tracking-widest shadow-xl">Add New Listing</button>
             </div>

             {products.length === 0 ? (
               <div className="flex flex-col items-center justify-center py-48 bg-white rounded-[5rem] border-4 border-dashed border-slate-100">
                  <div className="w-32 h-32 bg-slate-50 rounded-[3rem] flex items-center justify-center text-slate-300 mb-8 border-4 border-white shadow-xl">
                    <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"></path></svg>
                  </div>
                  <h3 className="text-2xl font-serif text-slate-400 mb-8 italic">Your shelves are currently empty.</h3>
                  <button onClick={() => setActiveTab('add-product')} className={buttonPrimary + " px-12"}>Start Your First Listing</button>
               </div>
             ) : (
               <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                  {products.map(p => (
                    <div key={p.id} className="bg-white rounded-[4rem] border-2 border-slate-100 shadow-sm hover:shadow-2xl transition-all group overflow-hidden flex flex-col">
                       <div className="flex flex-col md:flex-row p-10 gap-10">
                          <div className="w-full md:w-56 h-56 rounded-[3rem] overflow-hidden bg-slate-50 flex-shrink-0 relative border-4 border-white shadow-lg">
                            <img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={p.name} />
                          </div>
                          <div className="flex-1 flex flex-col">
                             <div className="flex justify-between items-start mb-4">
                                <h3 className="text-3xl font-serif text-slate-900 tracking-tight leading-none">{p.name}</h3>
                                <div className="text-emerald-600 font-black text-2xl tracking-tighter">₹{p.price}</div>
                             </div>
                             <p className="text-slate-500 font-medium text-sm leading-relaxed mb-6 line-clamp-3 italic opacity-90">"{p.description}"</p>
                             <div className="mt-auto">
                                <div className={`inline-flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border ${p.stock <= 0 ? 'bg-red-50 text-red-500 border-red-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                                   Inventory: {Math.max(0, p.stock)} {p.unit}
                                </div>
                             </div>
                          </div>
                       </div>

                       <div className="bg-slate-50/50 p-6 border-t-2 border-slate-50 flex gap-6">
                          <button onClick={() => setEditingProduct(p)} className="flex-1 bg-white border-2 border-slate-200 text-slate-800 font-black text-[11px] uppercase tracking-widest hover:bg-slate-900 hover:text-white py-5 rounded-[1.8rem] transition-all">Edit</button>
                          <button onClick={() => setDeleteConfirmId(p.id)} className="flex-1 bg-white border-2 border-red-100 text-red-500 font-black text-[11px] uppercase tracking-widest hover:bg-red-600 hover:text-white py-5 rounded-[1.8rem] transition-all">Remove</button>
                       </div>
                    </div>
                  ))}
               </div>
             )}
          </div>
        )}

        {/* ORDERS */}
        {activeTab === 'orders' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="bg-white rounded-[3rem] shadow-sm border-2 border-slate-100 overflow-hidden">
                <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                   <h2 className="text-3xl font-serif text-slate-900">Buyer Fulfillment List</h2>
                   <div className="bg-emerald-100 text-emerald-700 px-6 py-2 rounded-full font-black text-[10px] uppercase tracking-widest">Active Demand: {orders.filter(o => o.status !== 'delivered' && o.status !== 'cancelled').length}</div>
                </div>
                <div className="overflow-x-auto">
                   <table className="w-full text-left">
                      <thead className="bg-slate-100/30 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                         <tr>
                            <th className="px-10 py-6">Buyer / Product</th>
                            <th className="px-10 py-6">Quantity</th>
                            <th className="px-10 py-6">Status</th>
                            <th className="px-10 py-6">Action</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                         {orders.length === 0 ? (
                           <tr><td colSpan={4} className="py-24 text-center text-slate-400 font-serif text-xl italic">No orders received yet.</td></tr>
                         ) : (
                           orders.map(o => (
                             <tr key={o.id} className="hover:bg-slate-50 transition-all">
                                <td className="px-10 py-8">
                                   <p className="font-bold text-slate-900">{o.buyerName}</p>
                                   <p className="text-xs text-emerald-600 font-bold">{o.productName}</p>
                                </td>
                                <td className="px-10 py-8">
                                   <span className="font-black text-lg text-slate-800">{o.quantity} Units</span>
                                </td>
                                <td className="px-10 py-8">
                                   <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${o.status === 'pending' ? 'bg-amber-100 text-amber-600' : o.status === 'shipped' ? 'bg-blue-100 text-blue-600' : o.status === 'delivered' ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                                      {o.status}
                                   </div>
                                </td>
                                <td className="px-10 py-8">
                                   <div className="flex gap-2">
                                      {o.status === 'pending' && (
                                        <button onClick={() => handleUpdateOrderStatus(o.id, 'shipped')} className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-blue-100">Ship</button>
                                      )}
                                      {o.status === 'shipped' && (
                                        <button onClick={() => handleUpdateOrderStatus(o.id, 'delivered')} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-emerald-100">Delivered</button>
                                      )}
                                      <button onClick={() => setChatRecipient({id: o.buyerId, name: o.buyerName})} className="bg-slate-900 text-white p-2 rounded-xl">
                                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72"></path></svg>
                                      </button>
                                   </div>
                                </td>
                             </tr>
                           ))
                         )}
                      </tbody>
                   </table>
                </div>
             </div>
          </div>
        )}

        {/* ADD HARVEST (REDESIGNED) */}
        {activeTab === 'add-product' && (
          <div className="animate-in fade-in slide-in-from-bottom-10 duration-700">
             <div className="flex flex-col lg:flex-row gap-12 max-w-7xl mx-auto">
                {/* Left Form Panel */}
                <div className="flex-1 bg-white p-12 lg:p-16 rounded-[4rem] shadow-2xl border border-slate-100 space-y-12">
                   <div>
                      <h2 className="text-5xl font-serif text-slate-900 tracking-tight mb-4">Produce Studio</h2>
                      <p className="text-slate-500 font-medium">Create a compelling listing for your fresh harvest.</p>
                   </div>

                   <form onSubmit={handleAddProduct} className="space-y-10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                         <div className="space-y-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Product Name</label>
                            <input type="text" required className={inputClasses} placeholder="Organic Kashmiri Apples" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} />
                         </div>
                         <div className="space-y-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Market Category</label>
                            <select className={inputClasses} value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>
                               {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                            </select>
                         </div>
                         <div className="space-y-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Price per {newProduct.unit} (₹)</label>
                            <div className="relative">
                               <input type="number" step="0.01" required className={inputClasses} value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: e.target.value})} />
                               <button type="button" onClick={handleAISuggestPrice} className="absolute right-4 top-1/2 -translate-y-1/2 bg-emerald-50 text-emerald-600 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-emerald-600 hover:text-white transition-all" disabled={isPricing}>
                                  {isPricing ? '...' : '✨ Auto'}
                               </button>
                            </div>
                         </div>
                         <div className="space-y-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Total Harvest Stock</label>
                            <div className="flex gap-3">
                               <input type="number" required className={inputClasses} value={newProduct.stock} onChange={e => setNewProduct({...newProduct, stock: e.target.value})} />
                               <select className="w-32 px-4 py-4 rounded-2xl border-2 border-slate-200 bg-slate-50 font-black text-xs uppercase" value={newProduct.unit} onChange={e => setNewProduct({...newProduct, unit: e.target.value})}>
                                  <option value="kg">KG</option>
                                  <option value="L">Litre</option>
                                  <option value="Piece">Piece</option>
                                  <option value="Bundle">Bundle</option>
                               </select>
                            </div>
                         </div>
                      </div>

                      <div className="space-y-4">
                         <div className="flex justify-between items-center ml-4">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Story & Description</label>
                            <button type="button" onClick={() => handleMagicDescription(false)} className="bg-emerald-600 text-white px-5 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-xl hover:scale-105 transition-all" disabled={isGenerating}>
                               {isGenerating ? 'AI Writing...' : '✨ Magic Write'}
                            </button>
                         </div>
                         <textarea className={`${inputClasses} min-h-[160px] resize-none leading-relaxed`} placeholder="Share the origin and quality of your produce..." value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})} />
                      </div>

                      <div className="space-y-4">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Visual Identity</label>
                         <div onClick={() => fileInputRef.current?.click()} className="group relative h-64 bg-slate-50 border-4 border-dashed border-slate-100 rounded-[3rem] overflow-hidden cursor-pointer flex items-center justify-center transition-all hover:border-emerald-400 hover:bg-emerald-50">
                            {newProduct.imageUrl ? (
