import React, { useState, useEffect, useCallback } from 'react';
import { User, Role, Product, Order, Location } from './types';
import LoginView from './views/Login';
import FarmerDashboard from './views/FarmerDashboard';
import BuyerDashboard from './views/BuyerDashboard';
import { getAddressFromCoords } from './services/geminiService';
import { db } from './services/db';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userLocation, setUserLocation] = useState<Location | null>(null);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);

  // Auth persistence and periodic user refresh
  useEffect(() => {
    const checkAuth = async () => {
      const savedUser = localStorage.getItem('agro_user');
      if (savedUser) {
        const parsed = JSON.parse(savedUser);
        const actualUser = await db.users.findOne({ id: parsed.id });
        if (actualUser) {
          setCurrentUser(actualUser);
          setIsLoggedIn(true);
          if (actualUser.location) {
            setUserLocation(actualUser.location);
          }
        } else {
          localStorage.removeItem('agro_user');
        }
      }
    };
    checkAuth();

    const interval = setInterval(async () => {
      if (isLoggedIn && currentUser) {
        const freshUser = await db.users.findOne({ id: currentUser.id });
        if (freshUser) {
          setCurrentUser(prev => {
            if (JSON.stringify(prev) !== JSON.stringify(freshUser)) {
              return freshUser;
            }
            return prev;
          });
        }
      }
    }, 4000);

    return () => clearInterval(interval);
  }, [isLoggedIn, currentUser?.id]);

  const fetchLocation = useCallback(async () => {
    if (!("geolocation" in navigator)) {
      setLocationError("Browser doesn't support geolocation");
      return;
    }

    setIsLocating(true);
    setLocationError(null);

    const options = {
      timeout: 15000,
      enableHighAccuracy: false, // Set to false for faster, more reliable fetching in some browsers
      maximumAge: 0
    };

    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        const address = await getAddressFromCoords(loc.lat, loc.lng);
        const finalLoc = { ...loc, address };
        setUserLocation(finalLoc);

        if (currentUser) {
          await db.users.updateOne(currentUser.id, { location: finalLoc });
          const updated = { ...currentUser, location: finalLoc };
          setCurrentUser(updated);
          localStorage.setItem('agro_user', JSON.stringify(updated));
        }
      } catch (err) {
        console.error("Error updating location address:", err);
        setLocationError("Couldn't resolve address");
      } finally {
        setIsLocating(false);
      }
    }, (err) => {
      console.error("Geolocation error:", err);
      setIsLocating(false);
      switch(err.code) {
        case err.PERMISSION_DENIED:
          setLocationError("Location access denied");
          break;
        case err.POSITION_UNAVAILABLE:
          setLocationError("Location unavailable");
          break;
        case err.TIMEOUT:
          setLocationError("Location request timed out");
          break;
        default:
          setLocationError("Location fetch failed");
      }
    }, options);
  }, [currentUser]);

  // Try fetching on login if not present
  useEffect(() => {
    if (isLoggedIn && !userLocation && !isLocating) {
      fetchLocation();
    }
  }, [isLoggedIn, userLocation, isLocating, fetchLocation]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsLoggedIn(true);
    localStorage.setItem('agro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsLoggedIn(false);
    setUserLocation(null);
    localStorage.removeItem('agro_user');
  };

  const updateCurrentUser = async (updates: Partial<User>) => {
    if (currentUser) {
      await db.users.updateOne(currentUser.id, updates);
      const updated = { ...currentUser, ...updates };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  if (!isLoggedIn) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-emerald-100 selection:text-emerald-900">
      <header className="bg-white/90 backdrop-blur-2xl border-b border-slate-100 sticky top-0 z-50 px-6 md:px-12 py-5 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-100 transform -rotate-3 transition-transform hover:rotate-0">
            <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h1 className="text-2xl font-serif font-black text-slate-900 hidden sm:block tracking-tight">AgroFlow</h1>
        </div>

        <div className="flex items-center gap-4 md:gap-6">
          <button 
            onClick={fetchLocation}
            disabled={isLocating}
            className={`flex items-center gap-3 text-[10px] md:text-[11px] font-black uppercase tracking-widest transition-all px-4 md:px-5 py-2.5 rounded-2xl border ${isLocating ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : locationError ? 'bg-red-50 text-red-500 border-red-100' : 'bg-slate-50 text-slate-500 hover:bg-emerald-50 hover:text-emerald-600 border-slate-100'}`}
          >
            <svg className={`w-4 h-4 ${isLocating ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
            <span className="truncate max-w-[120px] md:max-w-[200px]">
              {isLocating ? 'Detecting...' : locationError ? locationError : (userLocation?.address || 'Detect Location')}
            </span>
          </button>

          <div className="flex items-center gap-4 border-l border-slate-100 pl-4 md:pl-6">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black text-slate-800 tracking-tight">{currentUser?.name}</p>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">{currentUser?.role}</p>
            </div>
            <button 
              onClick={handleLogout}
              className="w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all rounded-2xl border border-slate-100"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 bg-[#F8FAF9]">
        {currentUser?.role === 'farmer' ? (
          <FarmerDashboard user={currentUser} onUpdateUser={updateCurrentUser} />
        ) : (
          <BuyerDashboard user={currentUser!} onUpdateUser={updateCurrentUser} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import ChatWindow from '../components/ChatWindow';
import { db } from '../services/db';

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [chatRecipient, setChatRecipient] = useState<{id: string, name: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // States for Modals
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', 
    price: '', 
    category: 'Vegetables', 
    unit: 'kg', 
    stock: '', 
    description: '',
    imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const categories = ["Vegetables", "Fruits", "Grains", "Dairy", "Spices", "Other"];

  const inputClasses = "w-full px-5 py-4 rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-bold text-base";
  const buttonPrimary = "bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg hover:shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50";

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    const sortedProducts = userProducts.sort((a, b) => a.name.localeCompare(b.name));
    setProducts([...sortedProducts]);

    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) {
          setEditingProduct({ ...editingProduct, imageUrl: base64String });
        } else {
          setNewProduct({ ...newProduct, imageUrl: base64String });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMagicDescription = async (isEditing: boolean = false) => {
    const targetName = isEditing ? editingProduct?.name : newProduct.name;
    const targetCategory = isEditing ? editingProduct?.category : newProduct.category;
    if (!targetName) return;
    setIsGenerating(true);
    try {
      const description = await generateProductDescription(targetName, targetCategory || 'Vegetables');
      if (isEditing && editingProduct) {
        setEditingProduct({ ...editingProduct, description });
      } else {
        setNewProduct(prev => ({ ...prev, description }));
      }
    } catch (e) {
      console.warn("AI generation limit reached.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    try {
      const price = await suggestPrice(newProduct.name);
      setNewProduct(prev => ({ ...prev, price }));
    } catch (e) {
      console.warn("AI pricing limit reached.");
    } finally {
      setIsPricing(false);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.imageUrl) {
        showToast("Please upload a product image.", "error");
        return;
    }
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Freshly harvested organic produce.",
      imageUrl: newProduct.imageUrl
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed successfully!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
