                          <div className="absolute top-6 left-6 bg-white/95 backdrop-blur-md px-6 py-2 rounded-2xl shadow-xl font-black text-emerald-700 text-xl tracking-tighter">₹{newProduct.price || '0.00'}</div>
                      </div>
                      <div className="p-10 flex-1 flex flex-col">
                          <h3 className="text-2xl font-serif text-slate-900 mb-2 truncate">{newProduct.name || 'Produce Title'}</h3>
                          <p className="text-slate-400 font-black text-[9px] uppercase tracking-widest mb-4">{newProduct.category}</p>
                          <p className="text-slate-500 font-medium text-sm leading-relaxed mb-8 line-clamp-3 italic opacity-80">"{newProduct.description || 'Describe the quality of your harvest to attract buyers...'}"</p>
                          <div className="mt-auto flex items-center justify-between border-t-2 border-slate-50 pt-6">
                             <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">In Stock</div>
                             <div className="text-emerald-600 font-black text-sm">{newProduct.stock || '0'} {newProduct.unit}</div>
                          </div>
                      </div>
                   </div>
                   <div className="bg-emerald-900 p-8 rounded-[3rem] text-white shadow-2xl">
                      <p className="text-[10px] font-black opacity-60 uppercase tracking-widest mb-3">Farmer Insight</p>
                      <p className="text-sm font-medium leading-relaxed italic">"Detailed descriptions and high-quality photos increase buyer trust by up to 40%."</p>
                   </div>
                </div>
             </div>
          </div>
        )}

        {/* SETTINGS / LOGISTICS */}
        {activeTab === 'settings' && (
          <div className="max-w-4xl mx-auto bg-white p-14 rounded-[4rem] shadow-xl border-2 border-slate-100 animate-in slide-in-from-bottom-5 duration-300">
             <h2 className="text-4xl font-serif text-slate-900 mb-4 tracking-tight">Delivery Policy</h2>
             <form onSubmit={handleUpdateLogistics} className="space-y-12">
                <div className="space-y-5">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Service Radius (km)</label>
                   <input type="number" className={inputClasses} value={user.deliveryDistance || 15} onChange={e => onUpdateUser({ deliveryDistance: parseInt(e.target.value) })} />
                </div>
                <div className="space-y-5">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Fulfillment Threshold</label>
                   <input type="number" className={inputClasses} value={user.thresholdQuantity || 50} onChange={e => onUpdateUser({ thresholdQuantity: parseInt(e.target.value) })} />
                </div>
                <button type="submit" className={buttonPrimary + " w-full py-6 text-lg uppercase tracking-widest mt-12 shadow-2xl"}>Save Policies</button>
             </form>
          </div>
        )}
      </div>

      {/* DELETE MODAL */}
      {deleteConfirmId && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-lg z-[1000] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-md rounded-[4rem] p-12 shadow-2xl animate-in zoom-in duration-300 border border-slate-100 text-center">
              <h2 className="text-3xl font-serif text-slate-900 tracking-tight mb-4">Remove Harvest?</h2>
              <div className="space-y-4">
                 <button onClick={confirmRemoval} className="w-full bg-red-600 text-white font-black py-5 rounded-[1.8rem] text-[13px] uppercase tracking-widest">Yes, Remove</button>
                 <button onClick={() => setDeleteConfirmId(null)} className="w-full bg-slate-50 text-slate-400 font-black py-5 rounded-[1.8rem] text-[11px] uppercase tracking-widest">Cancel</button>
              </div>
           </div>
        </div>
      )}

      {/* EDIT MODAL */}
      {editingProduct && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[500] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-3xl rounded-[4.5rem] p-14 shadow-2xl animate-in zoom-in duration-300 max-h-[90vh] overflow-y-auto border-2 border-slate-100">
              <div className="flex justify-between items-center mb-10 pb-8 border-b-2 border-slate-50">
                <h2 className="text-4xl font-serif text-slate-900">Update Details</h2>
                <button onClick={() => setEditingProduct(null)} className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 hover:text-slate-900 transition-colors">
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
                </button>
              </div>
              <form onSubmit={handleUpdateProduct} className="space-y-10">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="space-y-8">
                       <div className="space-y-3">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Produce Name</label>
                          <input type="text" className={inputClasses} value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} />
                       </div>
                       <div className="grid grid-cols-2 gap-5">
                          <div className="space-y-3">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Price (₹)</label>
                              <input type="number" className={inputClasses} value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} />
                          </div>
                          <div className="space-y-3">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Available Stock</label>
                              <input type="number" className={inputClasses} value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} />
                          </div>
                       </div>
                       <div className="space-y-3">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Description</label>
                          <textarea className={`${inputClasses} min-h-[120px] resize-none leading-relaxed text-sm`} value={editingProduct.description} onChange={e => setEditingProduct({...editingProduct, description: e.target.value})} />
                       </div>
                    </div>

                    <div className="space-y-6">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Product Photo</label>
                       <div onClick={() => editFileInputRef.current?.click()} className="group relative h-full min-h-[280px] bg-slate-50 rounded-[3rem] border-2 border-slate-100 overflow-hidden cursor-pointer">
                          <img src={editingProduct.imageUrl} className="w-full h-full object-cover group-hover:opacity-40 transition-opacity" alt="Edit" />
                          <div className="absolute inset-0 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                             <div className="bg-emerald-600 text-white p-4 rounded-2xl shadow-2xl mb-4">
                                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                             </div>
                             <span className="text-slate-900 font-black text-[10px] uppercase tracking-widest">Replace Imagery</span>
                          </div>
                       </div>
                       <input type="file" hidden ref={editFileInputRef} accept="image/*" onChange={(e) => handleImageUpload(e, true)} />
                    </div>
                 </div>
                 <button type="submit" className={buttonPrimary + " w-full py-8 text-xl uppercase tracking-widest mt-8 shadow-2xl active:scale-95"}>Commit Changes</button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default FarmerDashboard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Product, Order } from '../types';
import { calculateDistance } from '../utils/geo';
import { db } from '../services/db';
import { suggestUsage } from '../services/geminiService';
import MessagesView from './MessagesView';

const StarRating: React.FC<{ initialValue?: number, onRate?: (val: number) => void, interactive?: boolean }> = ({ initialValue = 0, onRate, interactive = false }) => {
  const [hover, setHover] = useState(0);
  const stars = [1, 2, 3, 4, 5];

  return (
    <div className="flex items-center gap-1">
      {stars.map((star) => (
        <button
          key={star}
          type="button"
          disabled={!interactive}
          className={`${interactive ? 'cursor-pointer hover:scale-125' : 'cursor-default'} transition-all`}
          onClick={() => interactive && onRate && onRate(star)}
          onMouseEnter={() => interactive && setHover(star)}
          onMouseLeave={() => interactive && setHover(0)}
        >
          <svg
            className={`w-5 h-5 md:w-6 md:h-6 ${
              star <= (hover || initialValue) ? 'text-amber-500 fill-current' : 'text-slate-200 fill-current'
            }`}
            viewBox="0 0 20 20"
          >
            <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
          </svg>
        </button>
      ))}
    </div>
  );
};

const BuyerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [view, setView] = useState<'marketplace' | 'store' | 'orders' | 'messages'>('marketplace');
  const [farmers, setFarmers] = useState<User[]>([]);
  const [selectedFarmer, setSelectedFarmer] = useState<User | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [buyerOrders, setBuyerOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'all' | 'favorites'>('all');
  const [orderQuantities, setOrderQuantities] = useState<Record<string, number>>({});
  const [aiSuggestions, setAiSuggestions] = useState<Record<string, string>>({});
  const [ratingModal, setRatingModal] = useState<Order | null>(null);
  const [cancelConfirmOrder, setCancelConfirmOrder] = useState<Order | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const buttonPrimary = "bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg hover:shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50";

  const selectedFarmerIdRef = useRef<string | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    try {
      const allUsers = await db.users.find({ role: 'farmer' });
      setFarmers(allUsers);

      const orders = await db.orders.find({ buyerId: user.id });
      setBuyerOrders(orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

      if (selectedFarmerIdRef.current) {
        const fid = selectedFarmerIdRef.current;
        const farmerProducts = await db.products.find({ farmerId: fid });
        setStoreProducts(farmerProducts);
      }
    } catch (error) {
      console.error("Load Data Error:", error);
    }
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const nearbyFarmers = farmers.filter(f => {
    if (!user.location || !f.location) return true;
    const distance = calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng);
    return distance <= (f.deliveryDistance || 20); // Fallback to 20km if not working perfectly
  });

  const displayFarmers = activeTab === 'all' ? nearbyFarmers : nearbyFarmers.filter(f => user.favorites?.includes(f.id));

  const handleOpenStore = async (farmer: User) => {
    selectedFarmerIdRef.current = farmer.id;
    setSelectedFarmer(farmer);
    const farmerProducts = await db.products.find({ farmerId: farmer.id });
    setStoreProducts(farmerProducts);
    const initQtys: Record<string, number> = {};
    farmerProducts.forEach(p => initQtys[p.id] = 1);
    setOrderQuantities(initQtys);
    setView('store');
  };

  const handleBuy = async (product: Product) => {
    if (!selectedFarmer) return;
    const selectedQty = orderQuantities[product.id] || 1;

    if (selectedQty > product.stock) {
      showToast(`Insufficient stock! Only ${product.stock} available.`, 'error');
      return;
    }

    try {
      const newOrder: Order = {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        productName: product.name,
        farmerId: selectedFarmer.id,
        farmName: selectedFarmer.name,
        buyerId: user.id,
        buyerName: user.name,
        buyerLocation: user.location?.address || 'Standard Delivery',
        quantity: selectedQty,
        totalPrice: product.price * selectedQty,
        status: 'pending',
        date: new Date().toISOString()
      };

      await db.orders.insertOne(newOrder);
      await db.products.updateOne(product.id, { stock: (product.stock || 0) - selectedQty });

      const currentBatchQty = selectedFarmer.currentQuantity || 0;
      await db.users.updateOne(selectedFarmer.id, { currentQuantity: currentBatchQty + selectedQty });

      showToast(`Order placed successfully! Waiting for farm confirmation.`);
      await loadData();
      setView('orders');
    } catch (err) {
      showToast("Failed to place order.", "error");
    }
  };

  const confirmCancelOrder = async () => {
    if (!cancelConfirmOrder) return;
    const order = cancelConfirmOrder;

    try {
      await db.orders.updateOne(order.id, { status: 'cancelled' });
      const product = await db.products.findOne({ id: order.productId });
      if (product) {
        await db.products.updateOne(product.id, { stock: (product.stock || 0) + order.quantity });
      }
      const farmer = await db.users.findOne({ id: order.farmerId });
      if (farmer) {
        const updatedQty = Math.max(0, (farmer.currentQuantity || 0) - order.quantity);
        await db.users.updateOne(farmer.id, { currentQuantity: updatedQty });
      }
      setCancelConfirmOrder(null);
      await loadData();
      showToast("Order cancelled.");
    } catch (err) {
      showToast("Error cancelling order.", "error");
    }
  };

  const handleGiveRating = async (farmerId: string, value: number) => {
    try {
      const farmer = await db.users.findOne({ id: farmerId });
      if (farmer) {
        const oldRating = farmer.rating || 0;
        const newRating = oldRating === 0 ? value : (oldRating + value) / 2;
        await db.users.updateOne(farmer.id, { rating: newRating });
        setRatingModal(null);
        await loadData();
        showToast("Farm experience rated!");
      }
    } catch (err) {
      showToast("Failed to submit rating.", "error");
    }
  };

  const handleAISuggestUsage = async (product: Product) => {
    if (aiSuggestions[product.id]) return;
    const suggestion = await suggestUsage(product.name);
    setAiSuggestions(prev => ({ ...prev, [product.id]: suggestion }));
  };

  const toggleFavorite = async (farmerId: string) => {
    const currentFavs = user.favorites || [];
    const newFavs = currentFavs.includes(farmerId) 
      ? currentFavs.filter(id => id !== farmerId)
      : [...currentFavs, farmerId];
    await db.users.updateOne(user.id, { favorites: newFavs });
    onUpdateUser({ favorites: newFavs });
  };

  return (
    <div className="max-w-7xl mx-auto p-8 md:p-16 animate-in fade-in duration-700 relative">

      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 duration-300 font-black text-xs uppercase tracking-widest border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'}`}>
           {toast.message}
        </div>
      )}

      <div className="flex flex-col md:flex-row items-center justify-between mb-16 md:mb-20 gap-8 md:gap-12">
        <div className="flex bg-white p-2 md:p-2.5 rounded-[2rem] md:rounded-[2.8rem] shadow-2xl border-2 border-slate-100 overflow-x-auto max-w-full">
          <button onClick={() => { setView('marketplace'); setSelectedFarmer(null); selectedFarmerIdRef.current = null; }} className={`whitespace-nowrap px-6 md:px-12 py-3 md:py-5 rounded-[1.5rem] md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === 'marketplace' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Marketplace</button>
          <button onClick={() => setView('orders')} className={`whitespace-nowrap px-6 md:px-12 py-3 md:py-5 rounded-[1.5rem] md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === 'orders' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Orders</button>
          <button onClick={() => setView('messages')} className={`whitespace-nowrap px-6 md:px-12 py-3 md:py-5 rounded-[1.5rem] md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === 'messages' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Messages</button>
        </div>
        {view === 'marketplace' && (
          <div className="flex bg-white p-2 rounded-full shadow-lg border border-slate-100">
             <button onClick={() => setActiveTab('all')} className={`px-6 md:px-10 py-3 rounded-full text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'all' ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400'}`}>Nearby</button>
             <button onClick={() => setActiveTab('favorites')} className={`px-6 md:px-10 py-3 rounded-full text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'favorites' ? 'bg-pink-500 text-white shadow-xl' : 'text-slate-400'}`}>Favorites</button>
          </div>
        )}
      </div>

      {view === 'marketplace' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 md:gap-14">
          {displayFarmers.length === 0 ? (
            <div className="col-span-full py-40 text-center bg-white rounded-[5rem] border-4 border-dashed border-slate-100">
              <p className="text-slate-400 font-serif text-3xl italic">No nearby farmers detected.</p>
              <button onClick={() => window.location.reload()} className="mt-8 text-emerald-600 font-black uppercase tracking-widest text-xs underline">Reload Page</button>
            </div>
          ) : (
            displayFarmers.map(f => {
              const distance = user.location && f.location ? calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng) : 0;
              const progress = ((f.currentQuantity || 0) / (f.thresholdQuantity || 100)) * 100;
              const isFav = user.favorites?.includes(f.id);
              return (
                <div key={f.id} className="bg-white rounded-[3.5rem] md:rounded-[4rem] p-10 md:p-14 shadow-sm border-2 border-slate-100 hover:shadow-2xl transition-all relative overflow-hidden group">
                  <div className="flex justify-between items-start mb-12">
                    <div className="w-20 h-20 md:w-24 md:h-24 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center text-emerald-600 scale-110 shadow-inner relative">
                        <svg className="w-10 h-10 md:w-12 md:h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3"></path></svg>
                    </div>
                    <div className="flex flex-col gap-3">
                      <button onClick={() => setView('messages')} className="w-14 h-14 md:w-16 md:h-16 bg-emerald-600 text-white hover:bg-emerald-700 rounded-2xl md:rounded-3xl transition-all shadow-xl flex items-center justify-center group-hover:scale-105 border-4 border-white">
                          <svg className="w-7 h-7 md:w-8 md:h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72"></path></svg>
                      </button>
                      <button onClick={() => toggleFavorite(f.id)} className={`p-3 md:p-4 rounded-2xl transition-all shadow-sm ${isFav ? 'bg-pink-50 text-pink-500 border-2 border-pink-200' : 'bg-slate-50 text-slate-300 hover:bg-pink-50 hover:text-pink-400 border-2 border-transparent'}`}>
                          <svg className={`w-6 h-6 ${isFav ? 'fill-current' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"></path></svg>
                      </button>
                    </div>
                  </div>
                  <h3 className="text-3xl md:text-4xl font-serif text-slate-900 tracking-tight mb-3 truncate">{f.name}</h3>
                  <div className="flex items-center gap-3 md:gap-4 mb-10">
                    <div className="flex items-center gap-2 bg-amber-50 px-3 md:px-4 py-2 rounded-xl md:rounded-2xl border border-amber-100">
                      <span className="font-black text-xs md:text-sm tracking-widest text-amber-700">{f.rating?.toFixed(1) || '0.0'}</span>
                      <StarRating initialValue={Math.round(f.rating || 0)} />
                    </div>
                    <div className="w-1 h-1 bg-slate-300 rounded-full"></div>
                    <span className="text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-widest font-mono">{distance} KM</span>
                  </div>
                  <div className="bg-[#FBFDFB] p-6 md:p-8 rounded-[2.5rem] border-2 border-slate-50 mb-10 md:mb-12">
                    <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">
                        <span>Batch Goal</span>
                        <span className="text-emerald-600 font-black">{Math.round(progress)}% Full</span>
                    </div>
                    <div className="w-full bg-slate-200 h-3 md:h-4 rounded-full overflow-hidden p-1">
                        <div className={`h-full rounded-full transition-all duration-1000 ${progress >= 100 ? 'bg-emerald-500' : 'bg-slate-400'}`} style={{ width: `${progress}%` }}></div>
                    </div>
                  </div>
                  <button onClick={() => handleOpenStore(f)} className="w-full bg-slate-900 text-white font-black py-6 md:py-7 rounded-[1.5rem] md:rounded-[2rem] hover:bg-emerald-600 transition-all text-base md:text-lg uppercase tracking-widest">Visit Store</button>
                </div>
              );
            })
          )}
        </div>
      )}

      {view === 'messages' && <MessagesView currentUser={user} />}

      {view === 'store' && selectedFarmer && (
        <div className="animate-in slide-in-from-bottom-20 duration-700">
           <div className="flex items-center gap-8 md:gap-10 mb-16 md:mb-20">
              <button onClick={() => { setView('marketplace'); setSelectedFarmer(null); selectedFarmerIdRef.current = null; }} className="w-14 h-14 md:w-16 md:h-16 bg-white rounded-2xl border-2 border-slate-100 text-slate-400 hover:text-emerald-600 shadow-xl transition-all flex items-center justify-center">
