import React, { useState, useEffect, useRef } from 'react';
import { User, ChatMessage } from '../types';
import { db } from '../services/db';

interface Props {
  currentUser: User;
}

const MessagesView: React.FC<Props> = ({ currentUser }) => {
  const [conversations, setConversations] = useState<{user: User, lastMsg?: ChatMessage}[]>([]);
  const [selectedRecipient, setSelectedRecipient] = useState<User | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const loadConversations = async () => {
      const allUsers = await db.users.find();
      // In a real app, we'd filter by users we've chatted with. 
      // For this demo, we'll list all users of opposite role or anyone involved in orders.
      const others = allUsers.filter(u => u.id !== currentUser.id && u.role !== currentUser.role);

      const convosWithLastMsg = others.map(u => {
        const chatKey = `chat_${[currentUser.id, u.id].sort().join('_')}`;
        const saved = localStorage.getItem(chatKey);
        const parsed = saved ? JSON.parse(saved) : [];
        return {
          user: u,
          lastMsg: parsed.length > 0 ? parsed[parsed.length - 1] : undefined
        };
      });

      setConversations(convosWithLastMsg.sort((a, b) => {
        if (!a.lastMsg) return 1;
        if (!b.lastMsg) return -1;
        return new Date(b.lastMsg.timestamp).getTime() - new Date(a.lastMsg.timestamp).getTime();
      }));
    };
    loadConversations();
  }, [currentUser.id, currentUser.role]);

  useEffect(() => {
    if (!selectedRecipient) return;
    const chatKey = `chat_${[currentUser.id, selectedRecipient.id].sort().join('_')}`;

    const loadMsgs = () => {
      const saved = localStorage.getItem(chatKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.length !== messages.length) setMessages(parsed);
      } else {
        setMessages([]);
      }
    };

    loadMsgs();
    const interval = setInterval(loadMsgs, 2000);
    return () => clearInterval(interval);
  }, [selectedRecipient, currentUser.id, messages.length]);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || !selectedRecipient) return;

    const newMessage: ChatMessage = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      receiverId: selectedRecipient.id,
      text: inputText,
      timestamp: new Date().toISOString()
    };

    const updated = [...messages, newMessage];
    const chatKey = `chat_${[currentUser.id, selectedRecipient.id].sort().join('_')}`;
    localStorage.setItem(chatKey, JSON.stringify(updated));
    setMessages(updated);
    setInputText('');
  };

  return (
    <div className="flex flex-col lg:flex-row h-[700px] bg-white rounded-[3rem] shadow-2xl border-2 border-slate-50 overflow-hidden animate-in fade-in slide-in-from-bottom-5">
      {/* Sidebar - Contacts */}
      <div className="w-full lg:w-96 border-r-2 border-slate-50 flex flex-col h-full bg-[#FBFDFB]">
        <div className="p-10 border-b-2 border-slate-50">
          <h2 className="text-3xl font-serif text-slate-900 tracking-tight">Farm Connect</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-3">Active Negotiations</p>
        </div>
        <div className="flex-1 overflow-y-auto">
          {conversations.length === 0 ? (
            <div className="p-10 text-center text-slate-400 font-medium italic text-sm">No contacts yet. Start an order to chat.</div>
          ) : (
            conversations.map(c => (
              <button 
                key={c.user.id}
                onClick={() => setSelectedRecipient(c.user)}
                className={`w-full p-8 flex items-center gap-6 border-b border-slate-50 transition-all hover:bg-white text-left ${selectedRecipient?.id === c.user.id ? 'bg-white border-l-8 border-l-emerald-600 shadow-inner' : ''}`}
              >
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center text-xl font-black shadow-lg ${selectedRecipient?.id === c.user.id ? 'bg-emerald-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                  {c.user.name[0]}
                </div>
                <div className="flex-1 truncate">
                  <div className="flex justify-between items-center mb-1">
                    <h4 className="font-bold text-slate-900 truncate">{c.user.name}</h4>
                    {c.lastMsg && <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{new Date(c.lastMsg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>}
                  </div>
                  <p className="text-xs text-slate-400 truncate font-medium">{c.lastMsg ? c.lastMsg.text : `Start a conversation...`}</p>
                </div>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col h-full bg-white">
        {selectedRecipient ? (
          <>
            <div className="p-8 border-b-2 border-slate-50 flex items-center justify-between">
              <div className="flex items-center gap-5">
                <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center font-black text-lg border-2 border-emerald-100">
                  {selectedRecipient.name[0]}
                </div>
                <div>
                  <h3 className="font-bold text-slate-900">{selectedRecipient.name}</h3>
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{selectedRecipient.role} Network</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-10 space-y-6 bg-slate-50/30">
              {messages.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-30 grayscale p-20">
                    <svg className="w-24 h-24 mb-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72"></path></svg>
                    <p className="text-2xl font-serif italic text-slate-400">Secure end-to-end negotiation channel.</p>
                </div>
              ) : (
                messages.map(m => (
                  <div key={m.id} className={`flex ${m.senderId === currentUser.id ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[70%] px-6 py-4 rounded-[2rem] text-sm font-medium shadow-xl transition-all ${
                      m.senderId === currentUser.id ? 'bg-emerald-600 text-white rounded-tr-none' : 'bg-white text-slate-800 border-2 border-slate-100 rounded-tl-none'
                    }`}>
                      {m.text}
                      <div className={`text-[9px] mt-2 font-black tracking-widest uppercase ${m.senderId === currentUser.id ? 'text-emerald-200' : 'text-slate-400'}`}>
                        {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </div>
                    </div>
                  </div>
                ))
              )}
              <div ref={scrollRef} />
            </div>

            <form onSubmit={sendMessage} className="p-8 border-t-2 border-slate-50">
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="Negotiate harvest details..."
                  className="w-full pl-8 pr-20 py-5 bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] text-base font-bold placeholder-slate-400 focus:bg-white focus:border-emerald-600 outline-none transition-all shadow-inner"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                />
                <button 
                  type="submit"
                  className="absolute right-3 top-1/2 -translate-y-1/2 w-14 h-14 bg-emerald-600 text-white rounded-2xl flex items-center justify-center shadow-xl hover:bg-emerald-700 transition-all active:scale-90"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
                </button>
              </div>
            </form>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-20 text-center space-y-8 animate-in fade-in duration-1000">
             <div className="w-32 h-32 bg-slate-50 rounded-[3.5rem] flex items-center justify-center text-slate-300 shadow-inner">
                <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z"></path></svg>
             </div>
             <div className="max-w-md">
                <h3 className="text-3xl font-serif text-slate-900 tracking-tight">Select a Conversation</h3>
                <p className="text-slate-500 font-medium leading-relaxed mt-4">Select a buyer or farmer from the left to begin negotiating prices, quality, or delivery logistics.</p>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MessagesView;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Product, Order } from '../types';
import { calculateDistance } from '../utils/geo';
import { db } from '../services/db';
import { suggestUsage } from '../services/geminiService';
import MessagesView from './MessagesView';

const StarRating: React.FC<{ initialValue?: number, onRate?: (val: number) => void, interactive?: boolean }> = ({ initialValue = 0, onRate, interactive = false }) => {
  const [hover, setHover] = useState(0);
  const stars = [1, 2, 3, 4, 5];

  return (
    <div className="flex items-center gap-1">
      {stars.map((star) => (
        <button
          key={star}
          type="button"
          disabled={!interactive}
          className={`${interactive ? 'cursor-pointer hover:scale-125' : 'cursor-default'} transition-all`}
          onClick={() => interactive && onRate && onRate(star)}
          onMouseEnter={() => interactive && setHover(star)}
          onMouseLeave={() => interactive && setHover(0)}
        >
          <svg
            className={`w-5 h-5 md:w-6 md:h-6 ${
              star <= (hover || initialValue) ? 'text-amber-500 fill-current' : 'text-slate-200 fill-current'
            }`}
            viewBox="0 0 20 20"
          >
            <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
          </svg>
        </button>
      ))}
    </div>
  );
};

// Added missing Props interface to fix the error on line 39
interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const BuyerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [view, setView] = useState<'marketplace' | 'store' | 'orders' | 'messages'>('marketplace');
  const [farmers, setFarmers] = useState<User[]>([]);
  const [selectedFarmer, setSelectedFarmer] = useState<User | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [buyerOrders, setBuyerOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'all' | 'favorites'>('all');
  const [orderQuantities, setOrderQuantities] = useState<Record<string, number>>({});
  const [aiSuggestions, setAiSuggestions] = useState<Record<string, string>>({});
  const [ratingModal, setRatingModal] = useState<Order | null>(null);
  const [cancelConfirmOrder, setCancelConfirmOrder] = useState<Order | null>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const buttonPrimary = "bg-emerald-600 hover:bg-emerald-700 text-white font-black py-4 px-8 rounded-2xl shadow-lg hover:shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50";

  const selectedFarmerIdRef = useRef<string | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    try {
      const allUsers = await db.users.find({ role: 'farmer' });
      setFarmers(allUsers);

      const orders = await db.orders.find({ buyerId: user.id });
      setBuyerOrders(orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

      if (selectedFarmerIdRef.current) {
        const fid = selectedFarmerIdRef.current;
        const farmerProducts = await db.products.find({ farmerId: fid });
        setStoreProducts(farmerProducts);
      }
    } catch (error) {
      console.error("Load Data Error:", error);
    }
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const nearbyFarmers = farmers.filter(f => {
    if (!user.location || !f.location) return true;
    const distance = calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng);
    return distance <= (f.deliveryDistance || 20); // Fallback to 20km if not working perfectly
  });

  const displayFarmers = activeTab === 'all' ? nearbyFarmers : nearbyFarmers.filter(f => user.favorites?.includes(f.id));

  const handleOpenStore = async (farmer: User) => {
    selectedFarmerIdRef.current = farmer.id;
    setSelectedFarmer(farmer);
    const farmerProducts = await db.products.find({ farmerId: farmer.id });
    setStoreProducts(farmerProducts);
    const initQtys: Record<string, number> = {};
    farmerProducts.forEach(p => initQtys[p.id] = 1);
    setOrderQuantities(initQtys);
    setView('store');
  };

  const handleBuy = async (product: Product) => {
    if (!selectedFarmer) return;
    const selectedQty = orderQuantities[product.id] || 1;

    if (selectedQty > product.stock) {
      showToast(`Insufficient stock! Only ${product.stock} available.`, 'error');
      return;
    }

    try {
      const newOrder: Order = {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        productName: product.name,
        farmerId: selectedFarmer.id,
        farmName: selectedFarmer.name,
        buyerId: user.id,
        buyerName: user.name,
        buyerLocation: user.location?.address || 'Standard Delivery',
        quantity: selectedQty,
        totalPrice: product.price * selectedQty,
        status: 'pending',
        date: new Date().toISOString()
      };

      await db.orders.insertOne(newOrder);
      await db.products.updateOne(product.id, { stock: (product.stock || 0) - selectedQty });

      const currentBatchQty = selectedFarmer.currentQuantity || 0;
      await db.users.updateOne(selectedFarmer.id, { currentQuantity: currentBatchQty + selectedQty });

      showToast(`Order placed successfully! Waiting for farm confirmation.`);
      await loadData();
      setView('orders');
    } catch (err) {
      showToast("Failed to place order.", "error");
    }
  };

  const confirmCancelOrder = async () => {
    if (!cancelConfirmOrder) return;
    const order = cancelConfirmOrder;

    try {
      await db.orders.updateOne(order.id, { status: 'cancelled' });
      const product = await db.products.findOne({ id: order.productId });
      if (product) {
        await db.products.updateOne(product.id, { stock: (product.stock || 0) + order.quantity });
      }
      const farmer = await db.users.findOne({ id: order.farmerId });
      if (farmer) {
        const updatedQty = Math.max(0, (farmer.currentQuantity || 0) - order.quantity);
        await db.users.updateOne(farmer.id, { currentQuantity: updatedQty });
      }
      setCancelConfirmOrder(null);
      await loadData();
      showToast("Order cancelled.");
    } catch (err) {
      showToast("Error cancelling order.", "error");
    }
  };

  const handleGiveRating = async (farmerId: string, value: number) => {
    try {
      const farmer = await db.users.findOne({ id: farmerId });
      if (farmer) {
        const oldRating = farmer.rating || 0;
        const newRating = oldRating === 0 ? value : (oldRating + value) / 2;
        await db.users.updateOne(farmer.id, { rating: newRating });
        setRatingModal(null);
        await loadData();
        showToast("Farm experience rated!");
      }
    } catch (err) {
      showToast("Failed to submit rating.", "error");
    }
  };

  const handleAISuggestUsage = async (product: Product) => {
    if (aiSuggestions[product.id]) return;
    const suggestion = await suggestUsage(product.name);
    setAiSuggestions(prev => ({ ...prev, [product.id]: suggestion }));
  };

  const toggleFavorite = async (farmerId: string) => {
    const currentFavs = user.favorites || [];
    const newFavs = currentFavs.includes(farmerId) 
      ? currentFavs.filter(id => id !== farmerId)
      : [...currentFavs, farmerId];
    await db.users.updateOne(user.id, { favorites: newFavs });
    onUpdateUser({ favorites: newFavs });
  };

  return (
    <div className="max-w-7xl mx-auto p-8 md:p-16 animate-in fade-in duration-700 relative">

      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 duration-300 font-black text-xs uppercase tracking-widest border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'}`}>
           {toast.message}
        </div>
      )}

      <div className="flex flex-col md:flex-row items-center justify-between mb-16 md:mb-20 gap-8 md:gap-12">
        <div className="flex bg-white p-2 md:p-2.5 rounded-[2rem] md:rounded-[2.8rem] shadow-2xl border-2 border-slate-100 overflow-x-auto max-w-full">
          <button onClick={() => { setView('marketplace'); setSelectedFarmer(null); selectedFarmerIdRef.current = null; }} className={`whitespace-nowrap px-6 md:px-12 py-3 md:py-5 rounded-[1.5rem] md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === 'marketplace' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Marketplace</button>
          <button onClick={() => setView('orders')} className={`whitespace-nowrap px-6 md:px-12 py-3 md:py-5 rounded-[1.5rem] md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === 'orders' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Orders</button>
          <button onClick={() => setView('messages')} className={`whitespace-nowrap px-6 md:px-12 py-3 md:py-5 rounded-[1.5rem] md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === 'messages' ? 'bg-emerald-600 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>Messages</button>
        </div>
        {view === 'marketplace' && (
          <div className="flex bg-white p-2 rounded-full shadow-lg border border-slate-100">
             <button onClick={() => setActiveTab('all')} className={`px-6 md:px-10 py-3 rounded-full text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'all' ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400'}`}>Nearby</button>
             <button onClick={() => setActiveTab('favorites')} className={`px-6 md:px-10 py-3 rounded-full text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'favorites' ? 'bg-pink-500 text-white shadow-xl' : 'text-slate-400'}`}>Favorites</button>
          </div>
