                 <svg className="w-8 h-8 rotate-180" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7"></path></svg>
              </button>
              <div>
                <h2 className="text-4xl md:text-6xl font-serif text-slate-900 tracking-tight">{selectedFarmer.name}</h2>
                <div className="flex items-center gap-4 mt-2">
                   <StarRating initialValue={Math.round(selectedFarmer.rating || 0)} />
                   <p className="text-slate-400 font-bold uppercase text-[9px] md:text-[11px] tracking-widest hidden sm:block">Farm Direct</p>
                </div>
              </div>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 md:gap-14">
              {storeProducts.map(p => (
