                  </div>
                  <div className="p-10 md:p-14 flex-1 flex flex-col">
                      <h3 className="text-2xl md:text-3xl font-serif text-slate-900 mb-4">{p.name}</h3>
                      <p className="text-slate-500 font-medium mb-6 leading-relaxed italic text-base md:text-lg opacity-80 line-clamp-2">"{p.description}"</p>

                      {aiSuggestions[p.id] ? (
                        <div className="mb-6 p-4 bg-emerald-50 rounded-2xl border border-emerald-100 animate-in fade-in">
                          <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">AI Usage Tip</p>
                          <p className="text-sm font-medium text-slate-700 italic">"{aiSuggestions[p.id]}"</p>
