                        <div className="flex items-center justify-between bg-slate-50 p-4 rounded-2xl">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Qty ({p.unit})</label>
                          <input 
                            type="number" 
                            min="1" 
