                      </div>
                  </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {view === 'orders' && (
        <div className="bg-white rounded-[3rem] md:rounded-[4.5rem] shadow-2xl border-2 border-slate-50 overflow-hidden">
           <div className="p-12 md:p-20 bg-[#FBFDFB] border-b-2 border-slate-100 text-center">
              <h2 className="text-4xl md:text-6xl font-serif text-slate-900 tracking-tight leading-tight">Harvest Track</h2>
              <p className="text-slate-400 font-bold uppercase text-[10px] md:text-[11px] tracking-[0.5em] mt-5">Supply chain visibility</p>
           </div>
           <div className="overflow-x-auto">
              <table className="w-full text-left">
                 <thead className="text-slate-400 text-[10px] md:text-[11px] font-black uppercase tracking-[0.4em] bg-slate-100/30">
                    <tr>
                       <th className="px-10 md:px-20 py-8 md:py-10">Produce</th>
                       <th className="px-10 md:px-20 py-8 md:py-10">Status</th>
                       <th className="px-10 md:px-20 py-8 md:py-10">Action</th>
                       <th className="px-10 md:px-20 py-8 md:py-10 text-right">Settlement</th>
                    </tr>
                 </thead>
                 <tbody className="divide-y-4 divide-slate-50">
                    {buyerOrders.map(o => (
                      <tr key={o.id} className={`hover:bg-slate-50 transition-all ${o.status === 'cancelled' ? 'opacity-50 grayscale' : ''}`}>
                          <td className="px-10 md:px-20 py-10 md:py-14">
                            <p className="font-serif text-slate-900 text-2xl md:text-3xl tracking-tight leading-tight">{o.productName}</p>
                            <p className="text-emerald-600 font-black text-[9px] md:text-[10px] uppercase tracking-widest mt-2">{o.farmName}</p>
                          </td>
                          <td className="px-10 md:px-20 py-10 md:py-14">
                             <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${o.status === 'pending' ? 'bg-amber-100 text-amber-600' : o.status === 'confirmed' ? 'bg-blue-100 text-blue-600' : o.status === 'delivered' ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                                {o.status}
                             </div>
                          </td>
                          <td className="px-10 md:px-20 py-10 md:py-14">
                            <div className="flex items-center gap-4">
                              {o.status === 'delivered' && (
                                <button onClick={() => setRatingModal(o)} className="bg-amber-100 text-amber-700 font-black px-6 py-3 rounded-xl text-[10px] uppercase tracking-widest border-2 border-amber-200">Rate Farm</button>
