                              {o.status === 'pending' && (
                                <button onClick={() => setCancelConfirmOrder(o)} className="text-red-500 font-black text-[10px] uppercase tracking-widest hover:underline">Cancel</button>
                              )}
                              {(o.status === 'confirmed' || o.status === 'shipped') && (
                                <span className="text-slate-400 font-black text-[9px] uppercase tracking-widest">Confirmed (No Cancel)</span>
                              )}
                            </div>
                          </td>
                          <td className="px-10 md:px-20 py-10 md:py-14 text-right font-black text-slate-900 text-2xl md:text-3xl tracking-tighter">₹{o.totalPrice.toFixed(2)}</td>
                      </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {ratingModal && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[300] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-md rounded-[4rem] p-12 shadow-2xl space-y-10 animate-in zoom-in">
              <div className="text-center space-y-4">
                <h2 className="text-3xl font-serif text-slate-900 leading-tight">Rate your farm experience?</h2>
                <p className="text-slate-500 text-sm font-medium">For <span className="text-emerald-600 font-bold">{ratingModal.farmName}</span></p>
              </div>
              <div className="flex justify-center p-8 bg-slate-50 rounded-[3rem] shadow-inner">
                 <StarRating interactive onRate={(val) => handleGiveRating(ratingModal.farmerId, val)} />
              </div>
              <button onClick={() => setRatingModal(null)} className="w-full text-slate-400 font-black text-[10px] uppercase tracking-widest">Dismiss</button>
           </div>
        </div>
      )}

      {cancelConfirmOrder && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-lg z-[1000] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl text-center">
              <h2 className="text-3xl font-serif text-slate-900 tracking-tight mb-4">Cancel Order?</h2>
              <p className="text-slate-500 font-medium mb-10">Are you sure? Items will return to stock.</p>
              <div className="space-y-4">
                 <button onClick={confirmCancelOrder} className="w-full bg-red-600 text-white font-black py-4 rounded-2xl uppercase tracking-widest text-xs">Yes, Cancel Order</button>
                 <button onClick={() => setCancelConfirmOrder(null)} className="w-full bg-slate-100 text-slate-400 font-black py-4 rounded-2xl uppercase tracking-widest text-xs">Go Back</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default BuyerDashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Role, Product, Order, Location } from './types';
import LoginView from './views/Login';
import FarmerDashboard from './views/FarmerDashboard';
import BuyerDashboard from './views/BuyerDashboard';
import { getAddressFromCoords, getCoordsFromAddress } from './services/geminiService';
import { db } from './services/db';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userLocation, setUserLocation] = useState<Location | null>(null);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [showManualLoc, setShowManualLoc] = useState(false);
  const [manualAddress, setManualAddress] = useState('');

  const updateLocationState = async (loc: Location) => {
    setUserLocation(loc);
    if (currentUser) {
      await db.users.updateOne(currentUser.id, { location: loc });
      const updated = { ...currentUser, location: loc };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  const fetchLocation = useCallback(async (force = false) => {
    if (!force && userLocation) return;

    if (!("geolocation" in navigator)) {
      setLocationError("Geolocation not supported");
      setShowManualLoc(true);
      return;
    }

    setIsLocating(true);
    setLocationError(null);

    const options = {
      timeout: 15000,
      enableHighAccuracy: true,
      maximumAge: 0
    };

    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        const address = await getAddressFromCoords(loc.lat, loc.lng);
        const finalLoc = { ...loc, address };
        await updateLocationState(finalLoc);
      } catch (err) {
        setLocationError("Address resolution failed");
        setShowManualLoc(true);
      } finally {
        setIsLocating(false);
      }
    }, (err) => {
      setIsLocating(false);
      setShowManualLoc(true);
      setLocationError("Permission denied or timeout");
    }, options);
  }, [currentUser, userLocation]);

  useEffect(() => {
    const checkAuth = async () => {
      const savedUser = localStorage.getItem('agro_user');
      if (savedUser) {
        const parsed = JSON.parse(savedUser);
        const actualUser = await db.users.findOne({ id: parsed.id });
        if (actualUser) {
          setCurrentUser(actualUser);
          setIsLoggedIn(true);
          if (actualUser.location) {
            setUserLocation(actualUser.location);
          }
        }
      }
    };
    checkAuth();
  }, []);

  useEffect(() => {
    if (isLoggedIn && !userLocation && !isLocating) {
      fetchLocation();
    }
  }, [isLoggedIn, userLocation, isLocating, fetchLocation]);

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualAddress.trim()) return;
    setIsLocating(true);
    try {
      const coords = await getCoordsFromAddress(manualAddress);
      const finalLoc = { ...coords, address: manualAddress };
      await updateLocationState(finalLoc);
      setShowManualLoc(false);
    } catch (err) {
      setLocationError("Location not found");
    } finally {
      setIsLocating(false);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsLoggedIn(true);
    localStorage.setItem('agro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsLoggedIn(false);
    setUserLocation(null);
    localStorage.removeItem('agro_user');
  };

  const updateCurrentUser = async (updates: Partial<User>) => {
    if (currentUser) {
      await db.users.updateOne(currentUser.id, updates);
      const updated = { ...currentUser, ...updates };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  if (!isLoggedIn) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-emerald-100 selection:text-emerald-900">
      <header className="bg-white/95 backdrop-blur-xl border-b border-slate-200 sticky top-0 z-50 px-6 md:px-12 py-5 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-100 transform hover:scale-105 transition-transform">
            <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h1 className="text-2xl font-serif font-black text-slate-900 hidden sm:block tracking-tight">AgroFlow</h1>
        </div>

        <div className="flex items-center gap-4 md:gap-6">
          <button 
            onClick={() => fetchLocation(true)}
            disabled={isLocating}
            className={`flex items-center gap-3 text-[10px] md:text-[11px] font-black uppercase tracking-widest transition-all px-4 md:px-5 py-2.5 rounded-2xl border ${isLocating ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-500 hover:border-emerald-500 hover:text-emerald-600 border-slate-200 shadow-sm'}`}
          >
            <svg className={`w-4 h-4 ${isLocating ? 'animate-spin' : 'text-emerald-500'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path></svg>
            <span className="truncate max-w-[120px] md:max-w-[200px]">
              {isLocating ? 'UPDATING...' : (userLocation?.address || 'DETECT LOCATION')}
            </span>
          </button>

          <div className="flex items-center gap-4 border-l border-slate-200 pl-4 md:pl-6">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black text-slate-800 tracking-tight">{currentUser?.name}</p>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">{currentUser?.role}</p>
            </div>
            <button onClick={handleLogout} className="w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all rounded-2xl border border-slate-100 shadow-sm">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 16l4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
            </button>
          </div>
        </div>
      </header>

      {showManualLoc && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <h2 className="text-3xl font-serif text-slate-900 tracking-tight mb-4 text-center">Update Location</h2>
            <form onSubmit={handleManualLocation} className="space-y-6">
               <input 
                type="text" placeholder="Enter City/Area (e.g. Pune)" 
                className="w-full px-6 py-4 rounded-2xl border-2 border-slate-100 font-bold focus:border-emerald-600 outline-none"
                value={manualAddress} onChange={e => setManualAddress(e.target.value)} required
               />
               <div className="flex flex-col gap-3">
                  <button type="submit" disabled={isLocating} className="w-full bg-emerald-600 text-white font-black py-4 rounded-2xl shadow-xl hover:bg-emerald-700 transition-all uppercase tracking-widest text-xs">
                    SET MANUAL LOCATION
                  </button>
                  <button type="button" onClick={() => setShowManualLoc(false)} className="w-full text-slate-400 font-black py-2 uppercase tracking-widest text-[10px]">CANCEL</button>
               </div>
            </form>
          </div>
        </div>
      )}

      <main className="flex-1">
        {currentUser?.role === 'farmer' ? (
          <FarmerDashboard user={currentUser} onUpdateUser={updateCurrentUser} />
        ) : (
          <BuyerDashboard user={currentUser!} onUpdateUser={updateCurrentUser} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import { db } from '../services/db';
import MessagesView from './MessagesView';

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'messages' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    setProducts([...userProducts].sort((a, b) => a.name.localeCompare(b.name)));
    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleResetBatch = async () => {
    await db.users.updateOne(user.id, { currentQuantity: 0 });
    onUpdateUser({ currentQuantity: 0 });
    showToast("Batch progress reset for new harvest.");
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    await db.orders.updateOne(orderId, { status: newStatus });
    showToast(`Order marked as ${newStatus}`);
    await loadData();
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) setEditingProduct({ ...editingProduct, imageUrl: base64String });
        else setNewProduct({ ...newProduct, imageUrl: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.imageUrl) { showToast("Upload a photo.", "error"); return; }
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Fresh harvest.",
      imageUrl: newProduct.imageUrl
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      await db.products.updateOne(editingProduct.id, editingProduct);
      setEditingProduct(null);
      showToast("Updated!");
      await loadData();
    }
  };

  const handleMagicDescription = async () => {
    if (!newProduct.name) return;
    setIsGenerating(true);
    const desc = await generateProductDescription(newProduct.name, newProduct.category);
    setNewProduct({ ...newProduct, description: desc });
    setIsGenerating(false);
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    const price = await suggestPrice(newProduct.name);
    setNewProduct({ ...newProduct, price });
    setIsPricing(false);
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);
  const pendingRequests = orders.filter(o => o.status === 'pending').length;

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-73px)]">
      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-xs uppercase tracking-widest`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar */}
      <nav className="w-full md:w-80 glass border-r border-slate-200 p-8 space-y-4 flex-shrink-0 z-10 overflow-y-auto">
        <div className="pb-6 px-4"><h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Control Room</h3></div>
        {[
          { id: 'overview', label: 'Dashboard', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z' },
          { id: 'products', label: 'My Inventory', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
          { id: 'add-product', label: 'Add Harvest', icon: 'M12 4v16m8-8H4' },
          { id: 'orders', label: 'Orders', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2' },
          { id: 'messages', label: 'Messages', icon: 'M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72' },
          { id: 'settings', label: 'Logistics', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066' }
        ].map(item => (
          <button 
            key={item.id} onClick={() => setActiveTab(item.id as any)}
            className={`w-full flex items-center gap-5 px-7 py-5 rounded-[1.8rem] transition-all font-black text-xs uppercase tracking-widest border-2 ${activeTab === item.id ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200 scale-[1.02]' : 'bg-white border-transparent text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path></svg>
            {item.label}
          </button>
        ))}
      </nav>

      {/* Main Content */}
      <div className="flex-1 p-8 md:p-14 max-w-7xl mx-auto w-full overflow-y-auto">

        {activeTab === 'overview' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="bg-white p-12 rounded-[4.5rem] shadow-xl border border-slate-100 flex flex-col lg:flex-row items-center justify-between gap-12 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-8 opacity-5"><svg className="w-48 h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path></svg></div>
               <div className="space-y-6 flex-1 text-center lg:text-left z-10">
                  <h2 className="text-5xl font-serif text-slate-900 tracking-tight leading-tight">Batch Readiness</h2>
                  <p className="text-slate-500 text-lg font-medium max-w-lg leading-relaxed">Collect buyer interest to trigger direct fulfillment. Reset once your current batch is delivered.</p>
                  <div className="flex flex-wrap gap-4 justify-center lg:justify-start">
                    <div className="bg-emerald-600 text-white px-10 py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-200 text-2xl tracking-tighter">
                      {currentProgress} / {threshold} KG
                    </div>
                    {progressPercent >= 100 && (
                      <button onClick={handleResetBatch} className="bg-slate-900 text-white px-8 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-emerald-700 transition-all">Start New Batch</button>
                    )}
                  </div>
               </div>
               <div className="relative w-80 h-80 flex items-center justify-center flex-shrink-0 bg-white rounded-full p-10 shadow-2xl border-4 border-slate-50">
                  <svg className="w-full h-full -rotate-90 overflow-visible" viewBox="0 0 320 320">
                    <circle cx="160" cy="160" r="130" className="stroke-slate-100 fill-none" strokeWidth="28" />
                    <circle cx="160" cy="160" r="130" className="stroke-emerald-500 fill-none transition-all duration-1000" strokeWidth="28" strokeDasharray={`${progressPercent * 8.16} 816`} strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-6xl font-black tracking-tighter text-slate-800">{Math.round(progressPercent)}%</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">GOAL</span>
                  </div>
               </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
               <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-6">Farm Rating</p>
                  <div className="flex items-center gap-4">
                    <p className="text-5xl font-black text-slate-900 tracking-tighter">{user.rating?.toFixed(1) || '0.0'}</p>
                    <svg className="w-10 h-10 text-amber-400 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg>
                  </div>
               </div>
               <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-6">Active Requests</p>
                  <p className="text-5xl font-black text-blue-600 tracking-tighter">{pendingRequests}</p>
               </div>
               <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-6">Total Listings</p>
                  <p className="text-5xl font-black text-slate-900 tracking-tighter">{products.length}</p>
               </div>
               <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-6">Completed Sales</p>
                  <p className="text-5xl font-black text-emerald-600 tracking-tighter">{orders.filter(o => o.status === 'delivered').length}</p>
               </div>
             </div>
          </div>
        )}

        {activeTab === 'products' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="flex justify-between items-end px-4">
                <div><h2 className="text-4xl font-serif text-slate-900 tracking-tight">Farm Inventory</h2><p className="text-slate-400 font-black text-[10px] uppercase tracking-widest mt-3">Active Listings</p></div>
                <button onClick={() => setActiveTab('add-product')} className="bg-slate-900 text-white font-black px-10 py-5 rounded-[2rem] hover:bg-emerald-600 transition-all text-xs uppercase tracking-widest shadow-xl">Add New Harvest</button>
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                {products.map(p => (
                  <div key={p.id} className="bg-white rounded-[4rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group overflow-hidden flex flex-col">
                     <div className="flex flex-col md:flex-row p-10 gap-10">
                        <div className="w-full md:w-56 h-56 rounded-[3rem] overflow-hidden bg-slate-50 flex-shrink-0 relative shadow-inner"><img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={p.name} /></div>
                        <div className="flex-1">
                           <div className="flex justify-between items-start mb-4"><h3 className="text-3xl font-serif text-slate-900 tracking-tight">{p.name}</h3><div className="text-emerald-600 font-black text-2xl tracking-tighter">₹{p.price}</div></div>
                           <p className="text-slate-500 font-medium text-sm italic opacity-90 line-clamp-3">"{p.description}"</p>
                        </div>
                     </div>
                     <div className="bg-slate-50/50 p-6 flex gap-6"><button onClick={() => setEditingProduct(p)} className="flex-1 bg-white border-2 border-slate-200 text-slate-800 font-black text-[11px] uppercase tracking-widest hover:bg-emerald-600 hover:text-white py-5 rounded-[1.8rem] transition-all shadow-sm">Edit</button></div>
                  </div>
                ))}
             </div>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="bg-white rounded-[4rem] shadow-2xl border border-slate-100 overflow-hidden">
                <div className="p-10 border-b border-slate-100 bg-emerald-50/20 flex justify-between items-center"><h2 className="text-3xl font-serif text-slate-900">Buyer Fulfillment List</h2><div className="bg-emerald-600 text-white px-6 py-2 rounded-full font-black text-[10px] uppercase tracking-widest">{pendingRequests} Pending</div></div>
                <div className="overflow-x-auto">
                   <table className="w-full text-left">
                      <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest"><tr className="border-b border-slate-100"><th className="px-10 py-6">Buyer / Product</th><th className="px-10 py-6">Status</th><th className="px-10 py-6">Action</th></tr></thead>
                      <tbody className="divide-y divide-slate-100">
                         {orders.map(o => (
                           <tr key={o.id} className="hover:bg-slate-50/50 transition-all">
                              <td className="px-10 py-8"><p className="font-black text-slate-900">{o.buyerName}</p><p className="text-xs text-emerald-600 font-bold">{o.productName} ({o.quantity}kg)</p></td>
                              <td className="px-10 py-8"><div className={`inline-flex px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${o.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>{o.status}</div></td>
                              <td className="px-10 py-8">
                                 <div className="flex gap-2">
                                    {o.status === 'pending' && <button onClick={() => handleUpdateOrderStatus(o.id, 'confirmed')} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">Confirm</button>}
                                    {o.status === 'confirmed' && <button onClick={() => handleUpdateOrderStatus(o.id, 'delivered')} className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">Deliver</button>}
                                    <button onClick={() => setActiveTab('messages')} className="bg-slate-900 text-white p-2 rounded-xl"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72"></path></svg></button>
                                 </div>
                              </td>
                           </tr>
                         ))}
                      </tbody>
                   </table>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'add-product' && (
           <div className="bg-white p-12 lg:p-16 rounded-[4rem] shadow-2xl border border-slate-100 animate-in slide-in-from-bottom-10 duration-700 max-w-4xl mx-auto">
              <h2 className="text-5xl font-serif text-slate-900 tracking-tight mb-8">Produce Studio</h2>
              <form onSubmit={handleAddProduct} className="space-y-8">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Product Name</label><input type="text" required className={inputClasses} placeholder="Kashmiri Apple" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Category</label><select className={inputClasses} value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>{categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}</select></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Price (₹)</label><div className="relative"><input type="number" required className={inputClasses} value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: e.target.value})} /><button type="button" onClick={handleAISuggestPrice} className="absolute right-4 top-1/2 -translate-y-1/2 text-emerald-600 font-black text-[10px] uppercase">✨ AI</button></div></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Stock</label><input type="number" required className={inputClasses} value={newProduct.stock} onChange={e => setNewProduct({...newProduct, stock: e.target.value})} /></div>
                 </div>
                 <div className="space-y-2"><div className="flex justify-between items-center ml-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Description</label><button type="button" onClick={handleMagicDescription} className="text-emerald-600 font-black text-[10px] uppercase">✨ Magic Write</button></div><textarea className={`${inputClasses} min-h-[120px]`} value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})} /></div>
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Photo</label><div onClick={() => fileInputRef.current?.click()} className="h-64 bg-slate-50 border-4 border-dashed border-slate-200 rounded-[3rem] overflow-hidden cursor-pointer flex items-center justify-center hover:border-emerald-400 transition-all">{newProduct.imageUrl ? <img src={newProduct.imageUrl} className="w-full h-full object-cover" /> : <p className="text-slate-400 font-black text-xs uppercase">Click to upload</p>}</div><input type="file" hidden ref={fileInputRef} accept="image/*" onChange={(e) => handleImageUpload(e)} /></div>
                 <button type="submit" className="w-full bg-slate-900 text-white font-black py-8 rounded-[2.5rem] hover:bg-emerald-600 transition-all text-xl uppercase tracking-widest shadow-2xl">Publish Listing</button>
              </form>
           </div>
        )}

        {activeTab === 'messages' && <MessagesView currentUser={user} />}
        {activeTab === 'settings' && (
           <div className="max-w-4xl mx-auto bg-white p-14 rounded-[4rem] shadow-xl border border-slate-200"><h2 className="text-4xl font-serif text-slate-900 mb-8">Logistics Thresholds</h2><form className="space-y-10" onSubmit={(e) => { e.preventDefault(); onUpdateUser({ deliveryDistance: user.deliveryDistance, thresholdQuantity: user.thresholdQuantity }); showToast("Updated!"); }}><div className="space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Service Radius (KM)</label><input type="number" className={inputClasses} value={user.deliveryDistance} onChange={e => onUpdateUser({ deliveryDistance: parseInt(e.target.value) })} /></div><div className="space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Harvest Threshold (KG)</label><input type="number" className={inputClasses} value={user.thresholdQuantity} onChange={e => onUpdateUser({ thresholdQuantity: parseInt(e.target.value) })} /></div><button type="submit" className="w-full bg-slate-900 text-white font-black py-6 rounded-[2rem] hover:bg-emerald-600 transition-all uppercase tracking-widest">Update Policy</button></form></div>
        )}
      </div>

      {editingProduct && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[500] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-3xl rounded-[4.5rem] p-14 shadow-2xl border-2 border-slate-100 overflow-y-auto max-h-[90vh]"><div className="flex justify-between items-center mb-10"><h2 className="text-4xl font-serif text-slate-900">Edit Product</h2><button onClick={() => setEditingProduct(null)} className="text-slate-400 hover:text-red-500 font-black uppercase text-xs">Close</button></div><form onSubmit={handleUpdateProduct} className="space-y-8"><input type="text" className={inputClasses} value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} /><div onClick={() => editFileInputRef.current?.click()} className="h-64 bg-slate-50 rounded-[3rem] border-2 border-slate-100 overflow-hidden cursor-pointer"><img src={editingProduct.imageUrl} className="w-full h-full object-cover" /></div><input type="file" hidden ref={editFileInputRef} accept="image/*" onChange={(e) => handleImageUpload(e, true)} /><button type="submit" className="w-full bg-emerald-600 text-white font-black py-7 rounded-[2rem] shadow-xl">Apply Changes</button></form></div>
        </div>
      )}
    </div>
  );
};

export default FarmerDashboard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Product, Order } from '../types';
import { calculateDistance } from '../utils/geo';
import { db } from '../services/db';
import { suggestUsage } from '../services/geminiService';
import MessagesView from './MessagesView';

const StarRating: React.FC<{ initialValue?: number, onRate?: (val: number) => void, interactive?: boolean }> = ({ initialValue = 0, onRate, interactive = false }) => {
  const [hover, setHover] = useState(0);
  const stars = [1, 2, 3, 4, 5];
  return (
    <div className="flex items-center gap-1">
      {stars.map((star) => (
        <button key={star} type="button" disabled={!interactive} className={`${interactive ? 'cursor-pointer hover:scale-125' : 'cursor-default'} transition-all`} onClick={() => interactive && onRate && onRate(star)} onMouseEnter={() => interactive && setHover(star)} onMouseLeave={() => interactive && setHover(0)}>
          <svg className={`w-5 h-5 ${star <= (hover || initialValue) ? 'text-amber-500 fill-current' : 'text-slate-200 fill-current'}`} viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
        </button>
      ))}
    </div>
  );
};

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const BuyerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [view, setView] = useState<'marketplace' | 'store' | 'orders' | 'messages'>('marketplace');
  const [farmers, setFarmers] = useState<User[]>([]);
  const [selectedFarmer, setSelectedFarmer] = useState<User | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [buyerOrders, setBuyerOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'all' | 'favorites'>('all');
  const [orderQuantities, setOrderQuantities] = useState<Record<string, number>>({});
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const selectedFarmerIdRef = useRef<string | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const allFarmers = await db.users.find({ role: 'farmer' });
    setFarmers(allFarmers);
    const orders = await db.orders.find({ buyerId: user.id });
    setBuyerOrders(orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    if (selectedFarmerIdRef.current) {
      const prods = await db.products.find({ farmerId: selectedFarmerIdRef.current });
      setStoreProducts(prods);
    }
  }, [user.id]);

  useEffect(() => {
    loadData();
    const intv = setInterval(loadData, 5000);
    return () => clearInterval(intv);
  }, [loadData]);

  const nearbyFarmers = farmers.filter(f => {
    if (!user.location || !f.location) return true;
    const dist = calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng);
    return dist <= (f.deliveryDistance || 20);
  });

  const handleBuy = async (p: Product) => {
    if (!selectedFarmer) return;
    const qty = orderQuantities[p.id] || 1;
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      productId: p.id,
      productName: p.name,
      farmerId: selectedFarmer.id,
      farmName: selectedFarmer.name,
      buyerId: user.id,
      buyerName: user.name,
      quantity: qty,
      totalPrice: p.price * qty,
      status: 'pending',
      date: new Date().toISOString()
    };
    await db.orders.insertOne(newOrder);
    await db.users.updateOne(selectedFarmer.id, { currentQuantity: (selectedFarmer.currentQuantity || 0) + qty });
    showToast("Order placed!");
    setView('orders');
  };

  return (
    <div className="max-w-7xl mx-auto p-8 md:p-16 animate-in fade-in duration-700">
      {toast && <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-xs uppercase tracking-widest`}>{toast.message}</div>}

      <div className="flex flex-col md:flex-row items-center justify-between mb-16 gap-8">
        <div className="flex glass p-2 rounded-[2.8rem] shadow-xl overflow-x-auto max-w-full">
          {['marketplace', 'orders', 'messages'].map(v => (
            <button key={v} onClick={() => setView(v as any)} className={`px-12 py-5 rounded-[2.2rem] font-black text-xs uppercase tracking-widest transition-all ${view === v ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200' : 'text-slate-400 hover:text-emerald-600'}`}>{v}</button>
          ))}
        </div>
      </div>

      {view === 'marketplace' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-14">
          {nearbyFarmers.map(f => {
            const dist = user.location && f.location ? calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng) : 0;
            const progress = ((f.currentQuantity || 0) / (f.thresholdQuantity || 100)) * 100;
            return (
              <div key={f.id} className="bg-white rounded-[4rem] p-12 shadow-sm border border-slate-100 hover:shadow-2xl transition-all group relative overflow-hidden">
                <div className="flex justify-between items-start mb-10">
                  <div className="w-20 h-20 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center text-emerald-600 shadow-inner"><svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3"></path></svg></div>
                  <div className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest ${dist < 10 ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>{dist < 10 ? 'SAME AREA' : `${dist} KM`}</div>
                </div>
                <h3 className="text-3xl font-serif text-slate-900 mb-2 truncate">{f.name}</h3>
                <div className="mb-8"><StarRating initialValue={Math.round(f.rating || 0)} /></div>
                <div className="bg-slate-50 p-6 rounded-[2.5rem] mb-10 border border-slate-100">
                   <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3"><span>Batch Readiness</span><span>{Math.round(progress)}%</span></div>
                   <div className="w-full bg-slate-200 h-3 rounded-full overflow-hidden"><div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: `${Math.min(100, progress)}%` }}></div></div>
                </div>
                <button onClick={() => { setSelectedFarmer(f); selectedFarmerIdRef.current = f.id; setView('store'); }} className="w-full bg-slate-900 text-white font-black py-7 rounded-[2rem] hover:bg-emerald-600 transition-all text-lg uppercase tracking-widest shadow-xl">Browse Store</button>
              </div>
            );
          })}
        </div>
      )}

      {view === 'store' && selectedFarmer && (
        <div className="space-y-12 animate-in slide-in-from-bottom-20 duration-700">
           <button onClick={() => setView('marketplace')} className="glass px-8 py-4 rounded-2xl font-black text-xs uppercase text-slate-400 hover:text-emerald-600">Back to Market</button>
           <h2 className="text-6xl font-serif text-slate-900 tracking-tight">{selectedFarmer.name}</h2>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
              {storeProducts.map(p => (
                <div key={p.id} className="bg-white rounded-[4rem] overflow-hidden border border-slate-100 shadow-lg group">
                   <div className="h-72 overflow-hidden"><img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={p.name} /></div>
                   <div className="p-10"><h3 className="text-3xl font-serif text-slate-900 mb-3">{p.name}</h3><div className="text-emerald-600 font-black text-2xl mb-8">₹{p.price}</div><button onClick={() => handleBuy(p)} className="w-full bg-slate-900 text-white font-black py-6 rounded-[2rem] hover:bg-emerald-600 transition-all uppercase tracking-widest shadow-xl">Add to Basket</button></div>
                </div>
              ))}
           </div>
        </div>
      )}

      {view === 'orders' && (
        <div className="bg-white rounded-[4rem] shadow-2xl border border-slate-100 overflow-hidden">
           <div className="p-16 bg-emerald-50/20 text-center"><h2 className="text-5xl font-serif text-slate-900">Track Harvest</h2><p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mt-5">Direct Supply Chain</p></div>
           <table className="w-full text-left">
              <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest"><tr><th className="px-16 py-8">Produce</th><th className="px-16 py-8">Status</th><th className="px-16 py-8 text-right">Settlement</th></tr></thead>
              <tbody className="divide-y divide-slate-100">{buyerOrders.map(o => (<tr key={o.id} className="hover:bg-slate-50/50"><td className="px-16 py-12"><div><p className="font-serif text-slate-900 text-3xl">{o.productName}</p><p className="text-emerald-600 font-black text-[9px] uppercase tracking-widest mt-2">{o.farmName}</p></div></td><td className="px-16 py-12"><div className={`inline-flex px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${o.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>{o.status}</div></td><td className="px-16 py-12 text-right font-black text-2xl text-slate-900">₹{o.totalPrice}</td></tr>))}</tbody>
           </table>
        </div>
      )}

      {view === 'messages' && <MessagesView currentUser={user} />}
    </div>
  );
};

export default BuyerDashboard;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import { db } from '../services/db';
import MessagesView from './MessagesView';

// Define missing categories and inputClasses for reuse
const categories = ['Vegetables', 'Fruits', 'Grains', 'Spices', 'Dairy', 'Others'];
const inputClasses = "w-full px-6 py-4 rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 outline-none transition-all font-bold";

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'messages' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    setProducts([...userProducts].sort((a, b) => a.name.localeCompare(b.name)));
    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleResetBatch = async () => {
    await db.users.updateOne(user.id, { currentQuantity: 0 });
    onUpdateUser({ currentQuantity: 0 });
    showToast("Batch progress reset for new harvest.");
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    await db.orders.updateOne(orderId, { status: newStatus });
    showToast(`Order marked as ${newStatus}`);
    await loadData();
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) setEditingProduct({ ...editingProduct, imageUrl: base64String });
        else setNewProduct({ ...newProduct, imageUrl: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.imageUrl) { showToast("Upload a photo.", "error"); return; }
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Fresh harvest.",
      imageUrl: newProduct.imageUrl
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      await db.products.updateOne(editingProduct.id, editingProduct);
      setEditingProduct(null);
      showToast("Updated!");
      await loadData();
    }
  };

  const handleMagicDescription = async () => {
    if (!newProduct.name) return;
    setIsGenerating(true);
    const desc = await generateProductDescription(newProduct.name, newProduct.category);
    setNewProduct({ ...newProduct, description: desc });
    setIsGenerating(false);
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    const price = await suggestPrice(newProduct.name);
    setNewProduct({ ...newProduct, price });
    setIsPricing(false);
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);
  const pendingRequests = orders.filter(o => o.status === 'pending').length;

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-73px)]">
      {toast && (
        <div className={`fixed top-24 right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-xs uppercase tracking-widest`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar */}
      <nav className="w-full md:w-80 glass border-r border-slate-200 p-8 space-y-4 flex-shrink-0 z-10 overflow-y-auto">
        <div className="pb-6 px-4"><h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Control Room</h3></div>
        {[
          { id: 'overview', label: 'Dashboard', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z' },
          { id: 'products', label: 'My Inventory', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
          { id: 'add-product', label: 'Add Harvest', icon: 'M12 4v16m8-8H4' },
          { id: 'orders', label: 'Orders', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2' },
          { id: 'messages', label: 'Messages', icon: 'M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72' },
          { id: 'settings', label: 'Logistics', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066' }
        ].map(item => (
          <button 
            key={item.id} onClick={() => setActiveTab(item.id as any)}
            className={`w-full flex items-center gap-5 px-7 py-5 rounded-[1.8rem] transition-all font-black text-xs uppercase tracking-widest border-2 ${activeTab === item.id ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200 scale-[1.02]' : 'bg-white border-transparent text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path></svg>
            {item.label}
          </button>
        ))}
      </nav>

      {/* Main Content */}
      <div className="flex-1 p-8 md:p-14 max-w-7xl mx-auto w-full overflow-y-auto">

        {activeTab === 'overview' && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="bg-white p-12 rounded-[4.5rem] shadow-xl border border-slate-100 flex flex-col lg:flex-row items-center justify-between gap-12 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-8 opacity-5"><svg className="w-48 h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path></svg></div>
               <div className="space-y-6 flex-1 text-center lg:text-left z-10">
                  <h2 className="text-5xl font-serif text-slate-900 tracking-tight leading-tight">Batch Readiness</h2>
                  <p className="text-slate-500 text-lg font-medium max-w-lg leading-relaxed">Collect buyer interest to trigger direct fulfillment. Reset once your current batch is delivered.</p>
                  <div className="flex flex-wrap gap-4 justify-center lg:justify-start">
                    <div className="bg-emerald-600 text-white px-10 py-5 rounded-[2rem] font-black shadow-2xl shadow-emerald-200 text-2xl tracking-tighter">
                      {currentProgress} / {threshold} KG
                    </div>
                    {progressPercent >= 100 && (
                      <button onClick={handleResetBatch} className="bg-slate-900 text-white px-8 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-emerald-700 transition-all">Start New Batch</button>
                    )}
                  </div>
               </div>
               <div className="relative w-80 h-80 flex items-center justify-center flex-shrink-0 bg-white rounded-full p-10 shadow-2xl border-4 border-slate-50">
                  <svg className="w-full h-full -rotate-90 overflow-visible" viewBox="0 0 320 320">
                    <circle cx="160" cy="160" r="130" className="stroke-slate-100 fill-none" strokeWidth="28" />
                    <circle cx="160" cy="160" r="130" className="stroke-emerald-500 fill-none transition-all duration-1000" strokeWidth="28" strokeDasharray={`${progressPercent * 8.16} 816`} strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-6xl font-black tracking-tighter text-slate-800">{Math.round(progressPercent)}%</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">GOAL</span>
                  </div>
               </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
               <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between">
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-6">Farm Rating</p>
