        {activeTab === 'messages' && <MessagesView currentUser={user} />}
        {activeTab === 'settings' && (
           <div className="max-w-4xl mx-auto bg-white p-14 rounded-[4rem] shadow-xl border border-slate-200"><h2 className="text-4xl font-serif text-slate-900 mb-8">Logistics Thresholds</h2><form className="space-y-10" onSubmit={(e) => { e.preventDefault(); onUpdateUser({ deliveryDistance: user.deliveryDistance, thresholdQuantity: user.thresholdQuantity }); showToast("Updated!"); }}><div className="space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Service Radius (KM)</label><input type="number" className={inputClasses} value={user.deliveryDistance} onChange={e => onUpdateUser({ deliveryDistance: parseInt(e.target.value) })} /></div><div className="space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Harvest Threshold (KG)</label><input type="number" className={inputClasses} value={user.thresholdQuantity} onChange={e => onUpdateUser({ thresholdQuantity: parseInt(e.target.value) })} /></div><button type="submit" className="w-full bg-slate-900 text-white font-black py-6 rounded-[2rem] hover:bg-emerald-600 transition-all uppercase tracking-widest">Update Policy</button></form></div>
        )}
