import React, { useState, useEffect, useRef } from 'react';
import { User, ChatMessage } from '../types';
import { db } from '../services/db';

interface Props {
  currentUser: User;
}

const MessagesView: React.FC<Props> = ({ currentUser }) => {
  const [conversations, setConversations] = useState<{user: User, lastMsg?: ChatMessage}[]>([]);
  const [selectedRecipient, setSelectedRecipient] = useState<User | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const [showListOnMobile, setShowListOnMobile] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const loadConversations = async () => {
      const allUsers = await db.users.find();
      const others = allUsers.filter(u => u.id !== currentUser.id && u.role !== currentUser.role);

      const convosWithLastMsg = others.map(u => {
        const chatKey = `chat_${[currentUser.id, u.id].sort().join('_')}`;
        const saved = localStorage.getItem(chatKey);
        const parsed = saved ? JSON.parse(saved) : [];
        return {
          user: u,
          lastMsg: parsed.length > 0 ? parsed[parsed.length - 1] : undefined
        };
      });

      setConversations(convosWithLastMsg.sort((a, b) => {
        if (!a.lastMsg) return 1;
        if (!b.lastMsg) return -1;
        return new Date(b.lastMsg.timestamp).getTime() - new Date(a.lastMsg.timestamp).getTime();
      }));
    };
    loadConversations();
  }, [currentUser.id, currentUser.role]);

  useEffect(() => {
    if (!selectedRecipient) return;
    const chatKey = `chat_${[currentUser.id, selectedRecipient.id].sort().join('_')}`;

    const loadMsgs = () => {
      const saved = localStorage.getItem(chatKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.length !== messages.length) setMessages(parsed);
      } else {
        setMessages([]);
      }
    };

    loadMsgs();
    const interval = setInterval(loadMsgs, 2000);
    return () => clearInterval(interval);
  }, [selectedRecipient, currentUser.id, messages.length]);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || !selectedRecipient) return;

    const newMessage: ChatMessage = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      receiverId: selectedRecipient.id,
      text: inputText,
      timestamp: new Date().toISOString()
    };

    const updated = [...messages, newMessage];
    const chatKey = `chat_${[currentUser.id, selectedRecipient.id].sort().join('_')}`;
    localStorage.setItem(chatKey, JSON.stringify(updated));
    setMessages(updated);
    setInputText('');
  };

