import React, { useState } from 'react';
import { User, Role } from '../types';
import { db } from '../services/db';

interface LoginProps {
  onLogin: (user: User) => void;
}

const LoginView: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [verificationCode, setVerificationCode] = useState('');
  const [role, setRole] = useState<Role>('buyer');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');

  const inputClasses = "w-full px-5 py-3 md:px-6 md:py-4 rounded-xl md:rounded-2xl border-2 border-slate-300 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-medium text-base md:text-lg";

  const handleStartRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    const existing = await db.users.findOne({ email: formData.email });
    if (existing) {
      setError('An account with this email already exists.');
      return;
    }

    setIsSendingSms(true);
    setTimeout(() => {
      setIsSendingSms(false);
      setIsVerifying(true);
    }, 1500);
  };

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (verificationCode === '123456') {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        name: formData.name,
        email: formData.email.toLowerCase().trim(),
        phone: formData.phone,
        password: formData.password,
        role: role,
        favorites: [],
        rating: role === 'farmer' ? 0.0 : undefined,
        deliveryDistance: role === 'farmer' ? 15 : undefined,
        thresholdQuantity: role === 'farmer' ? 50 : undefined,
        currentQuantity: role === 'farmer' ? 0 : undefined
      };

      await db.users.insertOne(newUser);
      onLogin(newUser);
    } else {
      setError('Invalid code. Use 123456.');
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const user = await db.users.findOne({ 
      email: formData.email.toLowerCase().trim(), 
      password: formData.password 
    });

    if (user) {
      onLogin(user);
    } else {
      setError('Invalid credentials.');
    }
  };

  if (isSendingSms) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-6">
        <div className="text-center space-y-6">
          <div className="w-12 h-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mx-auto"></div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">VERIFYING SECURITY...</p>
        </div>
      </div>
    );
  }

  if (isVerifying) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[2rem] shadow-2xl p-8 space-y-8 border border-slate-100">
          <div className="text-center">
            <h2 className="text-2xl font-serif text-slate-900 mb-2">Security Code</h2>
            <p className="text-slate-500 text-sm font-medium leading-relaxed">Sent to <span className="text-emerald-600 font-bold">{formData.phone}</span></p>
          </div>
          <form onSubmit={handleVerify} className="space-y-6">
            <input 
              type="text" maxLength={6} required
              className="w-full text-center text-3xl tracking-[0.2em] font-black py-5 rounded-2xl border-2 border-slate-200 bg-slate-50 focus:border-emerald-500 outline-none"
              placeholder="000000"
              value={verificationCode}
              onChange={(e) => setVerificationCode(e.target.value)}
            />
            <button className="w-full bg-emerald-600 text-white font-bold py-4 rounded-xl shadow-xl hover:bg-emerald-700 transition-all text-base uppercase tracking-widest">
              Confirm
            </button>
          </form>
          <div className="text-center">
             <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">DEMO CODE: 123456</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="max-w-lg w-full bg-white rounded-[2.5rem] md:rounded-[3.5rem] shadow-2xl p-8 md:p-12 space-y-8 md:space-y-10 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1.5 bg-emerald-500"></div>

        <div className="text-center">
          <div className="mx-auto w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center text-white mb-4 shadow-xl rotate-3">
             <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h2 className="text-3xl font-serif text-slate-900 tracking-tight">AgroFlow</h2>
          <p className="text-slate-400 font-bold uppercase text-[8px] tracking-[0.3em] mt-2">DIRECT FARM ACCESS</p>
        </div>

        {isRegistering && (
          <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
            <button onClick={() => setRole('buyer')} className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all ${role === 'buyer' ? 'bg-white shadow text-emerald-600' : 'text-slate-400'}`}>BUYER</button>
            <button onClick={() => setRole('farmer')} className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all ${role === 'farmer' ? 'bg-white shadow text-emerald-600' : 'text-slate-400'}`}>FARMER</button>
          </div>
        )}

        <form onSubmit={isRegistering ? handleStartRegistration : handleLogin} className="space-y-4 md:space-y-5">
          {error && <div className="bg-red-50 text-red-600 p-3 rounded-xl text-[10px] font-black border border-red-100">{error}</div>}

          {isRegistering && (
            <input type="text" required className={inputClasses} placeholder="Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          )}
          {isRegistering && (
            <input type="tel" required className={inputClasses} placeholder="Mobile" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
          )}
          <input type="email" required className={inputClasses} placeholder="Email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
          <input type="password" required className={inputClasses} placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />

          {isRegistering && (
            <input type="password" required className={inputClasses} placeholder="Confirm" value={formData.confirmPassword} onChange={e => setFormData({...formData, confirmPassword: e.target.value})} />
          )}

          <button type="submit" className="w-full bg-emerald-600 text-white font-black py-4 md:py-5 rounded-xl md:rounded-2xl shadow-xl hover:bg-emerald-700 transition-all text-lg tracking-tight active:scale-95 shadow-emerald-200/40">
            {isRegistering ? 'Join Network' : 'Enter'}
          </button>
        </form>

        <button onClick={() => { setIsRegistering(!isRegistering); setError(''); }} className="w-full text-center text-[9px] font-black text-slate-400 hover:text-emerald-600 uppercase tracking-widest">
          {isRegistering ? 'Have an account? Login' : 'No account? Join Us'}
        </button>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import { db } from '../services/db';
import MessagesView from './MessagesView';

const categories = ['Vegetables', 'Fruits', 'Grains', 'Spices', 'Dairy', 'Others'];
const inputClasses = "w-full px-5 py-3 md:px-6 md:py-4 rounded-xl md:rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 outline-none transition-all font-bold";

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'messages' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    setProducts([...userProducts].sort((a, b) => a.name.localeCompare(b.name)));
    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleResetBatch = async () => {
    await db.users.updateOne(user.id, { currentQuantity: 0 });
    onUpdateUser({ currentQuantity: 0 });
    showToast("Batch progress reset for new harvest.");
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    await db.orders.updateOne(orderId, { status: newStatus });
    showToast(`Order marked as ${newStatus}`);
    await loadData();
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) setEditingProduct({ ...editingProduct, imageUrl: base64String });
        else setNewProduct({ ...newProduct, imageUrl: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.imageUrl) { showToast("Upload a photo.", "error"); return; }
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Fresh harvest.",
      imageUrl: newProduct.imageUrl
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      await db.products.updateOne(editingProduct.id, editingProduct);
      setEditingProduct(null);
      showToast("Updated successfully!");
      await loadData();
    }
  };

  const handleDeleteProduct = async (id: string) => {
    if (window.confirm("Are you sure you want to remove this listing?")) {
      await db.products.deleteOne(id);
      showToast("Listing removed", "error");
      await loadData();
    }
  };

  const handleMagicDescription = async () => {
    if (!newProduct.name) return;
    setIsGenerating(true);
    const desc = await generateProductDescription(newProduct.name, newProduct.category);
    setNewProduct({ ...newProduct, description: desc });
    setIsGenerating(false);
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    const price = await suggestPrice(newProduct.name);
    setNewProduct({ ...newProduct, price });
    setIsPricing(false);
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);
  const pendingRequests = orders.filter(o => o.status === 'pending').length;

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-65px)] bg-slate-50/30">
      {toast && (
        <div className={`fixed top-20 right-4 left-4 md:left-auto md:right-10 z-[1000] px-6 md:px-8 py-4 md:py-5 rounded-2xl shadow-2xl animate-in slide-in-from-top-10 md:slide-in-from-right-10 border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-[10px] md:text-xs uppercase tracking-widest text-center md:text-left`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar Navigation */}
      <nav className="w-full md:w-72 lg:w-80 glass border-b md:border-b-0 md:border-r border-slate-200 p-4 md:p-8 flex md:flex-col gap-2 md:gap-4 overflow-x-auto md:overflow-y-auto z-40 sticky top-0 md:h-[calc(100vh-73px)] no-scrollbar">
        <div className="hidden md:block pb-6 px-4"><h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">CONTROL ROOM</h3></div>
        {[
          { id: 'overview', label: 'Dashboard', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z' },
          { id: 'products', label: 'Inventory', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
          { id: 'add-product', label: 'Add Harvest', icon: 'M12 4v16m8-8H4' },
          { id: 'orders', label: 'Orders', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2' },
          { id: 'messages', label: 'Chats', icon: 'M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72' },
          { id: 'settings', label: 'Rules', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066' }
        ].map(item => (
          <button 
            key={item.id} onClick={() => setActiveTab(item.id as any)}
            className={`flex-shrink-0 flex items-center gap-3 md:gap-5 px-5 md:px-7 py-3 md:py-5 rounded-xl md:rounded-[1.8rem] transition-all font-black text-[10px] md:text-xs uppercase tracking-widest border-2 ${activeTab === item.id ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200' : 'bg-white border-transparent text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
          >
            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path></svg>
            <span className="md:inline">{item.label}</span>
          </button>
        ))}
      </nav>

      {/* Main Content */}
      <div className="flex-1 p-4 md:p-14 max-w-7xl mx-auto w-full overflow-y-auto">

        {activeTab === 'overview' && (
          <div className="space-y-6 md:space-y-12 animate-in fade-in duration-500">
             {/* Goal Progress Header */}
             <div className="bg-white p-6 md:p-12 rounded-[2rem] md:rounded-[4.5rem] shadow-xl border border-slate-100 flex flex-col lg:flex-row items-center justify-between gap-8 md:gap-12 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-4 md:p-8 opacity-5 hidden sm:block"><svg className="w-32 h-32 md:w-48 md:h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path></svg></div>
               <div className="space-y-4 md:space-y-6 flex-1 text-center lg:text-left z-10">
                  <h2 className="text-3xl md:text-5xl font-serif text-slate-900 tracking-tight leading-tight">Batch Readiness</h2>
                  <p className="text-slate-500 text-sm md:text-lg font-medium max-w-lg leading-relaxed">Reach your fulfillment goal to trigger direct delivery.</p>
                  <div className="flex flex-wrap gap-3 md:gap-4 justify-center lg:justify-start">
                    <div className="bg-emerald-600 text-white px-6 md:px-10 py-3 md:py-5 rounded-2xl md:rounded-[2rem] font-black shadow-2xl shadow-emerald-200 text-lg md:text-2xl tracking-tighter">
                      {currentProgress} / {threshold} KG
                    </div>
                    {progressPercent >= 100 && (
                      <button onClick={handleResetBatch} className="bg-slate-900 text-white px-6 py-3 rounded-2xl md:rounded-[2rem] font-black text-[10px] md:text-xs uppercase tracking-widest shadow-xl hover:bg-emerald-700 transition-all">Reset Batch</button>
                    )}
                  </div>
               </div>
               <div className="relative w-48 h-48 md:w-80 md:h-80 flex items-center justify-center flex-shrink-0 bg-white rounded-full p-4 md:p-10 shadow-2xl border-4 border-slate-50">
                  <svg className="w-full h-full -rotate-90 overflow-visible" viewBox="0 0 320 320">
                    <circle cx="160" cy="160" r="130" className="stroke-slate-100 fill-none" strokeWidth="28" />
                    <circle cx="160" cy="160" r="130" className="stroke-emerald-500 fill-none transition-all duration-1000" strokeWidth="28" strokeDasharray={`${progressPercent * 8.16} 816`} strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-3xl md:text-6xl font-black tracking-tighter text-slate-800">{Math.round(progressPercent)}%</span>
                    <span className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1 md:mt-2">GOAL</span>
                  </div>
               </div>
             </div>

             <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-8">
               {[
                 { label: 'Rating', val: user.rating?.toFixed(1) || '0.0', color: 'text-amber-500' },
                 { label: 'Requests', val: pendingRequests, color: 'text-blue-600' },
                 { label: 'Listings', val: products.length, color: 'text-slate-900' },
                 { label: 'Sales', val: orders.filter(o => o.status === 'delivered').length, color: 'text-emerald-600' }
               ].map((stat, i) => (
                 <div key={i} className="bg-white p-6 md:p-10 rounded-2xl md:rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                    <p className="text-slate-400 font-black uppercase text-[8px] md:text-[10px] tracking-widest mb-4 md:mb-6">{stat.label}</p>
                    <p className={`text-2xl md:text-5xl font-black ${stat.color} tracking-tighter`}>{stat.val}</p>
                 </div>
               ))}
             </div>
          </div>
        )}

        {activeTab === 'products' && (
          <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
             <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4 px-2">
                <div><h2 className="text-3xl md:text-4xl font-serif text-slate-900 tracking-tight">Farm Inventory</h2><p className="text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-widest mt-2">Active Listings</p></div>
                <button onClick={() => setActiveTab('add-product')} className="w-full sm:w-auto bg-slate-900 text-white font-black px-8 md:px-10 py-4 md:py-5 rounded-2xl md:rounded-[2rem] hover:bg-emerald-600 transition-all text-[10px] md:text-xs uppercase tracking-widest shadow-xl">Add New Harvest</button>
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-10">
                {products.length === 0 ? (
                  <div className="col-span-full py-20 text-center opacity-40 italic font-serif text-xl">No products listed yet.</div>
                ) : (
                  products.map(p => (
                    <div key={p.id} className="bg-white rounded-3xl md:rounded-[4rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group overflow-hidden flex flex-col">
                       <div className="flex flex-col md:flex-row p-6 md:p-10 gap-6 md:gap-10">
                          <div className="w-full md:w-44 lg:w-56 h-48 md:h-44 lg:h-56 rounded-2xl md:rounded-[3rem] overflow-hidden bg-slate-50 flex-shrink-0 relative shadow-inner">
                            <img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={p.name} />
                          </div>
                          <div className="flex-1">
                             <div className="flex justify-between items-start mb-2 md:mb-4">
                                <h3 className="text-2xl md:text-3xl font-serif text-slate-900 tracking-tight">{p.name}</h3>
                                <div className="text-emerald-600 font-black text-xl md:text-2xl tracking-tighter">₹{p.price}</div>
                             </div>
                             <p className="text-slate-500 font-medium text-xs md:text-sm italic opacity-90 line-clamp-2">"{p.description}"</p>
                          </div>
                       </div>
                       <div className="bg-slate-50/50 p-4 md:p-6 flex gap-4">
                          <button onClick={() => setEditingProduct(p)} className="flex-1 bg-white border-2 border-slate-200 text-slate-800 font-black text-[10px] md:text-[11px] uppercase tracking-widest hover:bg-emerald-600 hover:text-white py-4 md:py-5 rounded-xl md:rounded-[1.8rem] transition-all shadow-sm">Edit</button>
                          <button onClick={() => handleDeleteProduct(p.id)} className="px-6 md:px-8 bg-white border-2 border-red-100 text-red-500 font-black text-[10px] md:text-[11px] uppercase tracking-widest hover:bg-red-50 py-4 md:py-5 rounded-xl md:rounded-[1.8rem] transition-all">Remove</button>
                       </div>
                    </div>
                  ))
                )}
             </div>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="animate-in fade-in duration-500">
             <div className="bg-white rounded-2xl md:rounded-[4rem] shadow-2xl border border-slate-100 overflow-hidden">
                <div className="p-6 md:p-10 border-b border-slate-100 bg-emerald-50/20 flex flex-col sm:flex-row justify-between items-center gap-4">
                  <h2 className="text-2xl md:text-3xl font-serif text-slate-900">Orders List</h2>
                  <div className="bg-emerald-600 text-white px-5 py-2 rounded-full font-black text-[9px] md:text-[10px] uppercase tracking-widest">{pendingRequests} Pending</div>
                </div>
                <div className="overflow-x-auto">
                   <table className="w-full text-left">
                      <thead className="bg-slate-50 text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest"><tr className="border-b border-slate-100"><th className="px-6 md:px-10 py-4 md:py-6">Buyer</th><th className="px-6 md:px-10 py-4 md:py-6">Status</th><th className="px-6 md:px-10 py-4 md:py-6">Action</th></tr></thead>
                      <tbody className="divide-y divide-slate-100">
                         {orders.length === 0 ? (
                           <tr><td colSpan={3} className="p-10 text-center text-slate-400 italic">No orders yet.</td></tr>
                         ) : (
                           orders.map(o => (
                             <tr key={o.id} className="hover:bg-slate-50/50 transition-all text-xs md:text-sm">
                                <td className="px-6 md:px-10 py-6 md:py-8"><p className="font-black text-slate-900">{o.buyerName}</p><p className="text-[10px] text-emerald-600 font-bold">{o.productName} ({o.quantity}kg)</p></td>
                                <td className="px-6 md:px-10 py-6 md:py-8"><div className={`inline-flex px-3 py-1 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest ${o.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>{o.status}</div></td>
                                <td className="px-6 md:px-10 py-6 md:py-8">
                                   <div className="flex gap-2">
                                      {o.status === 'pending' && <button onClick={() => handleUpdateOrderStatus(o.id, 'confirmed')} className="bg-emerald-600 text-white p-2 rounded-lg md:rounded-xl text-[8px] md:text-[9px] font-black uppercase tracking-widest shadow-lg">Confirm</button>}
                                      {o.status === 'confirmed' && <button onClick={() => handleUpdateOrderStatus(o.id, 'delivered')} className="bg-blue-600 text-white p-2 rounded-lg md:rounded-xl text-[8px] md:text-[9px] font-black uppercase tracking-widest shadow-lg">Ship</button>}
                                      <button onClick={() => setActiveTab('messages')} className="bg-slate-900 text-white p-2 rounded-lg md:rounded-xl"><svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72"></path></svg></button>
                                   </div>
                                </td>
                             </tr>
                           ))
                         )}
                      </tbody>
                   </table>
                </div>
             </div>
          </div>
        )}

        {activeTab === 'add-product' && (
           <div className="bg-white p-6 md:p-12 lg:p-16 rounded-3xl md:rounded-[4rem] shadow-2xl border border-slate-100 animate-in slide-in-from-bottom-10 duration-700 max-w-4xl mx-auto">
              <h2 className="text-3xl md:text-5xl font-serif text-slate-900 tracking-tight mb-8">Harvest Studio</h2>
              <form onSubmit={handleAddProduct} className="space-y-6 md:space-y-8">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8">
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Name</label><input type="text" required className={inputClasses} placeholder="Organic Kashmiri Apple" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Category</label><select className={inputClasses} value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>{categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}</select></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Price (₹)</label><div className="relative"><input type="number" required className={inputClasses} value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: e.target.value})} /><button type="button" onClick={handleAISuggestPrice} className="absolute right-4 top-1/2 -translate-y-1/2 text-emerald-600 font-black text-[10px] uppercase">✨ AI</button></div></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Stock (KG)</label><input type="number" required className={inputClasses} value={newProduct.stock} onChange={e => setNewProduct({...newProduct, stock: e.target.value})} /></div>
                 </div>
                 <div className="space-y-2"><div className="flex justify-between items-center ml-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Description</label><button type="button" onClick={handleMagicDescription} className="text-emerald-600 font-black text-[10px] uppercase">✨ Magic Write</button></div><textarea className={`${inputClasses} min-h-[100px] md:min-h-[120px]`} value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})} /></div>
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Photo</label><div onClick={() => fileInputRef.current?.click()} className="h-48 md:h-64 bg-slate-50 border-4 border-dashed border-slate-200 rounded-[2rem] md:rounded-[3rem] overflow-hidden cursor-pointer flex items-center justify-center hover:border-emerald-400 transition-all">{newProduct.imageUrl ? <img src={newProduct.imageUrl} className="w-full h-full object-cover" /> : <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Click to upload</p>}</div><input type="file" hidden ref={fileInputRef} accept="image/*" onChange={(e) => handleImageUpload(e)} /></div>
                 <button type="submit" className="w-full bg-slate-900 text-white font-black py-6 md:py-8 rounded-2xl md:rounded-[2.5rem] hover:bg-emerald-600 transition-all text-lg md:text-xl uppercase tracking-widest shadow-2xl">Publish Harvest</button>
              </form>
           </div>
        )}

        {activeTab === 'messages' && <MessagesView currentUser={user} />}

        {activeTab === 'settings' && (
           <div className="max-w-4xl mx-auto bg-white p-8 md:p-14 rounded-3xl md:rounded-[4rem] shadow-xl border border-slate-200 animate-in fade-in"><h2 className="text-3xl md:text-4xl font-serif text-slate-900 mb-8">Settings</h2><form className="space-y-8" onSubmit={(e) => { e.preventDefault(); onUpdateUser({ deliveryDistance: user.deliveryDistance, thresholdQuantity: user.thresholdQuantity }); showToast("Settings Updated!"); }}><div className="space-y-2 md:space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Radius (KM)</label><input type="number" className={inputClasses} value={user.deliveryDistance} onChange={e => onUpdateUser({ deliveryDistance: parseInt(e.target.value) })} /></div><div className="space-y-2 md:space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Goal (KG)</label><input type="number" className={inputClasses} value={user.thresholdQuantity} onChange={e => onUpdateUser({ thresholdQuantity: parseInt(e.target.value) })} /></div><button type="submit" className="w-full bg-slate-900 text-white font-black py-4 md:py-6 rounded-2xl md:rounded-[2rem] hover:bg-emerald-600 transition-all uppercase tracking-widest">Save Rules</button></form></div>
        )}
      </div>

      {editingProduct && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[500] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-2xl rounded-3xl md:rounded-[4.5rem] p-8 md:p-14 shadow-2xl border-2 border-slate-100 overflow-y-auto max-h-[90vh]"><div className="flex justify-between items-center mb-8"><h2 className="text-3xl md:text-4xl font-serif text-slate-900">Edit Product</h2><button onClick={() => setEditingProduct(null)} className="text-slate-400 hover:text-red-500 font-black uppercase text-[10px] tracking-widest">Close</button></div><form onSubmit={handleUpdateProduct} className="space-y-6"><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Name</label><input type="text" className={inputClasses} value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} /></div><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Price (₹)</label><input type="number" className={inputClasses} value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} /></div><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Description</label><textarea className={inputClasses} value={editingProduct.description} onChange={e => setEditingProduct({...editingProduct, description: e.target.value})} /></div><div onClick={() => editFileInputRef.current?.click()} className="h-48 md:h-64 bg-slate-50 rounded-2xl md:rounded-[3rem] border-2 border-slate-100 overflow-hidden cursor-pointer"><img src={editingProduct.imageUrl} className="w-full h-full object-cover" /></div><input type="file" hidden ref={editFileInputRef} accept="image/*" onChange={(e) => handleImageUpload(e, true)} /><button type="submit" className="w-full bg-emerald-600 text-white font-black py-5 md:py-7 rounded-2xl md:rounded-[2rem] shadow-xl">Save Changes</button></form></div>
        </div>
      )}
    </div>
  );
};

export default FarmerDashboard;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import { db } from '../services/db';
import MessagesView from './MessagesView';

const categories = ['Vegetables', 'Fruits', 'Grains', 'Spices', 'Dairy', 'Others'];
const inputClasses = "w-full px-5 py-3 md:px-6 md:py-4 rounded-xl md:rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 outline-none transition-all font-bold";

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'messages' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  const [newProduct, setNewProduct] = useState({ 
    name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    setProducts([...userProducts].sort((a, b) => a.name.localeCompare(b.name)));
    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleResetBatch = async () => {
    await db.users.updateOne(user.id, { currentQuantity: 0 });
    onUpdateUser({ currentQuantity: 0 });
    showToast("Batch progress reset for new harvest.");
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    const order = await db.orders.findOne({ id: orderId });
    if (!order) return;

    await db.orders.updateOne(orderId, { status: newStatus });

    // If cancelled, deduct the quantity from the farmer's current batch progress
    if (newStatus === 'cancelled') {
      const currentQty = user.currentQuantity || 0;
      const newQty = Math.max(0, currentQty - order.quantity);
      await db.users.updateOne(user.id, { currentQuantity: newQty });
      onUpdateUser({ currentQuantity: newQty });
    }

    showToast(`Order ${newStatus}`);
    await loadData();
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) setEditingProduct({ ...editingProduct, imageUrl: base64String });
        else setNewProduct({ ...newProduct, imageUrl: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.imageUrl) { showToast("Upload a photo.", "error"); return; }
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Fresh harvest.",
      imageUrl: newProduct.imageUrl
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      await db.products.updateOne(editingProduct.id, {
        name: editingProduct.name,
        price: editingProduct.price,
        description: editingProduct.description,
        imageUrl: editingProduct.imageUrl,
        stock: editingProduct.stock,
        category: editingProduct.category
      });
      setEditingProduct(null);
      showToast("Updated successfully!");
      await loadData();
    }
  };

  const handleDeleteProduct = async (id: string) => {
    if (window.confirm("Are you sure you want to remove this product permanently?")) {
      try {
        await db.products.deleteOne(id);
        // Optimistically update local state for faster feel
        setProducts(prev => prev.filter(p => p.id !== id));
        showToast("Product removed", "error");
        // Reload to ensure sync
        await loadData();
      } catch (err) {
        showToast("Failed to remove product", "error");
      }
    }
  };

  const handleMagicDescription = async () => {
    if (!newProduct.name) return;
    setIsGenerating(true);
    const desc = await generateProductDescription(newProduct.name, newProduct.category);
    setNewProduct({ ...newProduct, description: desc });
    setIsGenerating(false);
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    const price = await suggestPrice(newProduct.name);
    setNewProduct({ ...newProduct, price });
    setIsPricing(false);
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);
  const pendingRequests = orders.filter(o => o.status === 'pending').length;

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-65px)] bg-slate-50/30">
      {toast && (
        <div className={`fixed top-20 right-4 left-4 md:left-auto md:right-10 z-[1000] px-6 md:px-8 py-4 md:py-5 rounded-2xl shadow-2xl animate-in slide-in-from-top-10 md:slide-in-from-right-10 border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-[10px] md:text-xs uppercase tracking-widest text-center md:text-left`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar Navigation */}
