            <button key={v} onClick={() => setView(v as any)} className={`px-6 md:px-12 py-3 md:py-5 rounded-xl md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === v ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200' : 'text-slate-400 hover:text-emerald-600'}`}>{v}</button>
          ))}
        </div>
      </div>

      {view === 'marketplace' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-14">
          {nearbyFarmers.map(f => {
            const dist = user.location && f.location ? calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng) : 0;
            const progress = ((f.currentQuantity || 0) / (f.thresholdQuantity || 100)) * 100;
            return (
              <div key={f.id} className="bg-white rounded-3xl md:rounded-[4rem] p-8 md:p-12 shadow-sm border border-slate-100 hover:shadow-2xl transition-all group relative overflow-hidden">
