        {activeTab === 'products' && (
          <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
             <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4 px-2">
                <div><h2 className="text-3xl md:text-4xl font-serif text-slate-900 tracking-tight">Farm Inventory</h2><p className="text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-widest mt-2">Active Listings</p></div>
                <button onClick={() => setActiveTab('add-product')} className="w-full sm:w-auto bg-slate-900 text-white font-black px-8 md:px-10 py-4 md:py-5 rounded-2xl md:rounded-[2rem] hover:bg-emerald-600 transition-all text-[10px] md:text-xs uppercase tracking-widest shadow-xl">Add New Harvest</button>
             </div>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-10">
                {products.length === 0 ? (
                  <div className="col-span-full py-20 text-center opacity-40 italic font-serif text-xl">No products listed yet. Start adding your harvest.</div>
                ) : (
                  products.map(p => (
                    <div key={p.id} className="bg-white rounded-3xl md:rounded-[4rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group overflow-hidden flex flex-col">
                       <div className="flex flex-col md:flex-row p-6 md:p-10 gap-6 md:gap-10">
                          <div className="w-full md:w-44 lg:w-56 h-48 md:h-44 lg:h-56 rounded-2xl md:rounded-[3rem] overflow-hidden bg-slate-50 flex-shrink-0 relative shadow-inner">
