                          <button onClick={() => setEditingProduct(p)} className="flex-1 bg-white border-2 border-slate-200 text-slate-800 font-black text-[10px] md:text-[11px] uppercase tracking-widest hover:bg-emerald-600 hover:text-white py-4 md:py-5 rounded-xl md:rounded-[1.8rem] transition-all shadow-sm">Edit Details</button>
