/**
 * A mock MongoDB-like client for the frontend.
 * Optimized for reliability and clear data separation.
 */
class Collection<T extends { id: string }> {
  private key: string;

  constructor(collectionName: string) {
    this.key = `agro_db_v2_${collectionName}`;
  }

  private getAll(): T[] {
    try {
      const data = localStorage.getItem(this.key);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Failed to read from localStorage", e);
      return [];
    }
  }

  private saveAll(data: T[]): void {
    try {
      localStorage.setItem(this.key, JSON.stringify(data));
    } catch (e) {
      console.error("Failed to write to localStorage", e);
    }
  }

  async find(query?: Partial<T>): Promise<T[]> {
    const all = this.getAll();
    if (!query) return all;
    return all.filter(item => {
      for (const key in query) {
        if (item[key as keyof T] !== query[key as keyof T]) return false;
      }
      return true;
    });
  }

  async findOne(query: Partial<T>): Promise<T | null> {
    const results = await this.find(query);
    return results.length > 0 ? results[0] : null;
  }

  async insertOne(item: T): Promise<T> {
    const all = this.getAll();
    // Ensure no ID collisions
    const filtered = all.filter(i => String(i.id) !== String(item.id));
    filtered.push(item);
    this.saveAll(filtered);
    return item;
  }

  async updateOne(id: string, updates: Partial<T>): Promise<void> {
    const all = this.getAll();
    const index = all.findIndex(i => String(i.id) === String(id));
    if (index !== -1) {
      all[index] = { ...all[index], ...updates };
      this.saveAll(all);
    }
  }

  async deleteOne(id: string): Promise<void> {
    const all = this.getAll();
    const filtered = all.filter(i => String(i.id) !== String(id));
    this.saveAll(filtered);
  }

  async deleteMany(query: Partial<T>): Promise<void> {
    const all = this.getAll();
    const filtered = all.filter(item => {
      for (const key in query) {
        if (item[key as keyof T] === query[key as keyof T]) return false;
      }
      return true;
    });
    this.saveAll(filtered);
  }
}

