                 <button type="submit" className="w-full bg-slate-900 text-white font-black py-6 md:py-8 rounded-2xl md:rounded-[2.5rem] hover:bg-emerald-600 transition-all text-lg md:text-xl uppercase tracking-widest shadow-2xl">Publish Harvest</button>
              </form>
           </div>
        )}

        {activeTab === 'messages' && <MessagesView currentUser={user} />}

        {activeTab === 'settings' && (
           <div className="max-w-4xl mx-auto bg-white p-8 md:p-14 rounded-3xl md:rounded-[4rem] shadow-xl border border-slate-200 animate-in fade-in"><h2 className="text-3xl md:text-4xl font-serif text-slate-900 mb-8">Settings</h2><form className="space-y-8" onSubmit={(e) => { e.preventDefault(); onUpdateUser({ deliveryDistance: user.deliveryDistance, thresholdQuantity: user.thresholdQuantity }); showToast("Settings Updated!"); }}><div className="space-y-2 md:space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Radius (KM)</label><input type="number" className={inputClasses} value={user.deliveryDistance} onChange={e => onUpdateUser({ deliveryDistance: parseInt(e.target.value) })} /></div><div className="space-y-2 md:space-y-4"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Goal (KG)</label><input type="number" className={inputClasses} value={user.thresholdQuantity} onChange={e => onUpdateUser({ thresholdQuantity: parseInt(e.target.value) })} /></div><button type="submit" className="w-full bg-slate-900 text-white font-black py-4 md:py-6 rounded-2xl md:rounded-[2rem] hover:bg-emerald-600 transition-all uppercase tracking-widest">Save Rules</button></form></div>
        )}
      </div>

      {editingProduct && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[500] flex items-center justify-center p-4">
           <div className="bg-white w-full max-w-2xl rounded-3xl md:rounded-[4.5rem] p-8 md:p-14 shadow-2xl border-2 border-slate-100 overflow-y-auto max-h-[90vh]"><div className="flex justify-between items-center mb-8"><h2 className="text-3xl md:text-4xl font-serif text-slate-900">Edit Product</h2><button onClick={() => setEditingProduct(null)} className="text-slate-400 hover:text-red-500 font-black uppercase text-[10px] tracking-widest">Close</button></div><form onSubmit={handleUpdateProduct} className="space-y-6"><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Name</label><input type="text" className={inputClasses} value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} /></div><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Category</label><select className={inputClasses} value={editingProduct.category} onChange={setEditingProduct as any}>{categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}</select></div><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Price (₹)</label><input type="number" className={inputClasses} value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} /></div><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Stock (KG)</label><input type="number" className={inputClasses} value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} /></div><div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Description</label><textarea className={inputClasses} value={editingProduct.description} onChange={e => setEditingProduct({...editingProduct, description: