itingProduct({...editingProduct, description: e.target.value})} /></div><div onClick={() => editFileInputRef.current?.click()} className="h-48 md:h-64 bg-slate-50 rounded-2xl md:rounded-[3rem] border-2 border-slate-100 overflow-hidden cursor-pointer"><img src={editingProduct.imageUrl} className="w-full h-full object-cover" /></div><input type="file" hidden ref={editFileInputRef} accept="image/*" onChange={(e) => handleImageUpload(e, true)} /><button type="submit" className="w-full bg-emerald-600 text-white font-black py-5 md:py-7 rounded-2xl md:rounded-[2rem] shadow-xl">Save Changes</button></form></div>
        </div>
      )}
    </div>
  );
};

