import React, { useState, useEffect, useCallback } from 'react';
import { User, Role, Product, Order, Location } from './types';
import LoginView from './views/Login';
import FarmerDashboard from './views/FarmerDashboard';
import BuyerDashboard from './views/BuyerDashboard';
import { getAddressFromCoords, getCoordsFromAddress } from './services/geminiService';
import { db } from './services/db';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userLocation, setUserLocation] = useState<Location | null>(null);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [showManualLoc, setShowManualLoc] = useState(false);
  const [manualAddress, setManualAddress] = useState('');

  const updateLocationState = async (loc: Location) => {
    setUserLocation(loc);
    if (currentUser) {
      await db.users.updateOne(currentUser.id, { location: loc });
      const updated = { ...currentUser, location: loc };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  const fetchLocation = useCallback(async (force = false) => {
    if (!force && userLocation) return;

    if (!("geolocation" in navigator)) {
      setLocationError("Geolocation not supported");
      setShowManualLoc(true);
      return;
    }

    setIsLocating(true);
    setLocationError(null);

    const options = {
      timeout: 15000,
      enableHighAccuracy: true,
      maximumAge: 0
    };

    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        const address = await getAddressFromCoords(loc.lat, loc.lng);
        const finalLoc = { ...loc, address };
        await updateLocationState(finalLoc);
      } catch (err) {
        setLocationError("Address resolution failed");
        setShowManualLoc(true);
      } finally {
        setIsLocating(false);
      }
    }, (err) => {
      setIsLocating(false);
      setShowManualLoc(true);
      setLocationError("Permission denied or timeout");
    }, options);
  }, [currentUser, userLocation]);

  useEffect(() => {
    const checkAuth = async () => {
      const savedUser = localStorage.getItem('agro_user');
      if (savedUser) {
        const parsed = JSON.parse(savedUser);
        const actualUser = await db.users.findOne({ id: parsed.id });
        if (actualUser) {
          setCurrentUser(actualUser);
          setIsLoggedIn(true);
          if (actualUser.location) {
            setUserLocation(actualUser.location);
          }
        }
      }
    };
    checkAuth();
  }, []);

  useEffect(() => {
    if (isLoggedIn && !userLocation && !isLocating) {
      fetchLocation();
    }
  }, [isLoggedIn, userLocation, isLocating, fetchLocation]);

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualAddress.trim()) return;
    setIsLocating(true);
    try {
      const coords = await getCoordsFromAddress(manualAddress);
      const finalLoc = { ...coords, address: manualAddress };
      await updateLocationState(finalLoc);
      setShowManualLoc(false);
    } catch (err) {
      setLocationError("Location not found");
    } finally {
      setIsLocating(false);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsLoggedIn(true);
    localStorage.setItem('agro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsLoggedIn(false);
    setUserLocation(null);
    localStorage.removeItem('agro_user');
  };

  const updateCurrentUser = async (updates: Partial<User>) => {
    if (currentUser) {
      await db.users.updateOne(currentUser.id, updates);
      const updated = { ...currentUser, ...updates };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  if (!isLoggedIn) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-emerald-100 selection:text-emerald-900">
      <header className="bg-white/95 backdrop-blur-xl border-b border-slate-200 sticky top-0 z-50 px-4 md:px-12 py-3 md:py-5 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2 md:gap-4">
          <div className="bg-emerald-600 p-2 rounded-xl md:rounded-2xl text-white shadow-lg shadow-emerald-100 transform hover:scale-105 transition-transform">
            <svg className="w-5 h-5 md:w-7 md:h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h1 className="text-xl md:text-2xl font-serif font-black text-slate-900 tracking-tight block">AgroFlow</h1>
        </div>

        <div className="flex items-center gap-2 md:gap-6">
          <button 
            onClick={() => fetchLocation(true)}
            disabled={isLocating}
            className={`flex items-center gap-2 md:gap-3 text-[9px] md:text-[11px] font-black uppercase tracking-widest transition-all px-3 md:px-5 py-2 md:py-2.5 rounded-xl md:rounded-2xl border ${isLocating ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-500 hover:border-emerald-500 hover:text-emerald-600 border-slate-200 shadow-sm'}`}
          >
            <svg className={`w-3.5 h-3.5 md:w-4 md:h-4 ${isLocating ? 'animate-spin' : 'text-emerald-500'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path></svg>
            <span className="truncate max-w-[80px] md:max-w-[200px]">
              {isLocating ? '...' : (userLocation?.address || 'SET LOC')}
            </span>
          </button>

          <div className="flex items-center gap-2 md:gap-4 border-l border-slate-200 pl-2 md:pl-6">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black text-slate-800 tracking-tight">{currentUser?.name}</p>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">{currentUser?.role}</p>
            </div>
            <button onClick={handleLogout} className="w-9 h-9 md:w-12 md:h-12 flex items-center justify-center bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all rounded-xl md:rounded-2xl border border-slate-100 shadow-sm" title="Logout">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
            </button>
          </div>
        </div>
      </header>

      {showManualLoc && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2rem] md:rounded-[3rem] p-6 md:p-10 shadow-2xl animate-in zoom-in duration-300">
            <h2 className="text-2xl md:text-3xl font-serif text-slate-900 tracking-tight mb-4 text-center">Update Location</h2>
            <form onSubmit={handleManualLocation} className="space-y-6">
               <input 
                type="text" placeholder="Enter City/Area (e.g. Pune)" 
                className="w-full px-6 py-4 rounded-xl md:rounded-2xl border-2 border-slate-100 font-bold focus:border-emerald-600 outline-none"
                value={manualAddress} onChange={e => setManualAddress(e.target.value)} required
               />
               <div className="flex flex-col gap-3">
                  <button type="submit" disabled={isLocating} className="w-full bg-emerald-600 text-white font-black py-4 rounded-xl md:rounded-2xl shadow-xl hover:bg-emerald-700 transition-all uppercase tracking-widest text-xs">
                    SET MANUAL LOCATION
                  </button>
                  <button type="button" onClick={() => setShowManualLoc(false)} className="w-full text-slate-400 font-black py-2 uppercase tracking-widest text-[10px]">CANCEL</button>
               </div>
            </form>
          </div>
        </div>
      )}

      <main className="flex-1 overflow-x-hidden">
        {currentUser?.role === 'farmer' ? (
          <FarmerDashboard user={currentUser} onUpdateUser={updateCurrentUser} />
        ) : (
          <BuyerDashboard user={currentUser!} onUpdateUser={updateCurrentUser} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Product, Order } from '../types';
import { calculateDistance } from '../utils/geo';
import { db } from '../services/db';
import MessagesView from './MessagesView';

