              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
            </button>
          </div>
        </div>
      </header>

      {showManualLoc && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2rem] md:rounded-[3rem] p-6 md:p-10 shadow-2xl animate-in zoom-in duration-300">
            <h2 className="text-2xl md:text-3xl font-serif text-slate-900 tracking-tight mb-4 text-center">Update Location</h2>
            <form onSubmit={handleManualLocation} className="space-y-6">
               <input 
                type="text" placeholder="Enter City/Area (e.g. Pune)" 
                className="w-full px-6 py-4 rounded-xl md:rounded-2xl border-2 border-slate-100 font-bold focus:border-emerald-600 outline-none"
                value={manualAddress} onChange={e => setManualAddress(e.target.value)} required
               />
               <div className="flex flex-col gap-3">
                  <button type="submit" disabled={isLocating} className="w-full bg-emerald-600 text-white font-black py-4 rounded-xl md:rounded-2xl shadow-xl hover:bg-emerald-700 transition-all uppercase tracking-widest text-xs">
                    SET MANUAL LOCATION
                  </button>
                  <button type="button" onClick={() => setShowManualLoc(false)} className="w-full text-slate-400 font-black py-2 uppercase tracking-widest text-[10px]">CANCEL</button>
               </div>
            </form>
          </div>
        </div>
      )}

      <main className="flex-1 overflow-x-hidden">
        {currentUser?.role === 'farmer' ? (
          <FarmerDashboard user={currentUser} onUpdateUser={updateCurrentUser} />
        ) : (
          <BuyerDashboard user={currentUser!} onUpdateUser={updateCurrentUser} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, Role } from '../types';
import { db } from '../services/db';

interface LoginProps {
  onLogin: (user: User) => void;
}

const LoginView: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [verificationCode, setVerificationCode] = useState('');
  const [role, setRole] = useState<Role>('buyer');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');

  const inputClasses = "w-full px-5 py-3 md:px-6 md:py-4 rounded-xl md:rounded-2xl border-2 border-slate-300 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-medium text-base md:text-lg";

  const handleStartRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    const existing = await db.users.findOne({ email: formData.email });
    if (existing) {
      setError('An account with this email already exists.');
      return;
    }

    setIsSendingSms(true);
    setTimeout(() => {
      setIsSendingSms(false);
      setIsVerifying(true);
    }, 1500);
  };

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (verificationCode === '123456') {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        name: formData.name,
        email: formData.email.toLowerCase().trim(),
        phone: formData.phone,
        password: formData.password,
        role: role,
        favorites: [],
        rating: role === 'farmer' ? 0.0 : undefined,
        deliveryDistance: role === 'farmer' ? 15 : undefined,
        thresholdQuantity: role === 'farmer' ? 50 : undefined,
        currentQuantity: role === 'farmer' ? 0 : undefined
      };

      await db.users.insertOne(newUser);
      onLogin(newUser);
    } else {
      setError('Invalid code. Use 123456.');
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const user = await db.users.findOne({ 
      email: formData.email.toLowerCase().trim(), 
      password: formData.password 
    });

    if (user) {
      onLogin(user);
    } else {
      setError('Invalid credentials.');
    }
  };

  if (isSendingSms) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-6">
        <div className="text-center space-y-6">
          <div className="w-12 h-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mx-auto"></div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">VERIFYING SECURITY...</p>
        </div>
      </div>
    );
  }

  if (isVerifying) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[2rem] shadow-2xl p-8 space-y-8 border border-slate-100">
          <div className="text-center">
            <h2 className="text-2xl font-serif text-slate-900 mb-2">Security Code</h2>
            <p className="text-slate-500 text-sm font-medium leading-relaxed">Sent to <span className="text-emerald-600 font-bold">{formData.phone}</span></p>
          </div>
          <form onSubmit={handleVerify} className="space-y-6">
            <input 
              type="text" maxLength={6} required
              className="w-full text-center text-3xl tracking-[0.2em] font-black py-5 rounded-2xl border-2 border-slate-200 bg-slate-50 focus:border-emerald-500 outline-none"
              placeholder="000000"
              value={verificationCode}
              onChange={(e) => setVerificationCode(e.target.value)}
            />
            <button className="w-full bg-emerald-600 text-white font-bold py-4 rounded-xl shadow-xl hover:bg-emerald-700 transition-all text-base uppercase tracking-widest">
              Confirm
            </button>
          </form>
          <div className="text-center">
             <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">DEMO CODE: 123456</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="max-w-lg w-full bg-white rounded-[2.5rem] md:rounded-[3.5rem] shadow-2xl p-8 md:p-12 space-y-8 md:space-y-10 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1.5 bg-emerald-500"></div>

        <div className="text-center">
          <div className="mx-auto w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center text-white mb-4 shadow-xl rotate-3">
             <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
          </div>
          <h2 className="text-3xl font-serif text-slate-900 tracking-tight">AgriConnect</h2>
          <p className="text-slate-400 font-bold uppercase text-[8px] tracking-[0.3em] mt-2">DIRECT FARM ACCESS</p>
        </div>

        {isRegistering && (
          <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
            <button onClick={() => setRole('buyer')} className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all ${role === 'buyer' ? 'bg-white shadow text-emerald-600' : 'text-slate-400'}`}>BUYER</button>
            <button onClick={() => setRole('farmer')} className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all ${role === 'farmer' ? 'bg-white shadow text-emerald-600' : 'text-slate-400'}`}>FARMER</button>
          </div>
        )}

        <form onSubmit={isRegistering ? handleStartRegistration : handleLogin} className="space-y-4 md:space-y-5">
          {error && <div className="bg-red-50 text-red-600 p-3 rounded-xl text-[10px] font-black border border-red-100">{error}</div>}

          {isRegistering && (
            <input type="text" required className={inputClasses} placeholder="Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          )}
          {isRegistering && (
            <input type="tel" required className={inputClasses} placeholder="Mobile" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
          )}
          <input type="email" required className={inputClasses} placeholder="Email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
          <input type="password" required className={inputClasses} placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />

          {isRegistering && (
            <input type="password" required className={inputClasses} placeholder="Confirm" value={formData.confirmPassword} onChange={e => setFormData({...formData, confirmPassword: e.target.value})} />
          )}

          <button type="submit" className="w-full bg-emerald-600 text-white font-black py-4 md:py-5 rounded-xl md:rounded-2xl shadow-xl hover:bg-emerald-700 transition-all text-lg tracking-tight active:scale-95 shadow-emerald-200/40">
            {isRegistering ? 'Join Network' : 'Enter'}
          </button>
        </form>

        <button onClick={() => { setIsRegistering(!isRegistering); setError(''); }} className="w-full text-center text-[9px] font-black text-slate-400 hover:text-emerald-600 uppercase tracking-widest">
          {isRegistering ? 'Have an account? Login' : 'No account? Join Us'}
        </button>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Product, Order } from '../types';
import { calculateDistance } from '../utils/geo';
import { db } from '../services/db';
import MessagesView from './MessagesView';

const StarRating: React.FC<{ initialValue?: number, onRate?: (val: number) => void, interactive?: boolean }> = ({ initialValue = 0, onRate, interactive = false }) => {
  const [hover, setHover] = useState(0);
  const stars = [1, 2, 3, 4, 5];
  return (
    <div className="flex items-center gap-1">
      {stars.map((star) => (
        <button key={star} type="button" disabled={!interactive} className={`${interactive ? 'cursor-pointer hover:scale-110' : 'cursor-default'} transition-all`} onClick={() => interactive && onRate && onRate(star)} onMouseEnter={() => interactive && setHover(star)} onMouseLeave={() => interactive && setHover(0)}>
          <svg className={`w-5 h-5 ${star <= (hover || initialValue) ? 'text-amber-400 fill-current' : 'text-slate-200 fill-current'}`} viewBox="0 0 24 24">
            <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" />
          </svg>
        </button>
      ))}
    </div>
  );
};

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const BuyerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [view, setView] = useState<'marketplace' | 'store' | 'orders' | 'messages'>('marketplace');
  const [farmers, setFarmers] = useState<User[]>([]);
  const [selectedFarmer, setSelectedFarmer] = useState<User | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [buyerOrders, setBuyerOrders] = useState<Order[]>([]);
  const [quantities, setQuantities] = useState<Record<string, number>>({});
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [marketFilter, setMarketFilter] = useState<'all' | 'favorites'>('all');

  // Modals state
  const [cancelData, setCancelData] = useState<{orderId: string, productId: string, farmerId: string, quantity: number} | null>(null);
  const [ratingData, setRatingData] = useState<{farmerId: string, orderId: string, farmerName: string} | null>(null);
  const [ratingValue, setRatingValue] = useState(5);

  const selectedFarmerIdRef = useRef<string | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const allFarmers = await db.users.find({ role: 'farmer' });
    setFarmers(allFarmers);
    const orders = await db.orders.find({ buyerId: user.id });
    setBuyerOrders(orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    if (selectedFarmerIdRef.current) {
      const prods = await db.products.find({ farmerId: selectedFarmerIdRef.current });
      setStoreProducts(prods);
    }
  }, [user.id]);

  useEffect(() => {
    loadData();
    const intv = setInterval(loadData, 5000);
    return () => clearInterval(intv);
  }, [loadData]);

  const nearbyFarmers = farmers.filter(f => {
    if (!user.location || !f.location) return true;
    const dist = calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng);
    return dist <= (f.deliveryDistance || 20);
  });

  const displayedFarmers = marketFilter === 'all' 
    ? nearbyFarmers 
    : nearbyFarmers.filter(f => (user.favorites || []).includes(f.id));

  const toggleFavorite = async (e: React.MouseEvent, farmerId: string) => {
    e.stopPropagation();
    const currentFavs = user.favorites || [];
    let newFavs: string[];

    if (currentFavs.includes(farmerId)) {
      newFavs = currentFavs.filter(id => id !== farmerId);
      showToast("Removed from favorites");
    } else {
      newFavs = [...currentFavs, farmerId];
      showToast("Added to favorites");
    }

    onUpdateUser({ favorites: newFavs });
    await db.users.updateOne(user.id, { favorites: newFavs });
  };

  const handleUpdateQty = (product: Product, delta: number) => {
    const currentQty = quantities[product.id] || 1;
    const newQty = currentQty + delta;

    if (newQty < 1) return;

    if (newQty > product.stock) {
      showToast(`Only ${product.stock}kg available`, 'error');
      return;
    }

    setQuantities(prev => ({
      ...prev,
      [product.id]: newQty
    }));
  };

  const handleBuy = async (p: Product) => {
    if (!selectedFarmer) return;
    const qty = quantities[p.id] || 1;

    // Double check stock
    const freshProduct = await db.products.findOne({ id: p.id });
    if (!freshProduct || freshProduct.stock < qty) {
      showToast("Not enough stock available", "error");
      await loadData();
      return;
    }

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      productId: p.id,
      productName: p.name,
      farmerId: selectedFarmer.id,
      farmName: selectedFarmer.name,
      buyerId: user.id,
      buyerName: user.name,
      buyerLocation: user.location?.address || 'Unknown Location',
      quantity: qty,
      totalPrice: p.price * qty,
      status: 'pending',
      date: new Date().toISOString()
    };

    await db.orders.insertOne(newOrder);

    // Update farmer's batch readiness progress
    const currentFarmer = await db.users.findOne({ id: selectedFarmer.id });
    if (currentFarmer) {
      await db.users.updateOne(selectedFarmer.id, { currentQuantity: (currentFarmer.currentQuantity || 0) + qty });
    }

    // Deduct stock
    await db.products.updateOne(p.id, { stock: freshProduct.stock - qty });

    showToast(`Order Placed! Total: ₹${p.price * qty}`);
    setQuantities(prev => ({ ...prev, [p.id]: 1 }));
    setView('orders');
    await loadData();
  };

  const initiateCancel = (order: Order) => {
    setCancelData({
      orderId: order.id,
      productId: order.productId,
      farmerId: order.farmerId,
      quantity: order.quantity
    });
  };

  const confirmCancelOrder = async () => {
    if (!cancelData) return;

    await db.orders.updateOne(cancelData.orderId, { status: 'cancelled' });

    // Deduct from farmer's batch progress
    const farmer = await db.users.findOne({ id: cancelData.farmerId });
    if (farmer) {
      const newQty = Math.max(0, (farmer.currentQuantity || 0) - cancelData.quantity);
      await db.users.updateOne(cancelData.farmerId, { currentQuantity: newQty });
    }

    // Restore product stock
    const product = await db.products.findOne({ id: cancelData.productId });
    if (product) {
      await db.products.updateOne(cancelData.productId, { stock: product.stock + cancelData.quantity });
    }

    showToast("Order cancelled", "error");
    setCancelData(null);
    await loadData();
  };

  const initiateRating = (order: Order) => {
    setRatingData({
      farmerId: order.farmerId,
      orderId: order.id,
      farmerName: order.farmName
    });
    setRatingValue(5);
  };

  const submitRating = async () => {
    if (!ratingData) return;

    const farmer = await db.users.findOne({ id: ratingData.farmerId });
    if (farmer) {
      const currentRating = farmer.rating || 0;
      const newRating = currentRating === 0 ? ratingValue : (currentRating + ratingValue) / 2;

      await db.users.updateOne(ratingData.farmerId, { rating: newRating });
      showToast(`Rated ${ratingData.farmerName} successfully!`);
    }

    setRatingData(null);
    await loadData();
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-16 animate-in fade-in duration-700">
      {toast && <div className={`fixed top-24 right-4 md:right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-[10px] md:text-xs uppercase tracking-widest`}>{toast.message}</div>}

      <div className="flex flex-col md:flex-row items-center justify-between mb-8 md:mb-16 gap-8">
        <div className="flex glass p-1.5 md:p-2 rounded-[1.8rem] md:rounded-[2.8rem] shadow-xl overflow-x-auto max-w-full no-scrollbar">
          {['marketplace', 'orders', 'messages'].map(v => (
            <button key={v} onClick={() => setView(v as any)} className={`px-6 md:px-12 py-3 md:py-5 rounded-xl md:rounded-[2.2rem] font-black text-[10px] md:text-xs uppercase tracking-widest transition-all ${view === v ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200' : 'text-slate-400 hover:text-emerald-600'}`}>{v}</button>
          ))}
        </div>
      </div>

      {view === 'marketplace' && (
        <>
          <div className="flex gap-4 mb-8 justify-center md:justify-start">
             <button onClick={() => setMarketFilter('all')} className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${marketFilter === 'all' ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-400 border-slate-200'}`}>All Farms</button>
             <button onClick={() => setMarketFilter('favorites')} className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${marketFilter === 'favorites' ? 'bg-red-500 text-white border-red-500' : 'bg-white text-slate-400 border-slate-200'}`}>Favorites</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-14">
            {displayedFarmers.length === 0 ? (
              <div className="col-span-full py-20 text-center opacity-40 italic font-serif text-xl">{marketFilter === 'favorites' ? 'No favorite farmers yet.' : 'No nearby farmers found. Try updating your location.'}</div>
            ) : (
              displayedFarmers.map(f => {
                const dist = user.location && f.location ? calculateDistance(user.location.lat, user.location.lng, f.location.lat, f.location.lng) : 0;
                const progress = ((f.currentQuantity || 0) / (f.thresholdQuantity || 100)) * 100;
                const isFav = (user.favorites || []).includes(f.id);

                return (
                  <div key={f.id} className="bg-white rounded-3xl md:rounded-[4rem] p-8 md:p-12 shadow-sm border border-slate-100 hover:shadow-2xl transition-all group relative overflow-hidden">
                    <div className="flex justify-between items-start mb-6 md:mb-10 relative z-10">
                      <div className="w-16 h-16 md:w-20 md:h-20 bg-emerald-50 rounded-2xl md:rounded-[2.5rem] flex items-center justify-center text-emerald-600 shadow-inner">
                        <svg className="w-8 h-8 md:w-10 md:h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3"></path></svg>
                      </div>
                      <div className="flex flex-col items-end gap-2">
                         <button onClick={(e) => toggleFavorite(e, f.id)} className={`w-10 h-10 flex items-center justify-center rounded-full transition-all ${isFav ? 'bg-red-50 text-red-500' : 'bg-slate-50 text-slate-300 hover:text-red-400'}`}>
                           <svg className={`w-5 h-5 ${isFav ? 'fill-current' : 'fill-none'}`} stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"></path></svg>
                         </button>
                         <div className={`px-4 md:px-5 py-1.5 md:py-2 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest ${dist < 10 ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>{dist < 10 ? 'SAME AREA' : `${dist} KM`}</div>
                      </div>
                    </div>
                    <h3 className="text-2xl md:text-3xl font-serif text-slate-900 mb-2 truncate">{f.name}</h3>
                    <div className="mb-6 md:mb-8"><StarRating initialValue={Math.round(f.rating || 0)} /></div>
                    <div className="bg-slate-50 p-4 md:p-6 rounded-2xl md:rounded-[2.5rem] mb-8 md:mb-10 border border-slate-100">
                       <div className="flex justify-between text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3"><span>Batch Readiness</span><span>{Math.round(progress)}%</span></div>
                       <div className="w-full bg-slate-200 h-2.5 md:h-3 rounded-full overflow-hidden"><div className="bg-emerald-500 h-full transition-all duration-1000" style={{ width: `${Math.min(100, progress)}%` }}></div></div>
                    </div>
                    <button onClick={() => { setSelectedFarmer(f); selectedFarmerIdRef.current = f.id; setView('store'); }} className="w-full bg-slate-900 text-white font-black py-5 md:py-7 rounded-2xl md:rounded-[2rem] hover:bg-emerald-600 transition-all text-base md:text-lg uppercase tracking-widest shadow-xl">Browse Store</button>
                  </div>
                );
              })
            )}
          </div>
        </>
      )}

      {view === 'store' && selectedFarmer && (
        <div className="space-y-8 md:space-y-12 animate-in slide-in-from-bottom-20 duration-700">
           <button onClick={() => setView('marketplace')} className="glass px-6 md:px-8 py-3 md:py-4 rounded-xl md:rounded-2xl font-black text-[10px] md:text-xs uppercase text-slate-400 hover:text-emerald-600 flex items-center gap-2">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7"></path></svg>
             Back to Market
           </button>
           <h2 className="text-4xl md:text-6xl font-serif text-slate-900 tracking-tight">{selectedFarmer.name}</h2>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12">
              {storeProducts.length === 0 ? (
                <div className="col-span-full py-20 text-center text-slate-400 italic font-serif text-2xl">No items listed by this farmer yet.</div>
              ) : (
                storeProducts.map(p => {
                  const qty = quantities[p.id] || 1;
                  const totalCost = p.price * qty;
                  const isOutOfStock = p.stock <= 0;

                  return (
                    <div key={p.id} className={`bg-white rounded-3xl md:rounded-[4rem] overflow-hidden border border-slate-100 shadow-lg group flex flex-col h-full ${isOutOfStock ? 'opacity-70 grayscale' : ''}`}>
                      <div className="h-48 md:h-64 overflow-hidden relative">
                        <img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={p.name} />
                        <div className="absolute top-4 right-4 bg-white/90 backdrop-blur-md px-4 py-2 rounded-xl font-black text-emerald-600 shadow-lg">₹{p.price}/kg</div>
                        {isOutOfStock ? (
                           <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-[2px] flex items-center justify-center">
                             <div className="bg-white text-slate-900 px-6 py-3 rounded-full font-black uppercase text-sm tracking-widest shadow-xl transform -rotate-6">Out of Stock</div>
                           </div>
                        ) : (
                           <div className="absolute bottom-4 left-4 bg-black/50 backdrop-blur-md px-3 py-1.5 rounded-lg font-bold text-white text-xs">{p.stock} kg available</div>
                        )}
                      </div>
                      <div className="p-8 md:p-10 flex flex-col flex-1">
                        <h3 className="text-2xl font-serif text-slate-900 mb-2">{p.name}</h3>
                        <p className="text-slate-500 text-sm mb-6 line-clamp-2 italic">"{p.description}"</p>

                        <div className="mt-auto space-y-4">
                          <div className="bg-slate-50 p-4 rounded-3xl border border-slate-100">
                            <div className="flex items-center justify-between mb-4">
                              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Quantity</span>
                              <div className="flex items-center gap-4">
                                <button disabled={isOutOfStock} onClick={() => handleUpdateQty(p, -1)} className="w-10 h-10 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-red-50 hover:text-red-500 transition-colors shadow-sm active:scale-90 font-black disabled:opacity-50">-</button>
                                <span className="text-xl font-black text-slate-800 w-8 text-center">{qty}</span>
                                <button disabled={isOutOfStock} onClick={() => handleUpdateQty(p, 1)} className="w-10 h-10 rounded-xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-emerald-50 hover:text-emerald-500 transition-colors shadow-sm active:scale-90 font-black disabled:opacity-50">+</button>
                              </div>
                            </div>
                            <div className="flex items-center justify-between border-t border-slate-200 pt-3">
                               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Total Cost</span>
                               <span className="text-2xl font-black text-emerald-600">₹{totalCost}</span>
                            </div>
                          </div>

                          <button disabled={isOutOfStock} onClick={() => handleBuy(p)} className="w-full bg-slate-900 text-white font-black py-4 md:py-6 rounded-2xl hover:bg-emerald-600 transition-all uppercase tracking-widest shadow-xl flex items-center justify-center gap-3 disabled:bg-slate-300 disabled:cursor-not-allowed">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z"></path></svg>
                            Place Order
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
           </div>
        </div>
      )}

      {view === 'orders' && (
        <div className="bg-white rounded-2xl md:rounded-[4rem] shadow-2xl border border-slate-100 overflow-hidden">
           <div className="p-8 md:p-16 bg-emerald-50/20 text-center"><h2 className="text-3xl md:text-5xl font-serif text-slate-900">Track Harvest</h2><p className="text-slate-400 font-black uppercase text-[9px] md:text-[10px] tracking-widest mt-3 md:mt-5">Direct Supply Chain</p></div>
           <div className="overflow-x-auto">
             <table className="w-full text-left">
                <thead className="bg-slate-50 text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest"><tr><th className="px-6 md:px-16 py-4 md:py-8">Produce</th><th className="px-6 md:px-16 py-4 md:py-8">Status</th><th className="px-6 md:px-16 py-4 md:py-8 text-right">Settlement</th><th className="px-6 md:px-16 py-4 md:py-8">Action</th></tr></thead>
                <tbody className="divide-y divide-slate-100">
                  {buyerOrders.length === 0 ? (
                    <tr><td colSpan={4} className="p-10 text-center text-slate-400 italic">No orders tracked yet.</td></tr>
                  ) : (
                    buyerOrders.map(o => (
                      <tr key={o.id} className="hover:bg-slate-50/50">
                        <td className="px-6 md:px-16 py-8 md:py-12"><div><p className="font-serif text-slate-900 text-2xl md:text-3xl">{o.productName}</p><p className="text-emerald-600 font-black text-[8px] md:text-[9px] uppercase tracking-widest mt-1 md:mt-2">{o.farmName} • {o.quantity}kg</p></div></td>
                        <td className="px-6 md:px-16 py-8 md:py-12"><div className={`inline-flex px-3 md:px-4 py-1.5 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest ${o.status === 'pending' ? 'bg-amber-100 text-amber-600' : (o.status === 'cancelled' ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600')}`}>{o.status}</div></td>
                        <td className="px-6 md:px-16 py-8 md:py-12 text-right font-black text-xl md:text-2xl text-slate-900">₹{o.totalPrice}</td>
                        <td className="px-6 md:px-16 py-8 md:py-12">
                          {(o.status === 'pending' || o.status === 'confirmed') && (
                            <button onClick={() => initiateCancel(o)} className="bg-red-50 text-red-500 font-black px-4 py-2 rounded-xl text-[9px] uppercase tracking-widest border border-red-100 hover:bg-red-600 hover:text-white transition-all shadow-sm">Cancel</button>
                          )}
                          {o.status === 'delivered' && (
                            <button onClick={() => initiateRating(o)} className="ml-2 bg-amber-50 text-amber-500 font-black px-4 py-2 rounded-xl text-[9px] uppercase tracking-widest border border-amber-100 hover:bg-amber-500 hover:text-white transition-all shadow-sm">Rate</button>
                          )}
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
             </table>
           </div>
        </div>
      )}

      {/* Cancel Order Modal */}
      {cancelData && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[600] flex items-center justify-center p-4 animate-in fade-in duration-200">
           <div className="bg-white max-w-sm w-full rounded-[2.5rem] p-8 shadow-2xl border-2 border-white text-center">
             <h3 className="text-2xl font-serif text-slate-900 mb-2">Cancel Order?</h3>
             <p className="text-slate-500 text-sm mb-8">This will restore the farmer's stock and remove this order.</p>
             <div className="flex gap-4">
                <button onClick={() => setCancelData(null)} className="flex-1 py-4 rounded-2xl bg-slate-100 text-slate-500 font-black text-xs uppercase tracking-widest hover:bg-slate-200">Keep It</button>
                <button onClick={confirmCancelOrder} className="flex-1 py-4 rounded-2xl bg-red-600 text-white font-black text-xs uppercase tracking-widest hover:bg-red-700 shadow-lg shadow-red-200">Yes, Cancel</button>
             </div>
           </div>
        </div>
      )}

      {/* Rating Modal */}
      {ratingData && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[600] flex items-center justify-center p-4 animate-in fade-in duration-200">
           <div className="bg-white max-w-sm w-full rounded-[2.5rem] p-8 shadow-2xl border-2 border-white text-center">
             <h3 className="text-2xl font-serif text-slate-900 mb-2">Rate Experience</h3>
             <p className="text-slate-500 text-sm mb-6">How was your order from {ratingData.farmerName}?</p>
             <div className="flex justify-center mb-8">
               <StarRating initialValue={ratingValue} onRate={setRatingValue} interactive />
             </div>
             <div className="flex gap-4">
                <button onClick={() => setRatingData(null)} className="flex-1 py-4 rounded-2xl bg-slate-100 text-slate-500 font-black text-xs uppercase tracking-widest hover:bg-slate-200">Later</button>
                <button onClick={submitRating} className="flex-1 py-4 rounded-2xl bg-emerald-600 text-white font-black text-xs uppercase tracking-widest hover:bg-emerald-700 shadow-lg shadow-emerald-200">Submit</button>
             </div>
           </div>
        </div>
      )}

      {view === 'messages' && <MessagesView currentUser={user} />}
    </div>
  );
};

export default BuyerDashboard;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { User, Product, Order } from '../types';
import { generateProductDescription, suggestPrice } from '../services/geminiService';
import { db } from '../services/db';
import MessagesView from './MessagesView';

const categories = ['Vegetables', 'Fruits', 'Grains', 'Spices', 'Dairy', 'Others'];
const inputClasses = "w-full px-5 py-3 md:px-6 md:py-4 rounded-xl md:rounded-2xl border-2 border-slate-200 bg-white text-slate-900 placeholder-slate-400 focus:border-emerald-600 outline-none transition-all font-bold";

interface Props {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const FarmerDashboard: React.FC<Props> = ({ user, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'products' | 'add-product' | 'orders' | 'messages' | 'settings'>('overview');
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null); // State for custom delete modal
  const [cancelOrderData, setCancelOrderData] = useState<Order | null>(null); // State for cancelling order

  const [newProduct, setNewProduct] = useState({ 
    name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: ''
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isPricing, setIsPricing] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadData = useCallback(async () => {
    const userProducts = await db.products.find({ farmerId: user.id });
    setProducts([...userProducts].sort((a, b) => a.name.localeCompare(b.name)));
    const userOrders = await db.orders.find({ farmerId: user.id });
    setOrders([...userOrders].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  }, [user.id]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000);
    return () => clearInterval(interval);
  }, [loadData]);

  const handleResetBatch = async () => {
    await db.users.updateOne(user.id, { currentQuantity: 0 });
    onUpdateUser({ currentQuantity: 0 });
    showToast("Batch progress reset for new harvest.");
  };

  const confirmCancelOrder = async () => {
    if (!cancelOrderData) return;

    await db.orders.updateOne(cancelOrderData.id, { status: 'cancelled' });

    // Restore stock logic:
    // 1. Restore product stock
    const product = await db.products.findOne({ id: cancelOrderData.productId });
    if (product) {
      await db.products.updateOne(cancelOrderData.productId, { stock: product.stock + cancelOrderData.quantity });
    }

    // 2. Reduce batch progress (if it hasn't been reset yet)
    const currentQty = user.currentQuantity || 0;
    const newQty = Math.max(0, currentQty - cancelOrderData.quantity);
    await db.users.updateOne(user.id, { currentQuantity: newQty });
    onUpdateUser({ currentQuantity: newQty });

    showToast("Order cancelled & stock restored.", "error");
    setCancelOrderData(null);
    await loadData();
  };

  const handleUpdateOrderStatus = async (orderId: string, newStatus: Order['status']) => {
    if (newStatus === 'cancelled') {
      const order = await db.orders.findOne({ id: orderId });
      if (order) setCancelOrderData(order);
      return;
    }

    const order = await db.orders.findOne({ id: orderId });
    if (!order) return;

    await db.orders.updateOne(orderId, { status: newStatus });

    if (newStatus === 'confirmed') {
      showToast("Order confirmed successfully!", "success");
    } else if (newStatus === 'delivered') {
      showToast("Order delivered! Batch goal reset.");
      // Auto reset goal after delivery as requested
      await db.users.updateOne(user.id, { currentQuantity: 0 });
      onUpdateUser({ currentQuantity: 0 });
    } else {
      showToast(`Order marked as ${newStatus}`);
    }

    await loadData();
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEditing = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (isEditing && editingProduct) setEditingProduct({ ...editingProduct, imageUrl: base64String });
        else setNewProduct({ ...newProduct, imageUrl: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.imageUrl) { showToast("Upload a photo.", "error"); return; }
    const product: Product = {
      id: Math.random().toString(36).substr(2, 9),
      farmerId: user.id,
      name: newProduct.name,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      unit: newProduct.unit,
      stock: parseInt(newProduct.stock) || 0,
      description: newProduct.description || "Fresh harvest.",
      imageUrl: newProduct.imageUrl
    };
    await db.products.insertOne(product);
    setNewProduct({ name: '', price: '', category: 'Vegetables', unit: 'kg', stock: '', description: '', imageUrl: '' });
    setActiveTab('products');
    showToast("Product listed!");
    await loadData();
  };

  const handleUpdateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      await db.products.updateOne(editingProduct.id, {
        name: editingProduct.name,
        price: editingProduct.price,
        description: editingProduct.description,
        imageUrl: editingProduct.imageUrl,
        stock: editingProduct.stock,
        category: editingProduct.category
      });
      setEditingProduct(null);
      showToast("Updated successfully!");
      await loadData();
    }
  };

  // Replaced native confirm with custom modal trigger
  const requestDelete = (productId: string) => {
    setDeleteId(productId);
  };

  const confirmDelete = async () => {
    if (!deleteId) return;
    try {
      await db.products.deleteOne(deleteId);
      setProducts(prev => prev.filter(p => p.id !== deleteId));
      showToast("Product removed permanently", "error");
      await loadData();
    } catch (err) {
      console.error("Delete failed:", err);
      showToast("Error removing product", "error");
    } finally {
      setDeleteId(null);
    }
  };

  const handleMagicDescription = async () => {
    if (!newProduct.name) return;
    setIsGenerating(true);
    const desc = await generateProductDescription(newProduct.name, newProduct.category);
    setNewProduct({ ...newProduct, description: desc });
    setIsGenerating(false);
  };

  const handleAISuggestPrice = async () => {
    if (!newProduct.name) return;
    setIsPricing(true);
    const price = await suggestPrice(newProduct.name);
    setNewProduct({ ...newProduct, price });
    setIsPricing(false);
  };

  const currentProgress = (user.currentQuantity || 0);
  const threshold = (user.thresholdQuantity || 100);
  const progressPercent = Math.min(100, (currentProgress / threshold) * 100);
  const pendingRequests = orders.filter(o => o.status === 'pending').length;

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-65px)] bg-slate-50/30">
      {toast && (
        <div className={`fixed top-24 right-4 md:right-10 z-[1000] px-8 py-5 rounded-2xl shadow-2xl animate-in slide-in-from-right-10 border-2 ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-red-600 border-red-500 text-white'} font-black text-[10px] md:text-xs uppercase tracking-widest`}>
           {toast.message}
        </div>
      )}

      {/* Sidebar Navigation */}
      <nav className="w-full md:w-72 lg:w-80 glass border-b md:border-b-0 md:border-r border-slate-200 p-4 md:p-8 flex md:flex-col gap-2 md:gap-4 overflow-x-auto md:overflow-y-auto z-40 sticky top-0 md:h-[calc(100vh-73px)] no-scrollbar">
        <div className="hidden md:block pb-6 px-4"><h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">CONTROL ROOM</h3></div>
        {[
          { id: 'overview', label: 'Dashboard', icon: 'M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6z' },
          { id: 'products', label: 'Inventory', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
          { id: 'add-product', label: 'Add Harvest', icon: 'M12 4v16m8-8H4' },
          { id: 'orders', label: 'Orders', icon: 'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2' },
          { id: 'messages', label: 'Chats', icon: 'M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72' },
          { id: 'settings', label: 'Rules', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066' }
        ].map(item => (
          <button 
            key={item.id} onClick={() => setActiveTab(item.id as any)}
            className={`flex-shrink-0 flex items-center gap-3 md:gap-5 px-5 md:px-7 py-3 md:py-5 rounded-xl md:rounded-[1.8rem] transition-all font-black text-[10px] md:text-xs uppercase tracking-widest border-2 ${activeTab === item.id ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200' : 'bg-white border-transparent text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
          >
            <svg className="w-4 h-4 md:w-5 md:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path></svg>
            <span className="md:inline">{item.label}</span>
          </button>
        ))}
      </nav>

      {/* Main Content */}
      <div className="flex-1 p-4 md:p-14 max-w-7xl mx-auto w-full overflow-y-auto">

        {activeTab === 'overview' && (
          <div className="space-y-6 md:space-y-12 animate-in fade-in duration-500">
             <div className="bg-white p-6 md:p-12 rounded-[2rem] md:rounded-[4.5rem] shadow-xl border border-slate-100 flex flex-col lg:flex-row items-center justify-between gap-8 md:gap-12 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-4 md:p-8 opacity-5 hidden sm:block"><svg className="w-32 h-32 md:w-48 md:h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path></svg></div>
               <div className="space-y-4 md:space-y-6 flex-1 text-center lg:text-left z-10">
                  <h2 className="text-3xl md:text-5xl font-serif text-slate-900 tracking-tight leading-tight">Batch Readiness</h2>
                  <p className="text-slate-500 text-sm md:text-lg font-medium max-w-lg leading-relaxed">Reach your fulfillment goal to trigger direct delivery.</p>
                  <div className="flex flex-wrap gap-3 md:gap-4 justify-center lg:justify-start">
                    <div className="bg-emerald-600 text-white px-6 md:px-10 py-3 md:py-5 rounded-2xl md:rounded-[2rem] font-black shadow-2xl shadow-emerald-200 text-lg md:text-2xl tracking-tighter">
                      {currentProgress} / {threshold} KG
                    </div>
                    {progressPercent >= 100 && (
                      <button onClick={handleResetBatch} className="bg-slate-900 text-white px-6 py-3 rounded-2xl md:rounded-[2rem] font-black text-[10px] md:text-xs uppercase tracking-widest shadow-xl hover:bg-emerald-700 transition-all">Reset Batch</button>
                    )}
                  </div>
               </div>
               <div className="relative w-48 h-48 md:w-80 md:h-80 flex items-center justify-center flex-shrink-0 bg-white rounded-full p-4 md:p-10 shadow-2xl border-4 border-slate-50">
                  <svg className="w-full h-full -rotate-90 overflow-visible" viewBox="0 0 320 320">
                    <circle cx="160" cy="160" r="130" className="stroke-slate-100 fill-none" strokeWidth="28" />
                    <circle cx="160" cy="160" r="130" className="stroke-emerald-500 fill-none transition-all duration-1000" strokeWidth="28" strokeDasharray={`${progressPercent * 8.16} 816`} strokeLinecap="round" />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-3xl md:text-6xl font-black tracking-tighter text-slate-800">{Math.round(progressPercent)}%</span>
                    <span className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1 md:mt-2">GOAL</span>
                  </div>
               </div>
             </div>

             <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-8">
               {[
                 { label: 'Rating', val: user.rating?.toFixed(1) || '0.0', color: 'text-amber-500' },
                 { label: 'Requests', val: pendingRequests, color: 'text-blue-600' },
                 { label: 'Listings', val: products.length, color: 'text-slate-900' },
                 { label: 'Sales', val: orders.filter(o => o.status === 'delivered').length, color: 'text-emerald-600' }
               ].map((stat, i) => (
                 <div key={i} className="bg-white p-6 md:p-10 rounded-2xl md:rounded-[3rem] border border-slate-200 shadow-sm flex flex-col justify-between hover:shadow-md transition-shadow">
                    <p className="text-slate-400 font-black uppercase text-[8px] md:text-[10px] tracking-widest mb-4 md:mb-6">{stat.label}</p>
                    <p className={`text-2xl md:text-5xl font-black ${stat.color} tracking-tighter`}>{stat.val}</p>
                 </div>
               ))}
             </div>
