              </div>
            </div>

            <button disabled={isOutOfStock} onClick={() => handleBuy(p)} className="w-full bg-slate-900 text-white font-black py-4 md:py-6 rounded-2xl hover:bg-emerald-600 transition-all uppercase tracking-widest shadow-xl flex items-center justify-center gap-3 disabled:bg-slate-300 disabled:cursor-not-allowed">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z"></path></svg>
              Place Order
            </button>
