        <div className="flex items-center gap-3">
          <div className="bg-gradient-to-br from-emerald-500 to-teal-600 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-200/50 transform hover:scale-105 transition-transform duration-300">
            {/* New Leaf/Agri Logo */}
            <svg className="w-5 h-5 md:w-6 md:h-6" fill="currentColor" viewBox="0 0 24 24">
               <path d="M12 3a9 9 0 0 0-9 9v7c0 1.1.9 2 2 2h7a9 9 0 0 0 0-18zm0 16H5v-7a7 7 0 0 1 7-7 7 7 0 0 1 7 7c0 3.87-3.13 7-7 7z"/>
               <path d="M12 19a3 3 0 0 1 0-6 3 3 0 0 1 0 6z" opacity="0.5"/>
            </svg>
          </div>
          <h1 className="text-xl md:text-2xl font-serif font-black text-slate-800 tracking-tight block">AgriConnect</h1>
        </div>

        <div className="flex items-center gap-3 md:gap-6">
          <button 
            onClick={() => fetchLocation(true)}
            disabled={isLocating}
            className={`group flex items-center gap-2 md:gap-3 text-[10px] md:text-xs font-black uppercase tracking-widest transition-all px-4 py-2 md:py-2.5 rounded-xl border ${isLocating ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-500 hover:border-emerald-200 hover:text-emerald-700 hover:shadow-md border-slate-200'}`}
          >
