import React, { useState } from 'react';
import { User, Role } from '../types';
import { db } from '../services/db';

interface LoginProps {
  onLogin: (user: User) => void;
}

const LoginView: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [verificationCode, setVerificationCode] = useState('');
  const [role, setRole] = useState<Role>('buyer');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');

  const inputClasses = "w-full px-5 py-3 md:px-6 md:py-4 rounded-xl md:rounded-2xl border-2 border-slate-200 bg-slate-50/50 text-slate-900 placeholder-slate-400 focus:border-emerald-500 focus:bg-white focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all font-bold text-base md:text-lg";

  const handleStartRegistration = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    const existing = await db.users.findOne({ email: formData.email });
    if (existing) {
      setError('An account with this email already exists.');
      return;
    }

    setIsSendingSms(true);
    setTimeout(() => {
      setIsSendingSms(false);
      setIsVerifying(true);
    }, 1500);
  };

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (verificationCode === '123456') {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        name: formData.name,
        email: formData.email.toLowerCase().trim(),
        phone: formData.phone,
        password: formData.password,
        role: role,
        favorites: [],
        rating: role === 'farmer' ? 0.0 : undefined,
        deliveryDistance: role === 'farmer' ? 15 : undefined,
        thresholdQuantity: role === 'farmer' ? 50 : undefined,
        currentQuantity: role === 'farmer' ? 0 : undefined
      };

      await db.users.insertOne(newUser);
      onLogin(newUser);
    } else {
      setError('Invalid code. Use 123456.');
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const user = await db.users.findOne({ 
      email: formData.email.toLowerCase().trim(), 
      password: formData.password 
    });

    if (user) {
      onLogin(user);
    } else {
      setError('Invalid credentials.');
    }
  };

  if (isSendingSms) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-6">
        <div className="text-center space-y-6">
          <div className="w-12 h-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mx-auto"></div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">VERIFYING SECURITY...</p>
        </div>
      </div>
    );
  }

  if (isVerifying) {
    return (
      <div className="min-h-screen bg-[#F8FAF9] flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[2rem] shadow-2xl p-8 space-y-8 border border-slate-100">
          <div className="text-center">
            <h2 className="text-2xl font-serif text-slate-900 mb-2">Security Code</h2>
            <p className="text-slate-500 text-sm font-medium leading-relaxed">Sent to <span className="text-emerald-600 font-bold">{formData.phone}</span></p>
          </div>
          <form onSubmit={handleVerify} className="space-y-6">
            <input 
              type="text" maxLength={6} required
              className="w-full text-center text-3xl tracking-[0.2em] font-black py-5 rounded-2xl border-2 border-slate-200 bg-slate-50 focus:border-emerald-500 outline-none"
              placeholder="000000"
              value={verificationCode}
              onChange={(e) => setVerificationCode(e.target.value)}
            />
            <button className="w-full bg-emerald-600 text-white font-bold py-4 rounded-xl shadow-xl hover:bg-emerald-700 transition-all text-base uppercase tracking-widest">
              Confirm
            </button>
          </form>
          <div className="text-center">
             <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">DEMO CODE: 123456</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center p-4 relative overflow-hidden bg-[#0f172a]">
      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
        <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] bg-emerald-600/20 rounded-full blur-[100px] animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="max-w-lg w-full bg-white/95 backdrop-blur-3xl rounded-[2.5rem] md:rounded-[3.5rem] shadow-2xl p-8 md:p-12 space-y-8 md:space-y-10 relative z-10 border border-white/20">
        <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-emerald-400 via-teal-500 to-emerald-600"></div>

        <div className="text-center">
          <div className="mx-auto w-20 h-20 bg-gradient-to-br from-emerald-500 to-teal-700 rounded-3xl flex items-center justify-center text-white mb-6 shadow-2xl shadow-emerald-500/30 transform hover:scale-110 transition-transform duration-500">
             {/* Logo */}
             <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 24 24">
                <path d="M12 3a9 9 0 0 0-9 9v7c0 1.1.9 2 2 2h7a9 9 0 0 0 0-18zm0 16H5v-7a7 7 0 0 1 7-7 7 7 0 0 1 7 7c0 3.87-3.13 7-7 7z"/>
                <path d="M12 19a3 3 0 0 1 0-6 3 3 0 0 1 0 6z" opacity="0.6"/>
             </svg>
          </div>
          <h2 className="text-4xl font-serif text-slate-900 tracking-tight">AgriConnect</h2>
          <p className="text-emerald-600 font-black uppercase text-[9px] tracking-[0.4em] mt-3">Cultivating Connections</p>
        </div>

        {isRegistering && (
          <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
            <button onClick={() => setRole('buyer')} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${role === 'buyer' ? 'bg-white shadow-md text-emerald-700' : 'text-slate-400 hover:text-slate-600'}`}>BUYER</button>
            <button onClick={() => setRole('farmer')} className={`flex-1 py-3 text-[10px] font-black rounded-xl transition-all ${role === 'farmer' ? 'bg-white shadow-md text-emerald-700' : 'text-slate-400 hover:text-slate-600'}`}>FARMER</button>
          </div>
        )}

        <form onSubmit={isRegistering ? handleStartRegistration : handleLogin} className="space-y-4 md:space-y-6">
          {error && <div className="bg-red-50 text-red-600 p-4 rounded-2xl text-xs font-black border border-red-100 flex items-center gap-2 animate-in slide-in-from-top-2"><span className="text-lg">!</span> {error}</div>}

          {isRegistering && (
            <input type="text" required className={inputClasses} placeholder="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          )}
          {isRegistering && (
            <input type="tel" required className={inputClasses} placeholder="Mobile Number" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
          )}
          <input type="email" required className={inputClasses} placeholder="Email Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
          <input type="password" required className={inputClasses} placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />

          {isRegistering && (
            <input type="password" required className={inputClasses} placeholder="Confirm Password" value={formData.confirmPassword} onChange={e => setFormData({...formData, confirmPassword: e.target.value})} />
          )}

          <button type="submit" className="w-full bg-slate-900 text-white font-black py-4 md:py-5 rounded-2xl shadow-xl hover:bg-emerald-600 transition-all text-lg tracking-wide active:scale-[0.98] shadow-slate-900/20 hover:shadow-emerald-500/30">
            {isRegistering ? 'Create Account' : 'Sign In'}
          </button>
        </form>

        <button onClick={() => { setIsRegistering(!isRegistering); setError(''); }} className="w-full text-center text-[10px] font-black text-slate-400 hover:text-emerald-600 uppercase tracking-widest transition-colors">
          {isRegistering ? 'Already have an account? Login' : 'Don\'t have an account? Join Now'}
        </button>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Role, Product, Order, Location } from './types';
import LoginView from './views/Login';
import FarmerDashboard from './views/FarmerDashboard';
import BuyerDashboard from './views/BuyerDashboard';
import { getAddressFromCoords, getCoordsFromAddress } from './services/geminiService';
import { db } from './services/db';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userLocation, setUserLocation] = useState<Location | null>(null);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [showManualLoc, setShowManualLoc] = useState(false);
  const [manualAddress, setManualAddress] = useState('');

  const updateLocationState = async (loc: Location) => {
    setUserLocation(loc);
    if (currentUser) {
      await db.users.updateOne(currentUser.id, { location: loc });
      const updated = { ...currentUser, location: loc };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  const fetchLocation = useCallback(async (force = false) => {
    if (!force && userLocation) return;

    if (!("geolocation" in navigator)) {
      setLocationError("Geolocation not supported");
      setShowManualLoc(true);
      return;
    }

    setIsLocating(true);
    setLocationError(null);

    const options = {
      timeout: 15000,
      enableHighAccuracy: true,
      maximumAge: 0
    };

    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const loc = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        const address = await getAddressFromCoords(loc.lat, loc.lng);
        const finalLoc = { ...loc, address };
        await updateLocationState(finalLoc);
      } catch (err) {
        setLocationError("Address resolution failed");
        setShowManualLoc(true);
      } finally {
        setIsLocating(false);
      }
    }, (err) => {
      setIsLocating(false);
      setShowManualLoc(true);
      setLocationError("Permission denied or timeout");
    }, options);
  }, [currentUser, userLocation]);

  useEffect(() => {
    const checkAuth = async () => {
      const savedUser = localStorage.getItem('agro_user');
      if (savedUser) {
        const parsed = JSON.parse(savedUser);
        const actualUser = await db.users.findOne({ id: parsed.id });
        if (actualUser) {
          setCurrentUser(actualUser);
          setIsLoggedIn(true);
          if (actualUser.location) {
            setUserLocation(actualUser.location);
          }
        }
      }
    };
    checkAuth();
  }, []);

  useEffect(() => {
    if (isLoggedIn && !userLocation && !isLocating) {
      fetchLocation();
    }
  }, [isLoggedIn, userLocation, isLocating, fetchLocation]);

  const handleManualLocation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualAddress.trim()) return;
    setIsLocating(true);
    try {
      const coords = await getCoordsFromAddress(manualAddress);
      const finalLoc = { ...coords, address: manualAddress };
      await updateLocationState(finalLoc);
      setShowManualLoc(false);
    } catch (err) {
      setLocationError("Location not found");
    } finally {
      setIsLocating(false);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsLoggedIn(true);
    localStorage.setItem('agro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsLoggedIn(false);
    setUserLocation(null);
    localStorage.removeItem('agro_user');
  };

  const updateCurrentUser = async (updates: Partial<User>) => {
    if (currentUser) {
      await db.users.updateOne(currentUser.id, updates);
      const updated = { ...currentUser, ...updates };
      setCurrentUser(updated);
      localStorage.setItem('agro_user', JSON.stringify(updated));
    }
  };

  if (!isLoggedIn) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-900 bg-[#f8fafc]">
      <header className="bg-white/90 backdrop-blur-xl border-b border-slate-200/80 sticky top-0 z-50 px-4 md:px-12 py-3 md:py-4 flex items-center justify-between shadow-sm transition-all">
        <div className="flex items-center gap-3">
          <div className="bg-white p-2 rounded-2xl shadow-lg shadow-emerald-200/20 border border-slate-100 transform hover:scale-105 transition-transform duration-300">
            {/* Custom AgriConnect Logo: Orange Arch + Green Plant */}
            <svg className="w-6 h-6 md:w-8 md:h-8" viewBox="0 0 24 24" fill="none">
              <path d="M4 12a8 8 0 0 1 16 0" stroke="#F59E0B" strokeWidth="2.5" strokeLinecap="round" />
              <path d="M12 21v-8" stroke="#10B981" strokeWidth="2.5" strokeLinecap="round" />
              <path d="M12 13c-2.5-3-5.5-1.5-5.5 1.5S10 16 12 13z" fill="#10B981" />
              <path d="M12 13c2.5-3 5.5-1.5 5.5 1.5S14 16 12 13z" fill="#10B981" />
            </svg>
          </div>
          <h1 className="text-xl md:text-2xl font-serif font-black text-slate-800 tracking-tight block">AgriConnect</h1>
        </div>

        <div className="flex items-center gap-3 md:gap-6">
          <button 
            onClick={() => fetchLocation(true)}
            disabled={isLocating}
            className={`group flex items-center gap-2 md:gap-3 text-[10px] md:text-xs font-black uppercase tracking-widest transition-all px-4 py-2 md:py-2.5 rounded-xl border ${isLocating ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-500 hover:border-emerald-200 hover:text-emerald-700 hover:shadow-md border-slate-200'}`}
          >
            <svg className={`w-3.5 h-3.5 md:w-4 md:h-4 ${isLocating ? 'animate-spin' : 'text-emerald-500 group-hover:scale-110 transition-transform'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path></svg>
            <span className="truncate max-w-[80px] md:max-w-[160px]">
              {isLocating ? 'Locating...' : (userLocation?.address || 'Set Location')}
            </span>
          </button>

          <div className="flex items-center gap-3 md:gap-5 border-l-2 border-slate-100 pl-3 md:pl-6">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black text-slate-800 tracking-tight leading-none mb-1">{currentUser?.name}</p>
              <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest leading-none bg-emerald-50 inline-block px-1.5 py-0.5 rounded">{currentUser?.role}</p>
            </div>
            <button onClick={handleLogout} className="w-10 h-10 md:w-11 md:h-11 flex items-center justify-center bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 transition-all rounded-xl border border-slate-200 hover:border-red-200 shadow-sm active:scale-95" title="Logout">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
            </button>
          </div>
        </div>
      </header>

      {showManualLoc && (
